  // GET /api/pve/patrol-health - Refund pool health check (last 24h on Metis)
  app.get("/api/pve/patrol-health", async (req, res) => {
    try {
      const { rawPg } = await import('./server/db.js');

      // Global stats: eligible (fights_completed=3) vs actually refunded.
      // native_gas_refund is set directly by the indexer via Blockscout v2 API
      // (native METIS internal calls are invisible to getLogs).
      const statsRows = await rawPg`
        SELECT
          COUNT(*) FILTER (WHERE fights_completed = 3)::int AS eligible_completions,
          COUNT(*) FILTER (WHERE fights_completed = 3 AND native_gas_refund > 0)::int AS refunded_completions,
          COALESCE(SUM(native_gas_refund) FILTER (WHERE fights_completed = 3), 0) AS total_metis_24h,
          MAX(completed_at) FILTER (WHERE native_gas_refund > 0) AS last_refund_at
        FROM pve_completions
        WHERE chain_id = 1088
          AND completed_at > NOW() - INTERVAL '24 hours'
      `;

      const s = statsRows[0] || {};
      const eligible = parseInt(s.eligible_completions) || 0;
      const refunded = parseInt(s.refunded_completions) || 0;
      const refundRatePct = eligible > 0 ? Math.round((refunded / eligible) * 1000) / 10 : null;
      const totalWmetis24h = parseFloat(s.total_metis_24h) || 0;
      const avgWmetisPerRefund = refunded > 0 ? Math.round((totalWmetis24h / refunded) * 10000) / 10000 : null;

      // Also get all-time totals
      const totalsRows = await rawPg`
        SELECT
          COUNT(*)::int AS total_completions_all_time,
          COUNT(*) FILTER (WHERE fights_completed = 3)::int AS total_full_completions,
          COALESCE(SUM(native_gas_refund) FILTER (WHERE fights_completed = 3), 0) AS total_metis_all_time,
          AVG(native_gas_refund) FILTER (WHERE native_gas_refund > 0) AS avg_metis_per_refund_all_time
        FROM pve_completions
        WHERE chain_id = 1088
      `;
      const t = totalsRows[0] || {};

      // 7-day burn rate for a smoother runway estimate
      const sevenDayRows = await rawPg`
        SELECT COALESCE(SUM(native_gas_refund) FILTER (WHERE fights_completed = 3), 0) AS total_metis_7d
        FROM pve_completions
        WHERE chain_id = 1088
          AND completed_at > NOW() - INTERVAL '7 days'
      `;
      const totalMetis7d = parseFloat(sevenDayRows[0]?.total_metis_7d) || 0;
      const dailyBurnRate = totalMetis7d / 7;

      // Live PVP Diamond balance on Metis — this IS the refund pool
      const PVP_DIAMOND_METIS = '0xc7681698B14a2381d9f1eD69FC3D27F33965b53B';
      const METIS_RPC = 'https://andromeda.metis.io/?owner=1088';
      let poolBalanceMetis = null;
      let estimatedRunwayDays = null;
      try {
        const rpcRes = await fetch(METIS_RPC, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ jsonrpc: '2.0', method: 'eth_getBalance', params: [PVP_DIAMOND_METIS, 'latest'], id: 1 }),
          signal: AbortSignal.timeout(6000),
        });
        const rpcData = await rpcRes.json();
        if (rpcData?.result) {
          poolBalanceMetis = Number(BigInt(rpcData.result)) / 1e18;
          estimatedRunwayDays = dailyBurnRate > 0
            ? Math.round((poolBalanceMetis / dailyBurnRate) * 10) / 10
            : null;
        }
      } catch (rpcErr) {
        console.warn('[PVE API] Failed to fetch PVP Diamond balance:', rpcErr?.message?.slice(0, 60));
      }

      res.json({
        ok: true,
        stats: {
          eligible_completions: eligible,
          refunded_completions: refunded,
          refund_rate_pct: refundRatePct,
          total_metis_24h: totalWmetis24h,
          avg_metis_per_refund: avgWmetisPerRefund,
          last_refund_at: s.last_refund_at || null,
          total_completions_all_time: parseInt(t.total_completions_all_time) || 0,
          total_full_completions_all_time: parseInt(t.total_full_completions) || 0,
          total_metis_all_time: parseFloat(t.total_metis_all_time) || 0,
          avg_metis_per_refund_all_time: parseFloat(t.avg_metis_per_refund_all_time) || null,
          pool_balance_metis: poolBalanceMetis,
          daily_burn_rate_metis: Math.round(dailyBurnRate * 10000) / 10000,
          estimated_runway_days: estimatedRunwayDays,
        }
      });
    } catch (error) {
      console.error('[PVE API] Error fetching patrol health:', error);
      res.status(500).json({ ok: false, error: error?.message ?? String(error) });
    }
  });

  // GET /api/pve/patrol-rewards?wallet= - Per-wallet patrol history on Metis
  app.get("/api/pve/patrol-rewards", async (req, res) => {
    try {
      const wallet = (req.query.wallet || '').toLowerCase().trim();
      if (!wallet) return res.status(400).json({ ok: false, error: 'wallet param required' });
      const limit = Math.min(parseInt(req.query.limit) || 50, 200);
      const offset = parseInt(req.query.offset) || 0;

      const { rawPg } = await import('./server/db.js');

      const rows = await rawPg`
        SELECT
          c.id,
          c.tx_hash,
          c.completed_at,
          c.fights_completed,
          c.chain_id,
          c.native_gas_refund,
          a.name AS patrol_name,
          a.activity_id AS patrol_type_id,
          COALESCE(
            json_agg(
              json_build_object(
                'item_name', l.name,
                'item_type', l.item_type,
                'amount',    r.amount,
                'item_address', l.item_address
              ) ORDER BY l.item_type DESC, l.name
            ) FILTER (WHERE r.id IS NOT NULL),
            '[]'::json
          ) AS rewards
        FROM pve_completions c
        LEFT JOIN pve_activities a ON c.activity_id = a.id
        LEFT JOIN pve_reward_events r ON r.tx_hash = c.tx_hash AND r.chain_id = c.chain_id
        LEFT JOIN pve_loot_items l ON r.item_id = l.id
        WHERE LOWER(c.player_address) = ${wallet}
          AND c.chain_id = 1088
        GROUP BY c.id, c.tx_hash, c.completed_at, c.fights_completed, c.chain_id, c.native_gas_refund, a.name, a.activity_id
        ORDER BY c.completed_at DESC
        LIMIT ${limit} OFFSET ${offset}
      `;

      const summaryRows = await rawPg`
        SELECT
          COUNT(*)::int AS total_completions,
          COUNT(*) FILTER (WHERE fights_completed = 3)::int AS total_full_completions,
          COALESCE(SUM(native_gas_refund) FILTER (WHERE fights_completed = 3), 0) AS total_metis_earned,
          COUNT(*) FILTER (WHERE fights_completed = 3 AND native_gas_refund > 0)::int AS total_refunded,
          MIN(completed_at) AS first_patrol_at,
          MAX(completed_at) AS last_patrol_at
        FROM pve_completions
        WHERE LOWER(player_address) = ${wallet}
          AND chain_id = 1088
      `;
      const sm = summaryRows[0] || {};

      res.json({
        ok: true,
        completions: rows.map(r => ({
          ...r,
          native_gas_refund: parseFloat(r.native_gas_refund) || 0,
          rewards: typeof r.rewards === 'string' ? JSON.parse(r.rewards) : r.rewards,
        })),
        summary: {
          total_completions: parseInt(sm.total_completions) || 0,
          total_full_completions: parseInt(sm.total_full_completions) || 0,
          total_metis_earned: parseFloat(sm.total_metis_earned) || 0,
          total_refunded: parseInt(sm.total_refunded) || 0,
          first_patrol_at: sm.first_patrol_at || null,
          last_patrol_at: sm.last_patrol_at || null,
        }
      });
    } catch (error) {
      console.error('[PVE API] Error fetching patrol rewards:', error);
      res.status(500).json({ ok: false, error: error?.message ?? String(error) });
    }
  });

  // GET /api/pve/loot/:activityId - Get loot drops for a specific activity
  app.get("/api/pve/loot/:activityId", async (req, res) => {
    try {
      const { activityId } = req.params;
      const loot = await db.execute(sql`
        SELECT 
          l.id as item_id,
          l.item_address,
          l.name as item_name,
          l.item_type,
          l.rarity,
          COUNT(r.id) as drop_count,
          AVG(r.party_luck) as avg_party_luck,
          (SELECT COUNT(*) FROM pve_completions c WHERE c.activity_id = ${parseInt(activityId)}) as total_completions,
          CASE 
            WHEN (SELECT COUNT(*) FROM pve_completions c WHERE c.activity_id = ${parseInt(activityId)}) > 0 
            THEN COUNT(r.id)::decimal / (SELECT COUNT(*) FROM pve_completions c WHERE c.activity_id = ${parseInt(activityId)})
            ELSE 0 
          END as observed_rate
        FROM pve_reward_events r
        JOIN pve_loot_items l ON r.item_id = l.id
        WHERE r.activity_id = ${parseInt(activityId)}
        GROUP BY l.id, l.item_address, l.name, l.item_type, l.rarity
        ORDER BY drop_count DESC
      `);
      res.json({ ok: true, activityId: parseInt(activityId), loot: loot });
    } catch (error) {
      console.error('[PVE API] Error fetching loot:', error);
      res.status(500).json({ ok: false, error: error?.message ?? String(error) });
    }
  });

  // GET /api/pve/loot-hierarchical/:activityId - Get hierarchical loot with equipment variants
  app.get("/api/pve/loot-hierarchical/:activityId", async (req, res) => {
    try {
      const { activityId } = req.params;
      const activityIdInt = parseInt(activityId);
      
      // Get total completions for this activity
      const completionsResult = await db.execute(sql`
        SELECT COUNT(*) as count FROM pve_completions WHERE activity_id = ${activityIdInt}
      `);
      const totalCompletions = parseInt(completionsResult[0]?.count || 0);
      
      // Get non-equipment loot (consumables, materials, currency) - excludes seasonal
      // Include items where is_equipment is FALSE/NULL, OR where item_type is explicitly NOT 'equipment'
      // Explicitly exclude seasonal items (they go in their own section)
      const regularLoot = await db.execute(sql`
        SELECT 
          l.id as item_id,
          l.item_address,
          l.name as item_name,
          l.item_type,
          l.rarity,
          COUNT(r.id) as drop_count,
          AVG(r.party_luck) as avg_party_luck,
          FALSE as is_equipment
        FROM pve_reward_events r
        JOIN pve_loot_items l ON r.item_id = l.id
        WHERE r.activity_id = ${activityIdInt} 
          AND (
            (r.is_equipment IS NULL OR r.is_equipment = FALSE)
            OR l.item_type IN ('consumable', 'currency', 'material', 'rune')
          )
          AND (l.item_type IS NULL OR l.item_type != 'seasonal')
        GROUP BY l.id, l.item_address, l.name, l.item_type, l.rarity
        ORDER BY drop_count DESC
      `);
      
      // Get seasonal event drops separately
      const seasonalLootQuery = await db.execute(sql`
        SELECT 
          l.id as item_id,
          l.item_address,
          l.name as item_name,
          l.item_type,
          l.rarity,
          COUNT(r.id) as drop_count,
          AVG(r.party_luck) as avg_party_luck,
          FALSE as is_equipment
        FROM pve_reward_events r
        JOIN pve_loot_items l ON r.item_id = l.id
        WHERE r.activity_id = ${activityIdInt} 
          AND l.item_type = 'seasonal'
        GROUP BY l.id, l.item_address, l.name, l.item_type, l.rarity
        ORDER BY drop_count DESC
      `);
      
      // Get equipment parent categories (grouped by item_address/contract)
      // Only include items where is_equipment = TRUE AND item_type is 'equipment' or NULL (unknown contracts)
      const equipmentParents = await db.execute(sql`
        SELECT 
          l.id as item_id,
          l.item_address,
          l.name as item_name,
          l.item_type,
          COUNT(DISTINCT r.id) as drop_count,
          COUNT(DISTINCT r.display_id) as variant_count,
          TRUE as is_equipment
        FROM pve_reward_events r
        JOIN pve_loot_items l ON r.item_id = l.id
        WHERE r.activity_id = ${activityIdInt} 
          AND r.is_equipment = TRUE
          AND (l.item_type = 'equipment' OR l.item_type IS NULL)
        GROUP BY l.id, l.item_address, l.name, l.item_type
        ORDER BY drop_count DESC
      `);
      
      // Get equipment variants (grouped by display_id + rarity_tier)
      // Join with dimension tables to get proper item names
      // Match priority: (chain_id, activity_id) > (chain_id, activity_id=0) > (DFK chain only: chain_id=0, activity_id=0)
      // NOTE: Shared items (chain_id=0) are only used for DFK chain (53935), NOT for METIS (1088) patrols
      const equipmentVariants = await db.execute(sql`
        SELECT 
          l.id as item_id,
          l.item_address,
          r.display_id,
          r.rarity_tier,
          r.equipment_type,
          r.chain_id,
          COUNT(r.id) as drop_count,
          AVG(r.party_luck) as avg_party_luck,
          COALESCE(
            w_activity.weapon_name, a_activity.armor_name, acc_activity.accessory_name,
            w_chain.weapon_name, a_chain.armor_name, acc_chain.accessory_name,
            CASE WHEN r.chain_id = 53935 THEN COALESCE(w_shared.weapon_name, a_shared.armor_name, acc_shared.accessory_name) END,
            'Type ' || r.equipment_type || ' #' || r.display_id
          ) as variant_name
        FROM pve_reward_events r
        JOIN pve_loot_items l ON r.item_id = l.id
        LEFT JOIN dim_weapon_details w_activity ON r.equipment_type = w_activity.weapon_type_id AND r.display_id = w_activity.display_id AND r.chain_id = w_activity.chain_id AND r.activity_id = w_activity.activity_id
        LEFT JOIN dim_weapon_details w_chain ON r.equipment_type = w_chain.weapon_type_id AND r.display_id = w_chain.display_id AND r.chain_id = w_chain.chain_id AND w_chain.activity_id = 0
        LEFT JOIN dim_weapon_details w_shared ON r.equipment_type = w_shared.weapon_type_id AND r.display_id = w_shared.display_id AND w_shared.chain_id = 0 AND w_shared.activity_id = 0
        LEFT JOIN dim_armor_details a_activity ON r.equipment_type = a_activity.armor_type_id AND r.display_id = a_activity.display_id AND r.chain_id = a_activity.chain_id AND r.activity_id = a_activity.activity_id
        LEFT JOIN dim_armor_details a_chain ON r.equipment_type = a_chain.armor_type_id AND r.display_id = a_chain.display_id AND r.chain_id = a_chain.chain_id AND a_chain.activity_id = 0
        LEFT JOIN dim_armor_details a_shared ON r.equipment_type = a_shared.armor_type_id AND r.display_id = a_shared.display_id AND a_shared.chain_id = 0 AND a_shared.activity_id = 0
        LEFT JOIN dim_accessory_details acc_activity ON r.equipment_type = acc_activity.accessory_type_id AND r.display_id = acc_activity.display_id AND r.chain_id = acc_activity.chain_id AND r.activity_id = acc_activity.activity_id
        LEFT JOIN dim_accessory_details acc_chain ON r.equipment_type = acc_chain.accessory_type_id AND r.display_id = acc_chain.display_id AND r.chain_id = acc_chain.chain_id AND acc_chain.activity_id = 0
        LEFT JOIN dim_accessory_details acc_shared ON r.equipment_type = acc_shared.accessory_type_id AND r.display_id = acc_shared.display_id AND acc_shared.chain_id = 0 AND acc_shared.activity_id = 0
        WHERE r.activity_id = ${activityIdInt} 
          AND r.is_equipment = TRUE
          AND (l.item_type = 'equipment' OR l.item_type IS NULL)
        GROUP BY l.id, l.item_address, r.display_id, r.rarity_tier, r.equipment_type, r.chain_id,
          w_activity.weapon_name, w_chain.weapon_name, w_shared.weapon_name, 
          a_activity.armor_name, a_chain.armor_name, a_shared.armor_name, 
          acc_activity.accessory_name, acc_chain.accessory_name, acc_shared.accessory_name
        ORDER BY l.item_address, r.rarity_tier DESC, drop_count DESC
      `);
      
      // Map rarity tiers to names
      const rarityNames = ['Common', 'Uncommon', 'Rare', 'Legendary', 'Mythic'];
      // Equipment type names - includes hunting-specific weapon types (6, 10-13)
      const equipmentTypeNames = { 
        0: 'Weapon', 1: 'Armor', 2: 'Shield', 3: 'Accessory',
        6: 'Staff', 10: 'Staff', 11: 'Sword', 12: 'Dagger', 13: 'Bow'
      };
      
      // Build hierarchical structure
      const hierarchicalEquipment = equipmentParents.map(parent => {
        const variants = equipmentVariants
          .filter(v => v.item_address === parent.item_address)
          .map(v => ({
            displayId: v.display_id,
            rarityTier: v.rarity_tier,
            rarityName: rarityNames[v.rarity_tier] || 'Unknown',
            equipmentType: v.equipment_type,
            equipmentTypeName: equipmentTypeNames[v.equipment_type] || 'Unknown',
            variantName: v.variant_name || `Type ${v.equipment_type} #${v.display_id}`,
            dropCount: parseInt(v.drop_count),
            observedRate: totalCompletions > 0 ? parseInt(v.drop_count) / totalCompletions : 0,
            avgPartyLuck: parseFloat(v.avg_party_luck) || 0,
          }));
        
        // Compute aggregate avgPartyLuck from variants
        const totalVariantDrops = variants.reduce((sum, v) => sum + v.dropCount, 0);
        const avgPartyLuck = totalVariantDrops > 0 
          ? variants.reduce((sum, v) => sum + (v.avgPartyLuck * v.dropCount), 0) / totalVariantDrops
          : 0;
        
        return {
          ...parent,
          dropCount: parseInt(parent.drop_count),
          variantCount: parseInt(parent.variant_count),
          observedRate: totalCompletions > 0 ? parseInt(parent.drop_count) / totalCompletions : 0,
          avgPartyLuck,
          variants,
          // Stats summary
          rarityDistribution: variants.reduce((acc, v) => {
            acc[v.rarityName] = (acc[v.rarityName] || 0) + v.dropCount;
            return acc;
          }, {}),
        };
      });
      
      // Format regular loot with total completions for sample size display
      const formattedRegularLoot = regularLoot.map(item => ({
        ...item,
        dropCount: parseInt(item.drop_count),
        totalCompletions,
        observedRate: totalCompletions > 0 ? parseInt(item.drop_count) / totalCompletions : 0,
        avgPartyLuck: parseFloat(item.avg_party_luck) || 0,
      }));
      
      // Format seasonal loot
      const formattedSeasonalLoot = seasonalLootQuery.map(item => ({
        ...item,
        dropCount: parseInt(item.drop_count),
        totalCompletions,
        observedRate: totalCompletions > 0 ? parseInt(item.drop_count) / totalCompletions : 0,
        avgPartyLuck: parseFloat(item.avg_party_luck) || 0,
      }));
      
      res.json({
        ok: true,
        activityId: activityIdInt,
        totalCompletions,
        regularLoot: formattedRegularLoot,
        seasonalLoot: formattedSeasonalLoot,
        equipment: hierarchicalEquipment,
      });
    } catch (error) {
      console.error('[PVE API] Error fetching hierarchical loot:', error);
      res.status(500).json({ ok: false, error: error?.message ?? String(error) });
    }
  });

