  // POST /api/admin/gardening-calc/yield-projection - Calculate expected yields across all pools for a given investment
  app.post('/api/admin/gardening-calc/yield-projection', isAdminOrHasTab('yield-calculator', 'gardening-calculator'), async (req, res) => {
    try {
      const { 
        getQuestRewardFundBalances, 
        getPoolAllocation, 
        calculateYieldPerStamina,
        calculateHeroFactor,
        POOL_NAMES
      } = await import('./src/services/gardeningCalculator.js');
      const { getCachedPoolAnalytics } = await import('./pool-cache.js');
      
      const {
        investmentUSD = 1000,
        wisdom = 45,
        vitality = 43,
        gardeningSkill = 31,
        hasGardeningGene = true,
        stamina = 30,
        petBonusPct = 0,
        petFed = true,
      } = req.body;
      
      // Get reward fund balances
      const rewardFund = await getQuestRewardFundBalances(false);
      
      // Get pool cache for TVL data
      const poolCache = getCachedPoolAnalytics();
      const pools = poolCache.data || [];
      
      // Calculate hero factor
      const heroFactor = calculateHeroFactor(wisdom, vitality, gardeningSkill);
      const petMultiplier = petFed && petBonusPct > 0 ? 1 + petBonusPct / 100 : 1.0;
      
      // Calculate yields for each pool
      const projections = await Promise.all(pools.map(async (pool) => {
        const poolId = pool.pid;
        const poolTVL = pool.totalTVL || 0;
        
        // Calculate user's LP share based on investment
        // IMPORTANT: New investment adds to pool TVL, so use (TVL + investment) as denominator
        const newPoolTVL = poolTVL + investmentUSD;
        const lpShare = newPoolTVL > 0 ? investmentUSD / newPoolTVL : 0;
        
        // Get pool allocation
        const poolAllocation = await getPoolAllocation(poolId);
        
        // Calculate BOTH CRYSTAL and JEWEL rewards (dual-hero gardening)
        const crystalPerStamina = calculateYieldPerStamina({
          rewardPool: rewardFund.crystalPool,
          poolAllocation,
          lpOwned: lpShare,
          heroFactor,
          hasGardeningGene,
          gardeningSkill,
          petMultiplier,
        });
        
        const jewelPerStamina = calculateYieldPerStamina({
          rewardPool: rewardFund.jewelPool,
          poolAllocation,
          lpOwned: lpShare,
          heroFactor,
          hasGardeningGene,
          gardeningSkill,
          petMultiplier,
        });
        
        // Calculate per-quest rewards (stamina parameter, typically 30)
        const crystalPerQuest = crystalPerStamina * stamina;
        const jewelPerQuest = jewelPerStamina * stamina;
        
        return {
          pid: poolId,
          pairName: pool.pairName,
          tvl: poolTVL,
          newTvl: newPoolTVL,
          lpShare: lpShare,
          lpSharePct: (lpShare * 100).toFixed(4),
          poolAllocation: poolAllocation,
          poolAllocationPct: (poolAllocation * 100).toFixed(2),
          crystalPerQuest,
          jewelPerQuest,
        };
      }));
      
      res.json({
        ok: true,
        inputs: {
          investmentUSD,
          wisdom,
          vitality,
          gardeningSkill,
          hasGardeningGene,
          stamina,
          petBonusPct,
          petFed,
          heroFactor,
          petMultiplier,
        },
        rewardFund: {
          crystalPool: rewardFund.crystalPool,
          jewelPool: rewardFund.jewelPool,
        },
        projections,
      });
    } catch (error) {
      console.error('[GardeningCalc] Yield projection error:', error);
      res.status(500).json({ ok: false, error: error.message });
    }
  });

  // POST /api/admin/gardening-calc/optimize - Optimize pool allocation for maximum yield
  app.post('/api/admin/gardening-calc/optimize', isAdminOrHasTab('yield-calculator', 'gardening-calculator'), async (req, res) => {
    try {
      const { optimizeGardenAllocation } = await import('./src/services/gardeningCalculator.js');
      
      const { walletAddress, selectedPoolIds, heroCount = 6, stamina = 30 } = req.body;
      
      if (!walletAddress) {
        return res.status(400).json({ ok: false, error: 'walletAddress is required' });
      }
      if (!selectedPoolIds || !Array.isArray(selectedPoolIds) || selectedPoolIds.length === 0) {
        return res.status(400).json({ ok: false, error: 'selectedPoolIds array is required' });
      }
      
      console.log(`[GardeningOptimizer] Optimizing for wallet ${walletAddress} with ${selectedPoolIds.length} pools`);
      
      const result = await optimizeGardenAllocation(walletAddress, selectedPoolIds, heroCount, stamina);
      
      res.json(result);
    } catch (error) {
      console.error('[GardeningOptimizer] Optimization error:', error);
      res.status(500).json({ ok: false, error: error.message });
    }
  });

