      await rawPg.unsafe(`CREATE INDEX IF NOT EXISTS dfk_reconciliation_results_snapshot_idx ON dfk_reconciliation_results(unit_snapshot_id)`);
      console.log('[Telemetry] DFK telemetry tables ready');

