  // GET /api/admin/tavern/wallet-activity - Hero & pet buy/sell/held history from DFK GraphQL
  app.get("/api/admin/tavern/wallet-activity", isAdminOrHasTab('tavern-wallet-activity'), async (req, res) => {
    try {
      const address = (req.query.address || '').trim().toLowerCase();
      if (!address || !/^0x[a-f0-9]{40}$/.test(address)) {
        return res.status(400).json({ ok: false, error: 'Invalid wallet address' });
      }

      const DFK_GRAPH = 'https://api.defikingdoms.com/graphql';
      const RARITY_MAP = ['Common', 'Uncommon', 'Rare', 'Legendary', 'Mythic'];
      const ELEMENT_MAP = ['Fire', 'Water', 'Earth', 'Wind', 'Lightning', 'Ice', 'Light', 'Dark'];

      function getRealmCurrency(network) {
        const n = String(network || '').toLowerCase();
        if (n === 'kaia' || n === 'klaytn' || n === 'sun') return { realm: 'SUN', currency: 'JEWEL' };
        if (n === 'sd' || n === 'serendale') return { realm: 'SD', currency: 'JADE' };
        return { realm: 'CRY', currency: 'CRYSTAL' };
      }

      async function gqlFetch(query) {
        const r = await fetch(DFK_GRAPH, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ query })
        });
        return r.json();
      }

      async function paginate(buildQuery, dataKey) {
        const results = [];
        let skip = 0;
        const first = 1000;
        while (true) {
          const data = await gqlFetch(buildQuery(first, skip));
          const page = (data?.data?.[dataKey]) || [];
          results.push(...page);
          if (page.length < first) break;
          skip += first;
        }
        return results;
      }

      function parsePrice(wei) {
        if (!wei || wei === '0') return null;
        try { return Math.round(parseFloat(wei) / 1e18 * 100) / 100; } catch { return null; }
      }

      const hf = 'id mainClass subClass rarity level generation summons maxSummons network';
      const auctionFields = 'id purchasePrice endedAt seller { id } winner { id }';

      const [heroBuys, heroSells, petBuys, petSells, ownedHeroes] = await Promise.all([
        paginate((f, s) => '{ saleAuctions(where: { winner: "' + address + '" } orderBy: endedAt orderDirection: desc first: ' + f + ' skip: ' + s + ') { ' + auctionFields + ' tokenId { ' + hf + ' } } }', 'saleAuctions'),
        paginate((f, s) => '{ saleAuctions(where: { seller: "' + address + '", endedAt_not: null } orderBy: endedAt orderDirection: desc first: ' + f + ' skip: ' + s + ') { ' + auctionFields + ' tokenId { ' + hf + ' } } }', 'saleAuctions'),
        paginate((f, s) => '{ petAuctions(where: { winner: "' + address + '" } orderBy: endedAt orderDirection: desc first: ' + f + ' skip: ' + s + ') { ' + auctionFields + ' tokenId { id name rarity element } } }', 'petAuctions'),
        paginate((f, s) => '{ petAuctions(where: { seller: "' + address + '", endedAt_not: null } orderBy: endedAt orderDirection: desc first: ' + f + ' skip: ' + s + ') { ' + auctionFields + ' tokenId { id name rarity element } } }', 'petAuctions'),
        paginate((f, s) => '{ heroes(where: { owner: "' + address + '" } first: ' + f + ' skip: ' + s + ') { id } }', 'heroes'),
      ]);

      const ownedHeroIds = new Set(ownedHeroes.map(h => String(h.id)));

      function formatHero(a, type) {
        const h = a.tokenId || {};
        const { realm, currency } = getRealmCurrency(h.network);
        const tokenId = h.id ? String(h.id) : null;
        return {
          itemType: 'hero',
          type,
          held: type === 'buy' && tokenId ? ownedHeroIds.has(tokenId) : false,
          auctionId: a.id,
          tokenId,
          mainClass: h.mainClass || null,
          subClass: h.subClass || null,
          rarity: h.rarity != null ? (RARITY_MAP[Number(h.rarity)] || String(h.rarity)) : null,
          rarityNum: h.rarity != null ? Number(h.rarity) : null,
          level: h.level || null,
          generation: h.generation || null,
          summons: h.summons != null ? h.summons : null,
          maxSummons: h.maxSummons != null ? h.maxSummons : null,
          petName: null,
          element: null,
          seller: a.seller?.id || null,
          buyer: a.winner?.id || null,
          price: parsePrice(a.purchasePrice),
          realm,
          currency,
          date: a.endedAt ? new Date(Number(a.endedAt) * 1000).toISOString() : null,
        };
      }

      function formatPet(a, type) {
        const p = a.tokenId || {};
        return {
          itemType: 'pet',
          type,
          held: false,
          auctionId: a.id,
          tokenId: p.id ? String(p.id) : null,
          mainClass: null,
          subClass: null,
          rarity: p.rarity != null ? (RARITY_MAP[Number(p.rarity)] || String(p.rarity)) : null,
          rarityNum: p.rarity != null ? Number(p.rarity) : null,
          level: null,
          generation: null,
          summons: null,
          maxSummons: null,
          petName: p.name || null,
          element: p.element != null ? (ELEMENT_MAP[Number(p.element)] || String(p.element)) : null,
          seller: a.seller?.id || null,
          buyer: a.winner?.id || null,
          price: parsePrice(a.purchasePrice),
          realm: 'CRY',
          currency: 'CRYSTAL',
          date: a.endedAt ? new Date(Number(a.endedAt) * 1000).toISOString() : null,
        };
      }

      const buys = [...heroBuys.map(a => formatHero(a, 'buy')), ...petBuys.map(a => formatPet(a, 'buy'))];
      const sells = [...heroSells.map(a => formatHero(a, 'sell')), ...petSells.map(a => formatPet(a, 'sell'))];

      // ── Cost Basis Calculation ─────────────────────────────────────────────
      // Step 1: Build map of tokenId -> wallet buys sorted oldest-first for matching
      const buysByToken = new Map();
      for (const b of buys) {
        if (!b.tokenId) continue;
        if (!buysByToken.has(b.tokenId)) buysByToken.set(b.tokenId, []);
        buysByToken.get(b.tokenId).push(b);
      }
      // Sort each token's buys oldest → newest so we match in chronological order
      for (const arr of buysByToken.values()) {
        arr.sort((a, b) => (a.date || '') < (b.date || '') ? -1 : 1);
      }

      // Track which buy index has been consumed per tokenId (FIFO matching)
      const buyConsumedIdx = new Map();

      const unmatchedSellTokenIds = new Set();

      for (const sell of sells) {
        const tid = sell.tokenId;
        if (!tid) { sell.costBasis = null; continue; }

        const walletBuys = buysByToken.get(tid) || [];
        let idx = buyConsumedIdx.get(tid) || 0;
        // Find the next unconsumed buy that happened before this sell
        let matched = null;
        while (idx < walletBuys.length) {
          const candidate = walletBuys[idx];
          if ((candidate.date || '') < (sell.date || '')) {
            matched = candidate;
            buyConsumedIdx.set(tid, idx + 1);
            break;
          }
          idx++;
        }

        if (matched) {
          sell.costBasis = { value: matched.price, source: 'buy' };
        } else {
          sell.costBasis = null; // placeholder — will try last market sale below
          unmatchedSellTokenIds.add(tid);
        }
      }

      // Step 2: For unmatched sells, batch-fetch last market sale price (hero only, 50 per request)
      const unmatchedIds = [...unmatchedSellTokenIds].filter(Boolean);
      const lastSalePriceMap = new Map();
      if (unmatchedIds.length > 0) {
        const CHUNK = 50;
        for (let i = 0; i < unmatchedIds.length; i += CHUNK) {
          const chunk = unmatchedIds.slice(i, i + CHUNK);
          try {
            const aliasQuery = '{ ' + chunk.map(tid => {
              const alias = 'h' + tid.replace(/\D/g, '');
              return alias + ': saleAuctions(where: { tokenId: "' + tid + '", endedAt_not: null } orderBy: endedAt orderDirection: desc first: 1) { purchasePrice endedAt }';
            }).join(' ') + ' }';
            const resp = await gqlFetch(aliasQuery);
            if (resp?.data) {
              chunk.forEach(tid => {
                const alias = 'h' + tid.replace(/\D/g, '');
                const sales = resp.data[alias];
                if (sales && sales.length > 0) {
                  const p = parsePrice(sales[0].purchasePrice);
                  if (p != null) lastSalePriceMap.set(tid, p);
                }
              });
            }
          } catch (batchErr) {
            console.warn('[WalletActivity] Last-sale batch failed:', batchErr.message?.slice(0, 60));
          }
        }
      }

      // Step 3: Apply last-sale prices and 'summoned' label to remaining unmatched sells
      for (const sell of sells) {
        if (sell.costBasis !== null) continue; // already matched
        const tid = sell.tokenId;
        if (tid && lastSalePriceMap.has(tid)) {
          sell.costBasis = { value: lastSalePriceMap.get(tid), source: 'lastSale' };
        } else {
          sell.costBasis = { value: null, source: 'summoned' };
        }
      }
      // ── End Cost Basis ─────────────────────────────────────────────────────

      const currencySummary = {};
      for (const t of [...buys, ...sells]) {
        const c = t.currency;
        if (!currencySummary[c]) currencySummary[c] = { spent: 0, earned: 0 };
        if (t.type === 'buy') currencySummary[c].spent += t.price || 0;
        else currencySummary[c].earned += t.price || 0;
      }
      for (const c of Object.keys(currencySummary)) {
        currencySummary[c].spent = Math.round(currencySummary[c].spent * 100) / 100;
        currencySummary[c].earned = Math.round(currencySummary[c].earned * 100) / 100;
      }

      res.json({
        ok: true,
        address,
        buys,
        sells,
        currencySummary,
        summary: {
          totalBuys: buys.length,
          totalSells: sells.length,
          heldCount: buys.filter(b => b.held).length,
        }
      });
    } catch (err) {
      console.error('[TavernWalletActivity] Error:', err.message);
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  // GET /api/admin/tavern-listings - Fetch heroes from indexed database (fast)
  // Falls back to live DFK API if no indexed data available
  // Supports tournament-ready filtering: rarity, combat power, level, TS
  app.get("/api/admin/tavern-listings", isAdmin, async (req, res) => {
    try {
      console.log('[Tavern] Starting tavern-listings request...');
      
      // Parse all filter parameters
      const limit = req.query.limit ? parseInt(req.query.limit) : 50;
      const maxTts = req.query.maxTts ? parseInt(req.query.maxTts) : undefined;
      const minTts = req.query.minTts ? parseInt(req.query.minTts) : undefined;
      const minRarity = req.query.minRarity ? parseInt(req.query.minRarity) : undefined;
      const maxRarity = req.query.maxRarity ? parseInt(req.query.maxRarity) : undefined;
      const minCombatPower = req.query.minCombatPower ? parseInt(req.query.minCombatPower) : undefined;
      const maxCombatPower = req.query.maxCombatPower ? parseInt(req.query.maxCombatPower) : undefined;
      const minLevel = req.query.minLevel ? parseInt(req.query.minLevel) : undefined;
      const maxLevel = req.query.maxLevel ? parseInt(req.query.maxLevel) : undefined;
      const mainClass = req.query.mainClass || undefined;
      const sortBy = req.query.sortBy || 'price'; // price, combat_power, value, level, ts
      const sortOrder = req.query.sortOrder || 'asc';
      const realm = req.query.realm || undefined; // cv, sd, or undefined for both
      
      // Try to get from indexed database first
      try {
        const { getTavernHeroes, getIndexerProgress } = await import("./src/etl/ingestion/tavernIndexer.js");
        const progress = await getIndexerProgress();
        
        // Check if we have recent indexed data (any heroes indexed)
        const totalIndexed = progress.reduce((sum, p) => sum + (p.heroes_indexed || 0), 0);
        
        if (totalIndexed > 0) {
          console.log('[Tavern] Serving from indexed database with filters:', { 
            minRarity, minCombatPower, minLevel, sortBy 
          });
          
          // Build filter options
          const filterOptions = { 
            maxTts, minTts, minRarity, maxRarity, 
            minCombatPower, maxCombatPower, 
            minLevel, maxLevel, mainClass,
            sortBy, sortOrder, limit 
          };
          
          // Get heroes from both realms (or specific realm if requested)
          let cvHeroes = [];
          let sdHeroes = [];
          
          if (!realm || realm === 'cv') {
            cvHeroes = await getTavernHeroes({ ...filterOptions, realm: 'cv' });
          }
          if (!realm || realm === 'sd') {
            sdHeroes = await getTavernHeroes({ ...filterOptions, realm: 'sd' });
          }
          
          // Transform to match expected format
          const transformHero = (h) => ({
            id: h.hero_id,
            normalizedId: Number(h.normalized_id),
            mainClassStr: h.main_class,
            subClassStr: h.sub_class || '',
            professionStr: h.profession || '',
            rarity: h.rarity || 0,
            level: h.level || 1,
            generation: h.generation || 0,
            summons: h.summons || 0,
            maxSummons: h.max_summons || 0,
            darkSummoned: h.dark_summoned || false,
            salePrice: h.sale_price || '0',
            strength: h.strength || 0,
            agility: h.agility || 0,
            intelligence: h.intelligence || 0,
            wisdom: h.wisdom || 0,
            luck: h.luck || 0,
            dexterity: h.dexterity || 0,
            vitality: h.vitality || 0,
            endurance: h.endurance || 0,
            hp: h.hp || 0,
            mp: h.mp || 0,
            stamina: h.stamina || 25,
            active1: h.active1,
            active2: h.active2,
            passive1: h.passive1,
            passive2: h.passive2,
            tavern: h.realm,
            nativeToken: h.native_token,
            priceNative: parseFloat(h.price_native) || 0,
            priceUSD: null,
            traitScore: h.trait_score || 0,
            combatPower: h.combat_power || 0,
            summonStone: h.summon_stone || null,
            stoneTier: h.stone_tier || null,
            stoneType: h.stone_type || null
          });
          
          const crystalvale = cvHeroes.map(transformHero);
          const serendale = sdHeroes.map(transformHero);
          
          // Get last indexed time from progress
          const lastIndexed = progress.find(p => p.last_success_at)?.last_success_at || null;
          
          return res.json({
            ok: true,
            source: 'indexed',
            lastIndexed,
            prices: { crystal: 0, jewel: 0 },
            crystalvale,
            serendale,
            totalListings: crystalvale.length + serendale.length
          });
        }
      } catch (indexerError) {
        console.log('[Tavern] Indexer not available, falling back to live API:', indexerError.message);
      }
      
      // Fallback to live DFK API
      console.log('[Tavern] Fetching from live DFK API...');
      const DFK_TAVERN_API = 'https://api.defikingdoms.com/communityAllPublicHeroSaleAuctions';
      
      const apiResponse = await fetch(DFK_TAVERN_API, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ limit: limit * 2, offset: 0 })
      }).then(async r => {
        if (!r.ok) throw new Error(`DFK API error: ${r.status}`);
        const data = await r.json();
        console.log('[Tavern] DFK API returned', data?.length || 0, 'heroes');
        return data;
      });
      
      const crystalPrice = 0;
      const jewelPrice = 0;
      
      // Helper to convert wei to token amount
      const weiToToken = (weiStr) => {
        if (!weiStr) return 0;
        const wei = BigInt(weiStr);
        const whole = wei / BigInt(1e18);
        const frac = Number(wei % BigInt(1e18)) / 1e18;
        return Number(whole) + frac;
      };
      
      const allHeroes = Array.isArray(apiResponse) ? apiResponse : [];
      
      // Class ID to name mapping (DFK returns numeric IDs)
      const CLASS_NAMES = {
        0: 'Warrior', 1: 'Knight', 2: 'Thief', 3: 'Archer', 4: 'Priest', 5: 'Wizard',
        6: 'Monk', 7: 'Pirate', 8: 'Berserker', 9: 'Seer', 10: 'Legionnaire', 11: 'Scholar',
        16: 'Paladin', 17: 'DarkKnight', 18: 'Summoner', 19: 'Ninja', 20: 'Shapeshifter',
        21: 'Bard', 24: 'Dragoon', 25: 'Sage', 26: 'SpellBow', 28: 'DreadKnight'
      };
      const PROFESSION_NAMES = {
        0: 'mining', 2: 'gardening', 4: 'fishing', 6: 'foraging'
      };
      const getClassName = (id) => CLASS_NAMES[parseInt(id)] || `Class${id}`;
      const getProfessionName = (id) => PROFESSION_NAMES[parseInt(id)] || `profession${id}`;
      
      // Hero ID ranges determine realm/tavern location:
      // - IDs >= 1,000,000,000,000 and < 2,000,000,000,000 = Crystalvale (DFK Chain) - CRYSTAL prices
      // - IDs >= 2,000,000,000,000 = Serendale/Sundered Isles (Klaytn) - JEWEL prices
      // - IDs < 1,000,000,000,000 = Legacy Serendale (Harmony) - skip
      const CV_ID_MIN = BigInt("1000000000000");
      const CV_ID_MAX = BigInt("2000000000000");
      
      const crystalvaleHeroes = [];
      const serendaleHeroes = [];
      
      for (const hero of allHeroes) {
        // DFK API uses 'startingPrice' or 'salePrice' field
        const priceField = hero.startingPrice || hero.salePrice || hero.price;
        const priceInToken = weiToToken(priceField);
        const heroId = BigInt(hero.id || hero.heroId);
        
        // Build normalized hero object with class names resolved
        const mainClassRaw = hero.mainClass ?? hero.mainClassStr;
        const subClassRaw = hero.subClass ?? hero.subClassStr;
        const professionRaw = hero.profession ?? hero.professionStr;
        
        // normalizedId should be a number (hero ID without the realm prefix)
        const normalizedIdNum = Number(heroId % BigInt(1000000000000));
        
        const normalizedHero = {
          id: String(heroId),
          normalizedId: hero.normalizedId ? Number(hero.normalizedId) : normalizedIdNum,
          mainClassStr: getClassName(mainClassRaw),
          subClassStr: subClassRaw != null ? getClassName(subClassRaw) : '',
          professionStr: getProfessionName(professionRaw),
          rarity: hero.rarity ?? 0,
          level: hero.level ?? 1,
          generation: hero.generation ?? 0,
          summons: hero.summons ?? 0,
          maxSummons: hero.maxSummons ?? 0,
          salePrice: priceField || '0',
          strength: hero.strength ?? 0,
          agility: hero.agility ?? 0,
          intelligence: hero.intelligence ?? 0,
          wisdom: hero.wisdom ?? 0,
          luck: hero.luck ?? 0,
          dexterity: hero.dexterity ?? 0,
          vitality: hero.vitality ?? 0,
          endurance: hero.endurance ?? 0,
          hp: hero.hp ?? 0,
          mp: hero.mp ?? 0,
          stamina: hero.stamina ?? 25,
          darkSummoned: hero.darkSummoned === true,
          // Ability data for trait score calculation (TS)
          active1: hero.active1 != null ? `ability_${hero.active1}` : null,
          active2: hero.active2 != null ? `ability_${hero.active2}` : null,
          passive1: hero.passive1 != null ? `ability_${hero.passive1}` : null,
          passive2: hero.passive2 != null ? `ability_${hero.passive2}` : null
        };
        
        if (heroId >= CV_ID_MIN && heroId < CV_ID_MAX) {
          // Crystalvale - prices in CRYSTAL
          crystalvaleHeroes.push({
            ...normalizedHero,
            tavern: 'cv',
            nativeToken: 'CRYSTAL',
            priceNative: priceInToken,
            priceUSD: crystalPrice > 0 ? priceInToken * crystalPrice : null
          });
        } else if (heroId >= CV_ID_MAX) {
          // Klaytn/Sundered Isles - prices in JEWEL
          serendaleHeroes.push({
            ...normalizedHero,
            tavern: 'sd',
            nativeToken: 'JEWEL',
            priceNative: priceInToken,
            priceUSD: jewelPrice > 0 ? priceInToken * jewelPrice : null
          });
        }
        // Skip heroes with IDs < 1 trillion (legacy Harmony Serendale, deprecated)
      }
      
      console.log('[Tavern] Categorized:', crystalvaleHeroes.length, 'CV heroes,', serendaleHeroes.length, 'SD heroes');
      
      // Sort by price ascending
      crystalvaleHeroes.sort((a, b) => a.priceNative - b.priceNative);
      serendaleHeroes.sort((a, b) => a.priceNative - b.priceNative);
      
      // Limit each list to requested limit
      const cvLimited = crystalvaleHeroes.slice(0, limit);
      const sdLimited = serendaleHeroes.slice(0, limit);
      
      res.json({
        ok: true,
        prices: {
          crystal: crystalPrice,
          jewel: jewelPrice
        },
        crystalvale: cvLimited,
        serendale: sdLimited,
        totalListings: cvLimited.length + sdLimited.length
      });
    } catch (error) {
      console.error('[Tavern Listings] Error fetching listings:', error);
      res.status(500).json({ ok: false, error: error?.message ?? String(error) });
    }
  });

