  // GET /api/admin/sniper/filters - Get available filter options
  app.get("/api/admin/sniper/filters", isAdminOrHasTab('tavern-sniper', 'summon-sniper'), async (req, res) => {
    try {
      const { rawPg } = await import('./server/db.js');
      const { CLASSES } = await import('./src/data/summoningGenetics.js');
      
      // Get canonical class list from summoningGenetics.js (ensures Sage, Dragoon, DreadKnight always available)
      const canonicalClasses = Object.values(CLASSES);
      
      // Get dynamic values from tavern_heroes for professions, realms, and ranges
      // Also get any classes from DB in case there are variants not in canonical list
      const [dbClassesResult, dbSubClassesResult, professionsResult, realmsResult, priceRangeResult, levelRangeResult, tsRangeResult] = await Promise.all([
        rawPg`SELECT DISTINCT main_class FROM tavern_heroes WHERE main_class IS NOT NULL`,
        rawPg`SELECT DISTINCT sub_class FROM tavern_heroes WHERE sub_class IS NOT NULL`,
        rawPg`SELECT DISTINCT profession FROM tavern_heroes WHERE profession IS NOT NULL ORDER BY profession`,
        rawPg`SELECT DISTINCT realm FROM tavern_heroes ORDER BY realm`,
        rawPg`SELECT MIN(price_native) as min_price, MAX(price_native) as max_price FROM tavern_heroes WHERE price_native > 0`,
        rawPg`SELECT MIN(level) as min_level, MAX(level) as max_level FROM tavern_heroes`,
        rawPg`SELECT MIN(trait_score) as min_ts, MAX(trait_score) as max_ts FROM tavern_heroes`
      ]);

      // Union canonical classes with any DB classes to ensure all are included
      const dbClasses = dbClassesResult.map(r => r.main_class);
      const dbSubClasses = dbSubClassesResult.map(r => r.sub_class);
      const classes = [...new Set([...canonicalClasses, ...dbClasses])].sort();
      const subClasses = [...new Set([...canonicalClasses, ...dbSubClasses])].sort(); // Same classes can be subclasses
      const professions = professionsResult.map(r => r.profession);
      const realms = realmsResult.map(r => r.realm);
      const priceRange = priceRangeResult[0] || { min_price: 0, max_price: 10000 };
      const levelRange = levelRangeResult[0] || { min_level: 1, max_level: 100 };
      const tsRange = tsRangeResult[0] || { min_ts: 0, max_ts: 100 };

      // Static ability lists (active and passive skills from DFK)
      const activeSkills = [
        // Basic
        'Poisoned Blade', 'Blinding Winds', 'Heal', 'Cleanse', 'Iron Skin', 'Speed', 'Critical Aim', 'Deathmark',
        // Advanced
        'Exhaust', 'Daze', 'Explosion', 'Hardened Shield',
        // Elite
        'Stun', 'Second Wind',
        // Transcendant
        'Resurrection'
      ];
      const passiveSkills = [
        // Basic
        'Duelist', 'Clutch', 'Foresight', 'Headstrong', 'Clear Vision', 'Fearless', 'Chatterbox', 'Stalwart',
        // Advanced
        'Leadership', 'Efficient', 'Intimidation', 'Toxic',
        // Elite
        'Giant Slayer', 'Last Stand',
        // Transcendant
        'Second Life'
      ];

      res.json({
        ok: true,
        filters: {
          classes,
          subClasses,
          professions,
          realms,
          activeSkills,
          passiveSkills,
          priceRange: {
            min: parseFloat(priceRange.min_price) || 0,
            max: parseFloat(priceRange.max_price) || 10000
          },
          levelRange: {
            min: parseInt(levelRange.min_level) || 1,
            max: parseInt(levelRange.max_level) || 100
          },
          tsRange: {
            min: parseFloat(tsRange.min_ts) || 0,
            max: parseFloat(tsRange.max_ts) || 100
          },
          rarities: [
            { id: 0, name: 'Common' },
            { id: 1, name: 'Uncommon' },
            { id: 2, name: 'Rare' },
            { id: 3, name: 'Legendary' },
            { id: 4, name: 'Mythic' }
          ]
        }
      });
    } catch (error) {
      console.error('[Sniper] Filters error:', error);
      res.status(500).json({ ok: false, error: error?.message ?? String(error) });
    }
  });

  let sniperPriceCache = { data: null, timestamp: 0 };
  const SNIPER_PRICE_CACHE_TTL = 5 * 60 * 1000;

  // POST /api/admin/sniper/search - Find optimal hero pairs
  app.post("/api/admin/sniper/search", isAdminOrHasTab('tavern-sniper', 'summon-sniper'), async (req, res) => {
    try {
      const { rawPg } = await import('./server/db.js');
      const { getHeroById, getAllHeroesByOwner } = await import('./onchain-data.js');
      const { decodeStatGenes } = await import('./gene-decoder.js');
      
      // Check if minSummonsRemaining was explicitly provided
      const minSummonsExplicit = req.body.minSummonsRemaining !== undefined;
      
      const {
        targetClasses = [],
        targetSubClasses = [],
        targetProfessions = [],
        targetActiveSkills = [],
        targetPassiveSkills = [],
        realms = ['cv', 'sd'],
        minSummonsRemaining = 0,
        maxSummonsRemaining = undefined,  // Optional filter for max summons remaining
        minRarity = 0,
        maxGeneration = 10,
        minLevel = 1,
        maxTS = null,
        tearPrice = 0.05,
        summonType = 'regular',  // 'regular' or 'dark'
        searchMode = 'tavern',   // 'tavern', 'myHero', or 'wallet'
        myHeroId = null,         // Hero ID for 'myHero' mode
        walletAddress = null,    // Wallet address for 'wallet' mode
        bridgeFeeUsd = 0.50,     // Estimated bridging fee per hero in USD (Metis heroes need bridging to CV)
        minOffspringSkillScore = null,  // Minimum expected offspring skill score (TS) - null means no filter
        targetTSValue = null,   // Target TS value for cumulative probability filter (e.g., 8 means "TS >= 8")
        minTSProbability = null, // Minimum probability % of achieving targetTSValue (e.g., 20 means ">= 20% chance")
        minEliteChance = null,   // Minimum % chance of at least one elite skill (Stun, Second Wind, Giant Slayer, Last Stand)
        minExaltedChance = null, // Minimum % chance of at least one exalted skill (Resurrection, Second Life)
        minMaxSlotExalted = null, // Minimum % chance in any single slot for exalted skill (max is 12.5% for perfect elite alignment)
        sortBy = 'efficiency',   // 'efficiency', 'chance', 'price', or 'skillScore'
        requireAllSkills = false, // When true, require pairs that can produce ALL selected skills (AND mode)
        limit = 20
      } = req.body;

      // Normalize inputs to arrays
      const classArray = Array.isArray(targetClasses) ? targetClasses : (targetClasses ? [targetClasses] : []);
      const subClassArray = Array.isArray(targetSubClasses) ? targetSubClasses : (targetSubClasses ? [targetSubClasses] : []);
      const professionArray = Array.isArray(targetProfessions) ? targetProfessions : (targetProfessions ? [targetProfessions] : []);
      const activeSkillArray = Array.isArray(targetActiveSkills) ? targetActiveSkills : (targetActiveSkills ? [targetActiveSkills] : []);
      const passiveSkillArray = Array.isArray(targetPassiveSkills) ? targetPassiveSkills : (targetPassiveSkills ? [targetPassiveSkills] : []);

      if (classArray.length === 0 && subClassArray.length === 0 && professionArray.length === 0 && activeSkillArray.length === 0 && passiveSkillArray.length === 0) {
        return res.status(400).json({ 
          ok: false, 
          error: 'At least one class, subclass, profession, or ability must be selected' 
        });
      }

      // Fetch current USD prices for tokens, with 5-minute cache to avoid repeated RPC calls
      let crystalPriceUsd = 0;
      let jewelPriceUsd = 0;
      const CRYSTAL_ADDRESS = '0x04b9dA42306B023f3572e106B11D82aAd9D32EBb'.toLowerCase();
      const JEWEL_ADDRESS = '0xCCb93dABD71c8Dad03Fc4CE5559dC3D89F67a260'.toLowerCase();
      try {
        const now = Date.now();
        if (sniperPriceCache.data && (now - sniperPriceCache.timestamp) < SNIPER_PRICE_CACHE_TTL) {
          crystalPriceUsd = sniperPriceCache.data.crystalPriceUsd;
          jewelPriceUsd = sniperPriceCache.data.jewelPriceUsd;
          console.log(`[Sniper] Token prices (cached): CRYSTAL=$${crystalPriceUsd.toFixed(4)}, JEWEL=$${jewelPriceUsd.toFixed(4)}`);
        } else {
          const priceGraph = await buildFocusedPriceGraph([]);
          crystalPriceUsd = priceGraph.get(CRYSTAL_ADDRESS) || 0;
          jewelPriceUsd = priceGraph.get(JEWEL_ADDRESS) || 0;
          sniperPriceCache = { data: { crystalPriceUsd, jewelPriceUsd }, timestamp: now };
          console.log(`[Sniper] Token prices (fresh): CRYSTAL=$${crystalPriceUsd.toFixed(4)}, JEWEL=$${jewelPriceUsd.toFixed(4)}`);
        }
      } catch (priceErr) {
        console.warn('[Sniper] Could not fetch token prices (proceeding without USD):', priceErr?.message);
      }

      const isDarkSummon = summonType === 'dark';
      const isMyHeroMode = searchMode === 'myHero' && myHeroId;
      const isWalletMode = searchMode === 'wallet' && walletAddress;
      
      // For regular summons, default to requiring at least 1 summon remaining
      // Only apply this default if minSummonsRemaining was NOT explicitly set by the client
      const effectiveMinSummons = (!minSummonsExplicit && !isDarkSummon && minSummonsRemaining === 0) 
        ? 1 
        : minSummonsRemaining;
      
      console.log('[Sniper] Search request:', { 
        targetClasses: classArray, targetProfessions: professionArray, 
        realms, minSummonsRemaining: effectiveMinSummons, maxSummonsRemaining, minRarity, minLevel, maxTS, tearPrice,
        summonType, searchMode, myHeroId: isMyHeroMode ? myHeroId : null
      });

      // Validate realm filter - only allow known realms
      const validRealms = ['cv', 'sd'];
      const filteredRealms = Array.isArray(realms) 
        ? realms.filter(r => validRealms.includes(r))
        : validRealms;

      // Class tier definitions for tear cost calculation
      const basicClasses = ['Warrior', 'Knight', 'Thief', 'Archer', 'Priest', 'Wizard', 'Monk', 'Pirate', 'Berserker', 'Seer', 'Legionnaire', 'Scholar'];
      const advancedClasses = ['Paladin', 'DarkKnight', 'Summoner', 'Ninja', 'Shapeshifter', 'Bard'];
      const eliteClasses = ['Dragoon', 'Sage', 'Spellbow'];
      const exaltedClasses = ['DreadKnight'];
      
      function getClassTier(className) {
        const normalized = className?.toLowerCase() || '';
        if (exaltedClasses.some(c => c.toLowerCase() === normalized)) return 'exalted';
        if (eliteClasses.some(c => c.toLowerCase() === normalized)) return 'elite';
        if (advancedClasses.some(c => c.toLowerCase() === normalized)) return 'advanced';
        return 'basic';
      }
      
      function getMinTears(tier) {
        const tearsByTier = { basic: 10, advanced: 40, elite: 70, exalted: 100 };
        return tearsByTier[tier] || 10;
      }
      
      function calculateSummonTokenCost(generation, totalSummoned, useDarkSummon = false) {
        const baseCost = 6;
        const perChildIncrease = 2;
        const generationIncrease = 10;
        let cost = baseCost + (perChildIncrease * totalSummoned) + (generationIncrease * generation);
        if (generation === 0 && cost > 30) cost = 30;
        // Dark summon costs 1/4 of regular summon
        if (useDarkSummon) cost = cost / 4;
        return cost;
      }
      
      // TS (Trait Score) calculation: sum of tier indices for active1, active2, passive1, passive2
      // Skill value ranges map to tiers: 0-15=Basic(0), 16-23=Advanced(1), 24-27=Elite(2), 28-31=Transcendent(3)
      function getSkillTier(skillValue) {
        if (skillValue == null) return 0;
        const val = parseInt(skillValue);
        if (val >= 28) return 3; // Transcendent
        if (val >= 24) return 2; // Elite
        if (val >= 16) return 1; // Advanced
        return 0; // Basic (0-15)
      }
      
      function calculateTS(active1, active2, passive1, passive2) {
        return getSkillTier(active1) + getSkillTier(active2) + getSkillTier(passive1) + getSkillTier(passive2);
      }

      // Fetch heroes from INDEXED DATABASE (heroes with complete gene data)
      const safeTS = maxTS !== null ? parseFloat(maxTS) : null;
      const safeMinLevel = parseInt(minLevel) || 1;
      
      // ===========================================================
      // WALLET MODE: Fetch heroes from wallet and decode their genes
      // ===========================================================
      let walletHeroes = [];
      if (isWalletMode) {
        console.log(`[Sniper] Wallet mode - fetching heroes for ${walletAddress}...`);
        try {
          const rawWalletHeroes = await getAllHeroesByOwner(walletAddress);
          console.log(`[Sniper] Found ${rawWalletHeroes.length} heroes in wallet`);
          
          // Process each wallet hero with gene decoding
          for (const hero of rawWalletHeroes) {
            // Decode statGenes if available
            let decodedGenes = null;
            if (hero.statGenes) {
              try {
                decodedGenes = decodeStatGenes(hero.statGenes);
              } catch (decodeErr) {
                console.warn(`[Sniper] Failed to decode genes for hero ${hero.id}:`, decodeErr.message);
              }
            }
            
            // Determine realm from network
            const network = hero.network || 'dfk';
            const realm = network === 'met' ? 'sd' : 'cv';
            const nativeToken = realm === 'cv' ? 'CRYSTAL' : 'JEWEL';
            
            // Extract skill gene IDs from decoded genes
            let active1 = null, active2 = null, passive1 = null, passive2 = null;
            let active1_r1 = 0, active1_r2 = 0, active1_r3 = 0;
            let active2_r1 = 0, active2_r2 = 0, active2_r3 = 0;
            let passive1_r1 = 0, passive1_r2 = 0, passive1_r3 = 0;
            let passive2_r1 = 0, passive2_r2 = 0, passive2_r3 = 0;
            
            if (decodedGenes) {
              // Get skill slots from decoded genes
              // Note: decoded genes use 'class' not 'mainClass', and each slot has d/r1/r2/r3 with value/name properties
              if (decodedGenes.active1) {
                active1 = `ability_${decodedGenes.active1.d.value}`;
                active1_r1 = decodedGenes.active1.r1?.value || 0;
                active1_r2 = decodedGenes.active1.r2?.value || 0;
                active1_r3 = decodedGenes.active1.r3?.value || 0;
              }
              if (decodedGenes.active2) {
                active2 = `ability_${decodedGenes.active2.d.value}`;
                active2_r1 = decodedGenes.active2.r1?.value || 0;
                active2_r2 = decodedGenes.active2.r2?.value || 0;
                active2_r3 = decodedGenes.active2.r3?.value || 0;
              }
              if (decodedGenes.passive1) {
                passive1 = `ability_${decodedGenes.passive1.d.value}`;
                passive1_r1 = decodedGenes.passive1.r1?.value || 0;
                passive1_r2 = decodedGenes.passive1.r2?.value || 0;
                passive1_r3 = decodedGenes.passive1.r3?.value || 0;
              }
              if (decodedGenes.passive2) {
                passive2 = `ability_${decodedGenes.passive2.d.value}`;
                passive2_r1 = decodedGenes.passive2.r1?.value || 0;
                passive2_r2 = decodedGenes.passive2.r2?.value || 0;
                passive2_r3 = decodedGenes.passive2.r3?.value || 0;
              }
            }
            
            walletHeroes.push({
              hero_id: String(hero.id),
              normalized_id: parseInt(hero.normalizedId) || 0,
              realm,
              main_class: hero.mainClassStr || 'Unknown',
              sub_class: hero.subClassStr || null,
              profession: (hero.professionStr || 'mining').toLowerCase(),
              rarity: parseInt(hero.rarity) || 0,
              level: parseInt(hero.level) || 1,
              generation: parseInt(hero.generation) || 0,
              summons: parseInt(hero.summons) || 0,
              max_summons: parseInt(hero.maxSummons) || 0,
              price_native: 0, // User already owns these
              native_token: nativeToken,
              trait_score: 0,
              combat_power: 0,
              stat_genes: hero.statGenes,
              visual_genes: hero.visualGenes,
              genes_status: hero.statGenes ? 'complete' : 'pending',
              main_class_r1: decodedGenes?.class?.r1?.value,
              main_class_r2: decodedGenes?.class?.r2?.value,
              main_class_r3: decodedGenes?.class?.r3?.value,
              sub_class_r1: decodedGenes?.subClass?.r1?.value,
              sub_class_r2: decodedGenes?.subClass?.r2?.value,
              sub_class_r3: decodedGenes?.subClass?.r3?.value,
              active1, active2, passive1, passive2,
              active1_r1, active1_r2, active1_r3,
              active2_r1, active2_r2, active2_r3,
              passive1_r1, passive1_r2, passive1_r3,
              passive2_r1, passive2_r2, passive2_r3,
              is_wallet_hero: true
            });
          }
          console.log(`[Sniper] Processed ${walletHeroes.length} wallet heroes with gene data`);
        } catch (walletErr) {
          console.error('[Sniper] Error fetching wallet heroes:', walletErr);
          return res.status(500).json({ 
            ok: false, 
            error: `Failed to fetch wallet heroes: ${walletErr.message}` 
          });
        }
      }
      
      console.log('[Sniper] Fetching heroes from indexed database (genes_status = complete)...');
      
      // Query indexed tavern heroes with complete gene data (no limit - search all)
      // Always fetch tavern heroes (needed for tavern mode, myHero mode, and wallet mode)
      let indexedResult = [];
      indexedResult = await rawPg`
        SELECT
          hero_id, normalized_id, realm, native_token,
          main_class, sub_class, profession,
          rarity, level, generation, summons, max_summons, price_native,
          trait_score, combat_power, genes_status, stat_genes, visual_genes,
          main_class_r1, main_class_r2, main_class_r3,
          sub_class_r1, sub_class_r2, sub_class_r3,
          active1, active2, passive1, passive2,
          active1_r1, active1_r2, active1_r3,
          active2_r1, active2_r2, active2_r3,
          passive1_r1, passive1_r2, passive1_r3,
          passive2_r1, passive2_r2, passive2_r3
        FROM tavern_heroes
        WHERE genes_status = 'complete'
        ORDER BY price_native ASC NULLS LAST
      `;
      
      const apiResponse = indexedResult || [];
      console.log('[Sniper] Database returned', apiResponse.length, 'heroes with complete genes');
      
      
      // Helper to convert wei to token amount
      const weiToToken = (weiStr) => {
        if (!weiStr) return 0;
        const wei = BigInt(weiStr);
        const whole = wei / BigInt(1e18);
        const frac = Number(wei % BigInt(1e18)) / 1e18;
        return Number(whole) + frac;
      };
      
      // Class ID to name mapping (DFK API returns numeric IDs)
      const CLASS_NAMES = {
        0: 'Warrior', 1: 'Knight', 2: 'Thief', 3: 'Archer', 4: 'Priest', 5: 'Wizard',
        6: 'Monk', 7: 'Pirate', 8: 'Berserker', 9: 'Seer', 10: 'Legionnaire', 11: 'Scholar',
        16: 'Paladin', 17: 'DarkKnight', 18: 'Summoner', 19: 'Ninja', 20: 'Shapeshifter',
        21: 'Bard', 24: 'Dragoon', 25: 'Sage', 26: 'SpellBow', 28: 'DreadKnight'
      };
      const getClassName = (id) => CLASS_NAMES[parseInt(id)] || `Class${id}`;
      
      // Profession ID to name mapping
      const PROFESSION_NAMES = {
        0: 'mining', 2: 'gardening', 4: 'fishing', 6: 'foraging'
      };
      const getProfessionName = (id) => PROFESSION_NAMES[parseInt(id)] || `profession${id}`;
      
      // Network values from DFK API determine realm
      // 'dfk' = DFK Chain (Crystalvale), 'met' = Metis (Sundered Isles)
      const NETWORK_TO_REALM = {
        'dfk': { realm: 'cv', token: 'CRYSTAL' },
        'met': { realm: 'sd', token: 'JEWEL' }
      };
      
      const allApiHeroes = Array.isArray(apiResponse) ? apiResponse : [];
      
      // Transform and filter heroes from indexed database
      // Indexed data has snake_case fields: hero_id, main_class, stat_genes, etc.
      let heroes = [];
      for (const hero of allApiHeroes) {
        // Handle indexed data format (already has hero_id, main_class, stat_genes)
        const heroId = hero.hero_id;
        const realm = hero.realm;
        const nativeToken = hero.native_token || (realm === 'cv' ? 'CRYSTAL' : 'JEWEL');
        
        // Apply realm filter
        if (!filteredRealms.includes(realm)) continue;
        
        const mainClass = hero.main_class;
        const subClass = hero.sub_class;
        const professionName = hero.profession;
        const rarity = parseInt(hero.rarity) || 0;
        const level = parseInt(hero.level) || 1;
        const generation = parseInt(hero.generation) || 0;
        const summons = parseInt(hero.summons) || 0;
        const maxSummons = parseInt(hero.max_summons) || 0;
        const summonsRemaining = maxSummons - summons;
        const priceInToken = parseFloat(hero.price_native) || 0;
        
        // Use pre-calculated TS from index
        const heroTS = parseInt(hero.trait_score) || 0;
        
        // Apply filters
        // Dark Summon can use heroes with 0 regular summons remaining, so skip this filter for dark summon
        if (!isDarkSummon && summonsRemaining < effectiveMinSummons) continue;
        if (!isDarkSummon && maxSummonsRemaining !== undefined && summonsRemaining > maxSummonsRemaining) continue;
        if (rarity < minRarity) continue;
        if (maxGeneration !== null && maxGeneration !== undefined && generation > maxGeneration) continue;
        if (level < safeMinLevel) continue;
        if (safeTS !== null && heroTS > safeTS) continue;
        
        heroes.push({
          hero_id: String(heroId),
          normalized_id: parseInt(hero.normalized_id) || 0,
          realm,
          main_class: mainClass,
          sub_class: subClass,
          profession: professionName,
          rarity,
          level,
          generation,
          summons,
          max_summons: maxSummons,
          price_native: priceInToken,
          native_token: nativeToken,
          trait_score: heroTS,
          combat_power: parseInt(hero.combat_power) || 0,
          stat_genes: hero.stat_genes,
          visual_genes: hero.visual_genes,
          genes_status: hero.genes_status,
          main_class_r1: hero.main_class_r1,
          main_class_r2: hero.main_class_r2,
          main_class_r3: hero.main_class_r3,
          sub_class_r1: hero.sub_class_r1,
          sub_class_r2: hero.sub_class_r2,
          sub_class_r3: hero.sub_class_r3,
          active1: hero.active1,
          active2: hero.active2,
          passive1: hero.passive1,
          passive2: hero.passive2,
          active1_r1: hero.active1_r1,
          active1_r2: hero.active1_r2,
          active1_r3: hero.active1_r3,
          active2_r1: hero.active2_r1,
          active2_r2: hero.active2_r2,
          active2_r3: hero.active2_r3,
          passive1_r1: hero.passive1_r1,
          passive1_r2: hero.passive1_r2,
          passive1_r3: hero.passive1_r3,
          passive2_r1: hero.passive2_r1,
          passive2_r2: hero.passive2_r2,
          passive2_r3: hero.passive2_r3
        });
      }
      
      console.log(`[Sniper] After filtering: ${heroes.length} eligible heroes`);
      
      // Now filter/select heroes for pairing
      // Prioritize heroes matching target classes AND/OR target professions AND/OR target skills
      const targetClassHeroes = classArray.length > 0 
        ? heroes.filter(h => classArray.includes(h.main_class))
        : [];
      const targetProfessionHeroes = professionArray.length > 0
        ? heroes.filter(h => professionArray.includes(h.profession))
        : [];
      
      console.log(`[Sniper] Found ${targetClassHeroes.length} heroes matching target classes`);
      console.log(`[Sniper] Found ${targetProfessionHeroes.length} heroes matching target professions`);
      
      // Skill gene ID to name mapping (sparse) - matches gene-decoder.js ACTIVE_GENES
      // Basic: 0-7, Advanced: 16-19, Elite: 24-25, Exalted: 28
      const ACTIVE_GENE_MAP_LOCAL = {
        0: 'Poisoned Blade', 1: 'Blinding Winds', 2: 'Heal', 3: 'Cleanse',
        4: 'Iron Skin', 5: 'Speed', 6: 'Critical Aim', 7: 'Deathmark',
        16: 'Exhaust', 17: 'Daze', 18: 'Explosion', 19: 'Hardened Shield',
        24: 'Stun', 25: 'Second Wind', 28: 'Resurrection'
      };
      
      const PASSIVE_GENE_MAP_LOCAL = {
        0: 'Duelist', 1: 'Clutch', 2: 'Foresight', 3: 'Headstrong',
        4: 'Clear Vision', 5: 'Fearless', 6: 'Chatterbox', 7: 'Stalwart',
        16: 'Leadership', 17: 'Efficient', 18: 'Intimidation', 19: 'Toxic',
        24: 'Giant Slayer', 25: 'Last Stand', 28: 'Second Life'
      };
      
      // Reverse lookup: skill name → gene ID
      const ACTIVE_GENE_ID_MAP_LOCAL = Object.fromEntries(
        Object.entries(ACTIVE_GENE_MAP_LOCAL).map(([id, name]) => [name, parseInt(id)])
      );
      const PASSIVE_GENE_ID_MAP_LOCAL = Object.fromEntries(
        Object.entries(PASSIVE_GENE_MAP_LOCAL).map(([id, name]) => [name, parseInt(id)])
      );
      
      // Mutation precursor lookup: mutated skill → [precursor1, precursor2]
      // Covers ALL mutation tiers for both active and passive skills
      const ACTIVE_MUTATION_PRECURSORS_LOCAL = {
        // Basic → Advanced
        'Exhaust': ['Poisoned Blade', 'Blinding Winds'],
        'Daze': ['Heal', 'Cleanse'],
        'Explosion': ['Iron Skin', 'Speed'],
        'Hardened Shield': ['Critical Aim', 'Deathmark'],
        // Advanced → Elite
        'Stun': ['Exhaust', 'Daze'],
        'Second Wind': ['Explosion', 'Hardened Shield'],
        // Elite → Exalted
        'Resurrection': ['Stun', 'Second Wind']
      };
      
      const PASSIVE_MUTATION_PRECURSORS_LOCAL = {
        // Basic → Advanced
        'Leadership': ['Duelist', 'Clutch'],
        'Efficient': ['Foresight', 'Headstrong'],
        'Intimidation': ['Clear Vision', 'Fearless'],
        'Toxic': ['Chatterbox', 'Stalwart'],
        // Advanced → Elite
        'Giant Slayer': ['Leadership', 'Efficient'],
        'Last Stand': ['Intimidation', 'Toxic'],
        // Elite → Exalted
        'Second Life': ['Giant Slayer', 'Last Stand']
      };
      
      // Helper: Get all gene IDs that can produce a target skill (direct OR via mutation)
      function getSkillGeneIdsLocal(skillName, isActive) {
        const geneIdMap = isActive ? ACTIVE_GENE_ID_MAP_LOCAL : PASSIVE_GENE_ID_MAP_LOCAL;
        const precursorMap = isActive ? ACTIVE_MUTATION_PRECURSORS_LOCAL : PASSIVE_MUTATION_PRECURSORS_LOCAL;
        
        const ids = new Set();
        
        // Direct gene ID for this skill
        if (geneIdMap[skillName] !== undefined) {
          ids.add(geneIdMap[skillName]);
        }
        
        // Precursor gene IDs (skills that can mutate into this one)
        const precursors = precursorMap[skillName];
        if (precursors) {
          for (const precursor of precursors) {
            if (geneIdMap[precursor] !== undefined) {
              ids.add(geneIdMap[precursor]);
            }
          }
        }
        
        return ids;
      }
      
      // Helper: Check if a hero has any of the target gene IDs in their active/passive slots
      // Checks dominant (D) AND recessive (R1, R2, R3) genes
      function heroHasSkillGenesLocal(hero, targetGeneIds, slotPrefix) {
        // Parse dominant skill ID from "ability_X" format (e.g., "ability_24" -> 24)
        const dominant = hero[slotPrefix];
        let d = null;
        if (dominant && typeof dominant === 'string') {
          const match = dominant.match(/ability_(\d+)/);
          d = match ? parseInt(match[1]) : null;
        }
        
        // Check R1, R2, R3 recessive columns for this slot
        const r1 = parseInt(hero[`${slotPrefix}_r1`]);
        const r2 = parseInt(hero[`${slotPrefix}_r2`]);
        const r3 = parseInt(hero[`${slotPrefix}_r3`]);
        
        return (d !== null && targetGeneIds.has(d)) || 
               targetGeneIds.has(r1) || targetGeneIds.has(r2) || targetGeneIds.has(r3);
      }
      
      // NEW: Skill-based hero filtering for mutation abilities
      // For mutations like Resurrection, we need COMPLEMENTARY pairs:
      // - Resurrection requires Stun in slotX from one parent + Second Wind in same slotX from other parent
      // Strategy: Build precursor buckets by slot and create complementary pairs
      let targetSkillHeroes = [];
      let mutationComplementaryPairs = []; // Extra pairs specifically for mutations
      
      // Build gene ID sets for active and passive skill targets (including mutation precursors)
      // Use activeSkillArray and passiveSkillArray which are already parsed from the request
      const activeGeneIdsNeeded = new Set();
      const passiveGeneIdsNeeded = new Set();
      
      for (const skillName of activeSkillArray) {
        const geneIds = getSkillGeneIdsLocal(skillName, true);
        geneIds.forEach(id => activeGeneIdsNeeded.add(id));
      }
      for (const skillName of passiveSkillArray) {
        const geneIds = getSkillGeneIdsLocal(skillName, false);
        geneIds.forEach(id => passiveGeneIdsNeeded.add(id));
      }
      
      // Helper: Check if hero has specific skill in a slot
      function heroHasSpecificSkillInSlot(hero, skillGeneId, slotPrefix) {
        const dominant = hero[slotPrefix];
        let d = null;
        if (dominant && typeof dominant === 'string') {
          const match = dominant.match(/ability_(\d+)/);
          d = match ? parseInt(match[1]) : null;
        }
        const r1 = parseInt(hero[`${slotPrefix}_r1`]);
        const r2 = parseInt(hero[`${slotPrefix}_r2`]);
        const r3 = parseInt(hero[`${slotPrefix}_r3`]);
        return d === skillGeneId || r1 === skillGeneId || r2 === skillGeneId || r3 === skillGeneId;
      }
      
      // Helper: Check if hero has enough summons for the search type
      function heroHasEnoughSummons(hero) {
        const summonsRemaining = (hero.max_summons || 0) - (hero.summons || 0);
        // Dark summon can use any hero, regular summon needs >= effectiveMinSummons
        return isDarkSummon || summonsRemaining >= effectiveMinSummons;
      }
      
      if (activeGeneIdsNeeded.size > 0 || passiveGeneIdsNeeded.size > 0) {
        console.log(`[Sniper] Looking for heroes with skill genes - Active: [${[...activeGeneIdsNeeded].join(',')}], Passive: [${[...passiveGeneIdsNeeded].join(',')}]`);
        
        // For mutation targets, build complementary precursor buckets by slot
        // Example: For Resurrection (needs Stun=24 + Second Wind=25), find heroes with each precursor per slot
        for (const skillName of activeSkillArray) {
          const precursors = ACTIVE_MUTATION_PRECURSORS_LOCAL[skillName];
          if (precursors && precursors.length === 2) {
            const precursor1Id = ACTIVE_GENE_ID_MAP_LOCAL[precursors[0]];
            const precursor2Id = ACTIVE_GENE_ID_MAP_LOCAL[precursors[1]];
            const targetSkillId = ACTIVE_GENE_ID_MAP_LOCAL[skillName];
            
            console.log(`[Sniper] Building complementary pairs for ${skillName} (needs ${precursors[0]}=${precursor1Id} + ${precursors[1]}=${precursor2Id})`);
            
            // For each active slot, find heroes with precursor1 vs precursor2
            // Also check summons - filter out heroes without enough summons for the search type
            for (const slot of ['active1', 'active2']) {
              const withPrecursor1 = heroes.filter(h => heroHasSpecificSkillInSlot(h, precursor1Id, slot) && heroHasEnoughSummons(h));
              const withPrecursor2 = heroes.filter(h => heroHasSpecificSkillInSlot(h, precursor2Id, slot) && heroHasEnoughSummons(h));
              const withTarget = heroes.filter(h => targetSkillId !== undefined && heroHasSpecificSkillInSlot(h, targetSkillId, slot) && heroHasEnoughSummons(h));
              
              console.log(`[Sniper]   ${slot}: ${withPrecursor1.length} with ${precursors[0]}, ${withPrecursor2.length} with ${precursors[1]}, ${withTarget.length} with ${skillName}`);
              
              // Sort each by price and take top N
              withPrecursor1.sort((a, b) => a.price_native - b.price_native);
              withPrecursor2.sort((a, b) => a.price_native - b.price_native);
              
              // Create complementary pairs (up to 500 cheapest combinations per slot)
              const maxPerSlot = 250;
              const top1 = withPrecursor1.slice(0, 50);
              const top2 = withPrecursor2.slice(0, 50);
              
              let addedCount = 0;
              for (const h1 of top1) {
                for (const h2 of top2) {
                  if (h1.hero_id !== h2.hero_id && addedCount < maxPerSlot) {
                    mutationComplementaryPairs.push({ hero1: h1, hero2: h2, slot });
                    addedCount++;
                  }
                }
              }
              
              // Also add heroes that already have the target skill
              for (const h of withTarget.slice(0, 20)) {
                targetSkillHeroes.push(h);
              }
            }
          }
        }
        
        // Same for passive skills
        for (const skillName of passiveSkillArray) {
          const precursors = PASSIVE_MUTATION_PRECURSORS_LOCAL[skillName];
          if (precursors && precursors.length === 2) {
            const precursor1Id = PASSIVE_GENE_ID_MAP_LOCAL[precursors[0]];
            const precursor2Id = PASSIVE_GENE_ID_MAP_LOCAL[precursors[1]];
            const targetSkillId = PASSIVE_GENE_ID_MAP_LOCAL[skillName];
            
            console.log(`[Sniper] Building complementary pairs for ${skillName} (needs ${precursors[0]}=${precursor1Id} + ${precursors[1]}=${precursor2Id})`);
            
            // Also check summons - filter out heroes without enough summons for the search type
            for (const slot of ['passive1', 'passive2']) {
              const withPrecursor1 = heroes.filter(h => heroHasSpecificSkillInSlot(h, precursor1Id, slot) && heroHasEnoughSummons(h));
              const withPrecursor2 = heroes.filter(h => heroHasSpecificSkillInSlot(h, precursor2Id, slot) && heroHasEnoughSummons(h));
              const withTarget = heroes.filter(h => targetSkillId !== undefined && heroHasSpecificSkillInSlot(h, targetSkillId, slot) && heroHasEnoughSummons(h));
              
              console.log(`[Sniper]   ${slot}: ${withPrecursor1.length} with ${precursors[0]}, ${withPrecursor2.length} with ${precursors[1]}, ${withTarget.length} with ${skillName}`);
              
              withPrecursor1.sort((a, b) => a.price_native - b.price_native);
              withPrecursor2.sort((a, b) => a.price_native - b.price_native);
              
              const maxPerSlot = 250;
              const top1 = withPrecursor1.slice(0, 50);
              const top2 = withPrecursor2.slice(0, 50);
              
              let addedCount = 0;
              for (const h1 of top1) {
                for (const h2 of top2) {
                  if (h1.hero_id !== h2.hero_id && addedCount < maxPerSlot) {
                    mutationComplementaryPairs.push({ hero1: h1, hero2: h2, slot });
                    addedCount++;
                  }
                }
              }
              
              for (const h of withTarget.slice(0, 20)) {
                targetSkillHeroes.push(h);
              }
            }
          }
        }
        
        // Also include heroes with any precursor (fallback)
        const fallbackHeroes = heroes.filter(h => {
          if (activeGeneIdsNeeded.size > 0) {
            const hasActive1 = heroHasSkillGenesLocal(h, activeGeneIdsNeeded, 'active1');
            const hasActive2 = heroHasSkillGenesLocal(h, activeGeneIdsNeeded, 'active2');
            if (hasActive1 || hasActive2) return true;
          }
          if (passiveGeneIdsNeeded.size > 0) {
            const hasPassive1 = heroHasSkillGenesLocal(h, passiveGeneIdsNeeded, 'passive1');
            const hasPassive2 = heroHasSkillGenesLocal(h, passiveGeneIdsNeeded, 'passive2');
            if (hasPassive1 || hasPassive2) return true;
          }
          return false;
        });
        
        // Merge fallback heroes into targetSkillHeroes (dedup)
        const skillHeroIds = new Set(targetSkillHeroes.map(h => h.hero_id));
        for (const h of fallbackHeroes) {
          if (!skillHeroIds.has(h.hero_id)) {
            targetSkillHeroes.push(h);
            skillHeroIds.add(h.hero_id);
          }
        }
        
        console.log(`[Sniper] Found ${targetSkillHeroes.length} heroes with target skill genes or precursors`);
        console.log(`[Sniper] Built ${mutationComplementaryPairs.length} complementary mutation pairs`);
      }
      
      // Sort all by price and take cheapest for pairing pool
      heroes.sort((a, b) => a.price_native - b.price_native);
      const cheapestHeroes = heroes.slice(0, 200);
      
      // Combine target class heroes + target profession heroes + target skill heroes + cheapest, deduplicate
      const seenIds = new Set();
      const combinedHeroes = [];
      for (const h of [...targetClassHeroes, ...targetProfessionHeroes, ...targetSkillHeroes, ...cheapestHeroes]) {
        if (!seenIds.has(h.hero_id)) {
          combinedHeroes.push(h);
          seenIds.add(h.hero_id);
        }
      }
      heroes = combinedHeroes;
      
      console.log(`[Sniper] Found ${heroes.length} total eligible heroes (after dedup)`);

      // ============================================================
      // MY HERO MODE: Fetch user's hero and pair with tavern heroes
      // ============================================================
      let userHero = null;
      if (isMyHeroMode) {
        console.log(`[Sniper] MyHero mode - fetching hero ${myHeroId}...`);
        try {
          const heroData = await getHeroById(myHeroId);
          if (!heroData) {
            return res.status(404).json({ 
              ok: false, 
              error: `Hero ${myHeroId} not found` 
            });
          }
          
          // For user's own hero, determine realm from which chain it was fetched on
          // getHeroById queries DFK Chain by default, so those heroes use CRYSTAL
          // If heroData includes network/chain info, use that; otherwise default to DFK Chain
          const heroIdBig = BigInt(myHeroId);
          let userRealm = null;
          let userToken = null;
          
          // Check if heroData has network info from the RPC response
          if (heroData.network === 'met' || heroData.chainId === 1088) {
            userRealm = 'sd';
            userToken = 'JEWEL';
          } else {
            // Default to Crystalvale (DFK Chain) since that's where getHeroById queries
            userRealm = 'cv';
            userToken = 'CRYSTAL';
          }
          
          const userMainClass = getClassName(heroData.mainClass);
          const userSubClass = getClassName(heroData.subClass);
          const userProfession = getProfessionName(heroData.profession ?? 0);
          const userSummonsRemaining = (heroData.maxSummons ?? 0) - (heroData.summons ?? 0);
          
          // Dark summon can use any hero with summons remaining
          // More summons available = higher rarity chance
          
          userHero = {
            hero_id: String(myHeroId),
            normalized_id: Number(heroIdBig % BigInt(1000000000000)),
            realm: userRealm,
            main_class: userMainClass,
            sub_class: userSubClass,
            profession: userProfession,
            rarity: heroData.rarity ?? 0,
            level: heroData.level ?? 1,
            generation: heroData.generation ?? 0,
            summons: heroData.summons ?? 0,
            max_summons: heroData.maxSummons ?? 0,
            price_native: 0, // User already owns this hero
            native_token: userToken,
            is_user_hero: true,
            statGenes: heroData.statGenes,
            visualGenes: heroData.visualGenes
          };
          
          console.log(`[Sniper] User hero: ${userMainClass} (${userRealm}), ${userSummonsRemaining} summons remaining`);
          
          // Filter tavern heroes to same realm as user's hero
          heroes = heroes.filter(h => h.realm === userRealm);
          console.log(`[Sniper] Filtered to ${heroes.length} heroes in ${userRealm} realm`);
        } catch (err) {
          console.error('[Sniper] Error fetching user hero:', err);
          return res.status(500).json({ 
            ok: false, 
            error: `Failed to fetch hero: ${err.message}` 
          });
        }
      }

      const minHeroesRequired = isMyHeroMode ? 1 : 2;
      if (heroes.length < minHeroesRequired) {
        return res.json({
          ok: true,
          message: isMyHeroMode 
            ? 'No eligible tavern heroes found to pair with your hero'
            : 'Not enough eligible heroes found',
          pairs: [],
          totalHeroes: heroes.length,
          userHero: userHero ? {
            id: userHero.hero_id,
            mainClass: userHero.main_class,
            realm: userHero.realm
          } : null
        });
      }

      // Group heroes by realm for same-realm pairing (cheaper summoning)
      const byRealm = { cv: [], sd: [] };
      for (const h of heroes) {
        if (byRealm[h.realm]) byRealm[h.realm].push(h);
      }

      // Calculate full cost for a hero pair (purchase + summon token cost + tears + bridging)
      function calculatePairFullCost(hero1, hero2, tearPriceValue, useDarkSummon = false, bridgeFeePerHeroUsd = 0) {
        const purchaseCost = parseFloat(hero1.price_native) + parseFloat(hero2.price_native);
        
        // Summon token cost - BOTH heroes pay their fee (not just the lower one)
        // Dark summon uses 1/4 of the regular cost
        const summonCost1 = calculateSummonTokenCost(hero1.generation, hero1.summons, useDarkSummon);
        const summonCost2 = calculateSummonTokenCost(hero2.generation, hero2.summons, useDarkSummon);
        const summonTokenCost = summonCost1 + summonCost2;
        
        // Tear cost - BOTH heroes contribute tears based on their class tier
        // Dark summons don't require tears for the basic summon (only for optional rarity boost)
        const tier1 = getClassTier(hero1.main_class);
        const tier2 = getClassTier(hero2.main_class);
        const tearCount1 = useDarkSummon ? 0 : getMinTears(tier1);
        const tearCount2 = useDarkSummon ? 0 : getMinTears(tier2);
        const tearCount = tearCount1 + tearCount2;
        const tearCost = tearCount * (tearPriceValue || 0.05);
        
        // Bridging cost - Metis heroes need to be bridged to CV for summoning
        // Count heroes that need bridging (realm = 'sd' = Metis)
        let heroesNeedingBridge = 0;
        if (hero1.realm === 'sd' && !hero1.is_user_hero) heroesNeedingBridge++;
        if (hero2.realm === 'sd' && !hero2.is_user_hero) heroesNeedingBridge++;
        const bridgeCostUsd = heroesNeedingBridge * bridgeFeePerHeroUsd;
        
        return {
          purchaseCost,
          summonTokenCost,
          tearCost,
          tearCount,
          bridgeCostUsd,
          heroesNeedingBridge,
          totalCost: purchaseCost + summonTokenCost + tearCost,
          isDarkSummon: useDarkSummon
        };
      }

      // Generate candidate pairs from all heroes
      // Strategy: Generate pairs where at least one hero is a target class/profession hero
      // This ensures we find the best pairs for summoning the target class/profession
      const candidatePairs = [];
      
      // Track which heroes match target criteria
      const targetClassSet = new Set(classArray.map(c => c.toLowerCase()));
      const targetProfessionSet = new Set(professionArray.map(p => p.toLowerCase()));
      const isTargetClass = (h) => targetClassSet.has((h.main_class || '').toLowerCase());
      const isTargetProfession = (h) => targetProfessionSet.has((h.profession || '').toLowerCase());
      const isTargetHero = (h) => isTargetClass(h) || isTargetProfession(h);
      
      if (isWalletMode && walletHeroes.length === 0) {
        console.log(`[Sniper] Wallet mode but no wallet heroes found - returning empty results`);
        return res.json({
          ok: true,
          pairs: [],
          meta: {
            totalHeroesSearched: 0,
            totalPairsEvaluated: 0,
            searchMode: 'wallet',
            walletAddress,
            message: 'No heroes found in this wallet'
          }
        });
      } else if (isWalletMode) {
        // ============================================================
        // WALLET MODE: Pair each wallet hero with tavern heroes
        // Like "My Hero" mode but for every hero in the wallet
        // ============================================================
        console.log(`[Sniper] Wallet mode - pairing ${walletHeroes.length} wallet heroes against tavern heroes...`);
        
        // Apply same filters to wallet heroes as we do to tavern heroes
        const filteredWalletHeroes = walletHeroes.filter(h => {
          if (!filteredRealms.includes(h.realm)) return false;
          const generation = parseInt(h.generation) || 0;
          const rarity = parseInt(h.rarity) || 0;
          const level = parseInt(h.level) || 1;
          const summonsRemaining = (parseInt(h.max_summons) || 0) - (parseInt(h.summons) || 0);
          if (!isDarkSummon && summonsRemaining < effectiveMinSummons) return false;
          if (!isDarkSummon && maxSummonsRemaining !== undefined && summonsRemaining > maxSummonsRemaining) return false;
          if (rarity < minRarity) return false;
          if (maxGeneration !== null && maxGeneration !== undefined && generation > maxGeneration) return false;
          if (level < safeMinLevel) return false;
          return true;
        });
        
        console.log(`[Sniper] ${filteredWalletHeroes.length} wallet heroes pass filters`);
        
        // Sort tavern heroes by price and take cheapest 200
        heroes.sort((a, b) => a.price_native - b.price_native);
        const tavernHeroesToPair = heroes.slice(0, 200);
        
        for (const walletHero of filteredWalletHeroes) {
          for (const tavernHero of tavernHeroesToPair) {
            if (walletHero.realm !== tavernHero.realm) continue;
            const costs = calculatePairFullCost(walletHero, tavernHero, tearPrice, isDarkSummon, bridgeFeeUsd);
            candidatePairs.push({ 
              hero1: walletHero, 
              hero2: tavernHero, 
              realm: walletHero.realm, 
              isMyHeroPair: true,
              ...costs 
            });
          }
        }
        
        console.log(`[Sniper] Generated ${candidatePairs.length} wallet-vs-tavern pairs`);
      } else if (isMyHeroMode && userHero) {
        // ============================================================
        // MY HERO MODE: Pair user's hero with each tavern hero
        // ============================================================
        console.log(`[Sniper] MyHero mode - generating pairs with user's hero...`);
        
        // Sort tavern heroes by price and take cheapest
        heroes.sort((a, b) => a.price_native - b.price_native);
        const tavernHeroesToPair = heroes.slice(0, 200);
        
        for (const tavernHero of tavernHeroesToPair) {
          const costs = calculatePairFullCost(userHero, tavernHero, tearPrice, isDarkSummon, bridgeFeeUsd);
          candidatePairs.push({ 
            hero1: userHero, 
            hero2: tavernHero, 
            realm: userHero.realm, 
            isMyHeroPair: true,
            ...costs 
          });
        }
        
        console.log(`[Sniper] Generated ${candidatePairs.length} pairs with user's hero`);
      } else {
        // ============================================================
        // TAVERN MODE: Pair tavern heroes with each other
        // ============================================================
        for (const realm of Object.keys(byRealm)) {
          const realmHeroes = byRealm[realm];
          if (realmHeroes.length < 2) continue;
          
          // Separate target class/profession heroes from others
          let targetHeroes = realmHeroes.filter(isTargetHero);
          const otherHeroes = realmHeroes.filter(h => !isTargetHero(h));
          
          // Sort others by price and limit to 100 cheapest
          otherHeroes.sort((a, b) => a.price_native - b.price_native);
          const cheapOthers = otherHeroes.slice(0, 100);
          
          // CRITICAL: Limit target heroes to prevent OOM when many classes are selected
          // With 20k+ target heroes, nested loop generates 200M+ pairs causing memory crash
          // Sort by price and limit to 500 cheapest targets per realm for pair generation
          if (targetHeroes.length > 500) {
            targetHeroes.sort((a, b) => a.price_native - b.price_native);
            targetHeroes = targetHeroes.slice(0, 500);
          }
          
          // Generate pairs:
          // 1. Target hero + Target hero (for best class probability)
          for (let i = 0; i < targetHeroes.length; i++) {
            for (let j = i + 1; j < targetHeroes.length; j++) {
              const hero1 = targetHeroes[i];
              const hero2 = targetHeroes[j];
              const costs = calculatePairFullCost(hero1, hero2, tearPrice, isDarkSummon, bridgeFeeUsd);
              candidatePairs.push({ hero1, hero2, realm, ...costs });
            }
          }
          
          // 2. Target hero + Cheap other hero
          for (const targetHero of targetHeroes) {
            for (const otherHero of cheapOthers) {
              const costs = calculatePairFullCost(targetHero, otherHero, tearPrice, isDarkSummon, bridgeFeeUsd);
              candidatePairs.push({ hero1: targetHero, hero2: otherHero, realm, ...costs });
            }
          }
          
          // 3. Cheap other + Cheap other (if no targets found, these can still produce target class)
          // Limit to top 30 cheapest to avoid explosion
          const cheapLimit = Math.min(cheapOthers.length, 30);
          for (let i = 0; i < cheapLimit; i++) {
            for (let j = i + 1; j < cheapLimit; j++) {
              const hero1 = cheapOthers[i];
              const hero2 = cheapOthers[j];
              const costs = calculatePairFullCost(hero1, hero2, tearPrice, isDarkSummon, bridgeFeeUsd);
              candidatePairs.push({ hero1, hero2, realm, ...costs });
            }
          }
        }
      }

      // Add mutation complementary pairs to candidatePairs (skip in wallet mode - wallet pairs are already wallet-vs-tavern)
      // These are specifically matched pairs where one hero has precursor1 and the other has precursor2 in the same slot
      if (mutationComplementaryPairs.length > 0 && !isWalletMode) {
        const seenPairKeys = new Set(candidatePairs.map(p => 
          [p.hero1.hero_id, p.hero2.hero_id].sort().join('-')
        ));
        
        let addedMutationPairs = 0;
        for (const { hero1, hero2, slot } of mutationComplementaryPairs) {
          const pairKey = [hero1.hero_id, hero2.hero_id].sort().join('-');
          if (!seenPairKeys.has(pairKey)) {
            // Both heroes should be in the same realm, or pick the first one's realm
            const realm = hero1.realm || hero2.realm || 'cv';
            const costs = calculatePairFullCost(hero1, hero2, tearPrice, isDarkSummon, bridgeFeeUsd);
            candidatePairs.push({ hero1, hero2, realm, isMutationPair: true, mutationSlot: slot, ...costs });
            seenPairKeys.add(pairKey);
            addedMutationPairs++;
          }
        }
        console.log(`[Sniper] Added ${addedMutationPairs} new mutation complementary pairs`);
      }
      
      // Prioritize pairs containing target class/profession heroes when selecting pairs to score
      // This ensures we score pairs that are most likely to produce the target class/profession
      const pairsWithTarget = candidatePairs.filter(p => 
        isTargetHero(p.hero1) || isTargetHero(p.hero2)
      );
      const pairsWithoutTarget = candidatePairs.filter(p => 
        !isTargetHero(p.hero1) && !isTargetHero(p.hero2)
      );
      
      // Sort each group by cost
      pairsWithTarget.sort((a, b) => a.totalCost - b.totalCost);
      pairsWithoutTarget.sort((a, b) => a.totalCost - b.totalCost);
      
      // Score ALL candidate pairs - with indexed gene data this is fast (no API calls needed)
      // No limit - we need to find all high-TS pairs regardless of price for Bargain Hunter mode
      const pairsToScore = [...pairsWithTarget, ...pairsWithoutTarget];
      
      console.log(`[Sniper] Generated ${candidatePairs.length} candidate pairs (${pairsWithTarget.length} with target class), scoring ALL ${pairsToScore.length}`);

      // Class gene ID to name mapping
      const CLASS_GENE_MAP = [
        'Warrior', 'Knight', 'Thief', 'Archer', 'Priest', 'Wizard', 'Monk', 'Pirate',
        'Berserker', 'Seer', 'Legionnaire', 'Scholar', 'Unknown12', 'Unknown13', 'Unknown14', 'Unknown15',
        'Paladin', 'DarkKnight', 'Summoner', 'Ninja', 'Shapeshifter', 'Bard', 'Unknown22', 'Unknown23',
        'Dragoon', 'Sage', 'Spellbow', 'Unknown27', 'DreadKnight', 'Unknown29', 'Unknown30', 'Unknown31'
      ];
      
      // Skill gene ID to name mapping (sparse) - matches gene-decoder.js ACTIVE_GENES
      // Basic: 0-7, Advanced: 16-19, Elite: 24-25, Exalted: 28
      const ACTIVE_GENE_MAP = {
        0: 'Poisoned Blade', 1: 'Blinding Winds', 2: 'Heal', 3: 'Cleanse',
        4: 'Iron Skin', 5: 'Speed', 6: 'Critical Aim', 7: 'Deathmark',
        16: 'Exhaust', 17: 'Daze', 18: 'Explosion', 19: 'Hardened Shield',
        24: 'Stun', 25: 'Second Wind', 28: 'Resurrection'
      };
      
      const PASSIVE_GENE_MAP = {
        0: 'Duelist', 1: 'Clutch', 2: 'Foresight', 3: 'Headstrong',
        4: 'Clear Vision', 5: 'Fearless', 6: 'Chatterbox', 7: 'Stalwart',
        16: 'Leadership', 17: 'Efficient', 18: 'Intimidation', 19: 'Toxic',
        24: 'Giant Slayer', 25: 'Last Stand', 28: 'Second Life'
      };
      
      // Build genetics object from indexed hero component columns
      function buildGeneticsFromIndex(hero) {
        const getClassName = (geneId) => CLASS_GENE_MAP[parseInt(geneId)] || `Unknown${geneId}`;
        const getActiveName = (geneId) => ACTIVE_GENE_MAP[parseInt(geneId)] || `Unknown`;
        const getPassiveName = (geneId) => PASSIVE_GENE_MAP[parseInt(geneId)] || `Unknown`;
        
        // Parse skill ID from "ability_X" format (e.g., "ability_7" -> 7)
        const parseSkillId = (skillStr) => {
          if (!skillStr) return null;
          const match = skillStr.match(/ability_(\d+)/);
          return match ? parseInt(match[1]) : null;
        };
        
        // Get dominant active/passive skill names from the "ability_X" format columns
        const getDominantActive = (skillStr) => {
          const id = parseSkillId(skillStr);
          return id !== null ? getActiveName(id) : 'Unknown';
        };
        const getDominantPassive = (skillStr) => {
          const id = parseSkillId(skillStr);
          return id !== null ? getPassiveName(id) : 'Unknown';
        };
        
        // Profession mapping (database stores lowercase)
        const PROFESSION_MAP = {
          'mining': 'Mining',
          'gardening': 'Gardening',
          'fishing': 'Fishing',
          'foraging': 'Foraging'
        };
        
        return {
          id: hero.hero_id,
          mainClass: {
            dominant: hero.main_class || 'Unknown',
            R1: getClassName(hero.main_class_r1),
            R2: getClassName(hero.main_class_r2),
            R3: getClassName(hero.main_class_r3)
          },
          subClass: {
            dominant: hero.sub_class || 'Unknown',
            R1: getClassName(hero.sub_class_r1),
            R2: getClassName(hero.sub_class_r2),
            R3: getClassName(hero.sub_class_r3)
          },
          profession: {
            dominant: PROFESSION_MAP[hero.profession] || 'Unknown',
            R1: 'Unknown', R2: 'Unknown', R3: 'Unknown'
          },
          passive1: {
            dominant: getDominantPassive(hero.passive1),
            R1: getPassiveName(hero.passive1_r1),
            R2: getPassiveName(hero.passive1_r2),
            R3: getPassiveName(hero.passive1_r3)
          },
          passive2: {
            dominant: getDominantPassive(hero.passive2),
            R1: getPassiveName(hero.passive2_r1),
            R2: getPassiveName(hero.passive2_r2),
            R3: getPassiveName(hero.passive2_r3)
          },
          active1: {
            dominant: getDominantActive(hero.active1),
            R1: getActiveName(hero.active1_r1),
            R2: getActiveName(hero.active1_r2),
            R3: getActiveName(hero.active1_r3)
          },
          active2: {
            dominant: getDominantActive(hero.active2),
            R1: getActiveName(hero.active2_r1),
            R2: getActiveName(hero.active2_r2),
            R3: getActiveName(hero.active2_r3)
          },
          statBoost1: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
          statBoost2: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
          element: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
          visual: {
            gender: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
            headAppendage: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown', dominantValue: 0, R1Value: 0, R2Value: 0, R3Value: 0 },
            backAppendage: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown', dominantValue: 0, R1Value: 0, R2Value: 0, R3Value: 0 },
            background: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown', dominantValue: 0, R1Value: 0, R2Value: 0, R3Value: 0 },
            hairStyle: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
            hairColor: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
            eyeColor: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
            skinColor: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
            appendageColor: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' },
            backAppendageColor: { dominant: 'Unknown', R1: 'Unknown', R2: 'Unknown', R3: 'Unknown' }
          }
        };
      }

      // Cache for hero genetics - pre-populated from indexed database using component columns
      const geneticsCache = new Map();
      
      // Pre-populate cache from indexed heroes using component columns
      for (const h of heroes) {
        if (h.genes_status === 'complete' && h.main_class_r1 !== null) {
          geneticsCache.set(h.hero_id, buildGeneticsFromIndex(h));
        }
      }
      console.log(`[Sniper] Pre-cached ${geneticsCache.size} hero genetics from component columns`);
      
      // Pre-populate cache with wallet heroes' genetics (wallet mode)
      if (isWalletMode && walletHeroes.length > 0) {
        for (const wh of walletHeroes) {
          if (wh.stat_genes && wh.visual_genes) {
            geneticsCache.set(wh.hero_id, decodeHeroGenes({
              statGenes: wh.stat_genes,
              visualGenes: wh.visual_genes,
              id: wh.hero_id
            }));
          } else if (wh.active1 !== null || wh.passive1 !== null) {
            geneticsCache.set(wh.hero_id, buildGeneticsFromIndex(wh));
          }
        }
        console.log(`[Sniper] Pre-cached wallet hero genetics (${geneticsCache.size - heroes.length} from wallet)`);
      }
      
      // Pre-populate cache with user's hero genes if available (uses raw gene decoding)
      if (userHero && userHero.statGenes) {
        geneticsCache.set(userHero.hero_id, decodeHeroGenes(userHero));
        console.log(`[Sniper] Pre-cached user hero genetics for ${userHero.hero_id}`);
      }
      
      function getHeroGenetics(heroId) {
        if (geneticsCache.has(heroId)) {
          return geneticsCache.get(heroId);
        }
        console.log(`[Sniper] Warning: No genetics found for hero ${heroId} (not in index)`);
        return null;
      }

      // Score pairs with actual probability calculations
      const pairs = [];
      
      // Track TS metadata for user guidance (max probabilities seen across all pairs)
      let tsMetadata = { maxExpectedTS: 0, maxCumulativeByTarget: {} };
      for (let t = 0; t <= 12; t++) tsMetadata.maxCumulativeByTarget[t] = 0;
      
      // Debug logging flag - log first scored pair for validation
      let debugLoggedFirstPair = false;
      const DEBUG_TS = process.env.DEBUG_SNIPER_TS === 'true';
      
      for (const { hero1, hero2, realm, purchaseCost, summonTokenCost, tearCost, tearCount, bridgeCostUsd, heroesNeedingBridge, totalCost } of pairsToScore) {
        try {
          // Get pre-decoded genetics from cache
          const genetics1 = getHeroGenetics(hero1.hero_id);
          const genetics2 = getHeroGenetics(hero2.hero_id);
          
          if (!genetics1 || !genetics2) continue;

          const rarity1 = ['Common', 'Uncommon', 'Rare', 'Legendary', 'Mythic'][hero1.rarity] || 'Common';
          const rarity2 = ['Common', 'Uncommon', 'Rare', 'Legendary', 'Mythic'][hero2.rarity] || 'Common';

          const probs = calculateSummoningProbabilities(genetics1, genetics2, rarity1, rarity2, { skipVisuals: true });

          // Calculate JOINT probability of target traits
          // For multiple classes/professions: use OR logic (sum probabilities)
          // Between categories (class AND profession): use AND logic (multiply)
          let jointProbability = 1.0;
          let hasAnyTarget = false;
          
          // Multiple target classes: OR logic (sum their probabilities, cap at 1)
          if (classArray.length > 0 && probs.class) {
            let classSum = 0;
            for (const targetClass of classArray) {
              const classProb = Object.entries(probs.class).find(([name]) => 
                name.toLowerCase() === targetClass.toLowerCase()
              );
              if (classProb) {
                classSum += parseFloat(classProb[1]) / 100;
              }
            }
            if (classSum > 0) {
              jointProbability *= Math.min(classSum, 1.0);
              hasAnyTarget = true;
            } else {
              jointProbability = 0;
            }
          }

          // Multiple target subclasses: OR logic (sum their probabilities, cap at 1)
          if (subClassArray.length > 0 && probs.subClass) {
            let subClassSum = 0;
            for (const targetSubClass of subClassArray) {
              const subClassProb = Object.entries(probs.subClass).find(([name]) => 
                name.toLowerCase() === targetSubClass.toLowerCase()
              );
              if (subClassProb) {
                subClassSum += parseFloat(subClassProb[1]) / 100;
              }
            }
            if (subClassSum > 0) {
              jointProbability *= Math.min(subClassSum, 1.0);
              hasAnyTarget = true;
            } else {
              jointProbability = 0;
            }
          }

          // Multiple target professions: OR logic (sum their probabilities, cap at 1)
          if (professionArray.length > 0 && probs.profession) {
            let profSum = 0;
            for (const targetProfession of professionArray) {
              const profProb = Object.entries(probs.profession).find(([name]) => 
                name.toLowerCase().includes(targetProfession.toLowerCase())
              );
              if (profProb) {
                profSum += parseFloat(profProb[1]) / 100;
              }
            }
            if (profSum > 0) {
              jointProbability *= Math.min(profSum, 1.0);
              hasAnyTarget = true;
            } else {
              jointProbability = 0;
            }
          }

          // Helper to get skill probability from a slot
          function getSkillProbInSlot(slotProbs, skillName) {
            if (!slotProbs) return 0;
            const entry = Object.entries(slotProbs).find(([name]) => 
              name.toLowerCase() === skillName.toLowerCase()
            );
            return entry ? parseFloat(entry[1]) / 100 : 0;
          }
          
          // Active skills: OR mode (any skill) or AND mode (all skills in different slots)
          if (activeSkillArray.length > 0 && (probs.active1 || probs.active2)) {
            if (requireAllSkills && activeSkillArray.length >= 2) {
              // AND mode: Calculate P(all skills appear in different slots)
              // For 2 skills: P(S1 in slot1 AND S2 in slot2) + P(S1 in slot2 AND S2 in slot1)
              // For >2 skills: Only possible if we have enough slots (max 2 active slots)
              if (activeSkillArray.length > 2) {
                // Can't fit more than 2 skills in 2 slots
                jointProbability = 0;
              } else {
                const skill1 = activeSkillArray[0];
                const skill2 = activeSkillArray[1];
                const p1Slot1 = getSkillProbInSlot(probs.active1, skill1);
                const p1Slot2 = getSkillProbInSlot(probs.active2, skill1);
                const p2Slot1 = getSkillProbInSlot(probs.active1, skill2);
                const p2Slot2 = getSkillProbInSlot(probs.active2, skill2);
                
                // P(S1 in slot1, S2 in slot2) + P(S1 in slot2, S2 in slot1)
                const andProb = (p1Slot1 * p2Slot2) + (p1Slot2 * p2Slot1);
                if (andProb > 0) {
                  jointProbability *= andProb;
                  hasAnyTarget = true;
                } else {
                  jointProbability = 0;
                }
              }
            } else {
              // OR mode: Sum probabilities across all skills and slots
              let activeSum = 0;
              for (const targetSkill of activeSkillArray) {
                activeSum += getSkillProbInSlot(probs.active1, targetSkill);
                activeSum += getSkillProbInSlot(probs.active2, targetSkill);
              }
              if (activeSum > 0) {
                jointProbability *= Math.min(activeSum, 1.0);
                hasAnyTarget = true;
              } else {
                jointProbability = 0;
              }
            }
          }

          // Passive skills: OR mode (any skill) or AND mode (all skills in different slots)
          if (passiveSkillArray.length > 0 && (probs.passive1 || probs.passive2)) {
            if (requireAllSkills && passiveSkillArray.length >= 2) {
              // AND mode: Calculate P(all skills appear in different slots)
              if (passiveSkillArray.length > 2) {
                // Can't fit more than 2 skills in 2 slots
                jointProbability = 0;
              } else {
                const skill1 = passiveSkillArray[0];
                const skill2 = passiveSkillArray[1];
                const p1Slot1 = getSkillProbInSlot(probs.passive1, skill1);
                const p1Slot2 = getSkillProbInSlot(probs.passive2, skill1);
                const p2Slot1 = getSkillProbInSlot(probs.passive1, skill2);
                const p2Slot2 = getSkillProbInSlot(probs.passive2, skill2);
                
                const andProb = (p1Slot1 * p2Slot2) + (p1Slot2 * p2Slot1);
                if (andProb > 0) {
                  jointProbability *= andProb;
                  hasAnyTarget = true;
                } else {
                  jointProbability = 0;
                }
              }
            } else {
              // OR mode: Sum probabilities across all skills and slots
              let passiveSum = 0;
              for (const targetSkill of passiveSkillArray) {
                passiveSum += getSkillProbInSlot(probs.passive1, targetSkill);
                passiveSum += getSkillProbInSlot(probs.passive2, targetSkill);
              }
              if (passiveSum > 0) {
                jointProbability *= Math.min(passiveSum, 1.0);
                hasAnyTarget = true;
              } else {
                jointProbability = 0;
              }
            }
          }
          
          // For AND mode with 1 active + 1 passive skill, they're independent (different slot types)
          // The joint probability is already correct from the above multiplications

          // Calculate offspring TS probabilities FIRST (before any filtering)
          // This allows tracking of max TS values across ALL pairs for user guidance
          const tsData = calculateTSProbabilities(probs);
          
          // Debug logging: log first pair's TS data for validation (enabled via DEBUG_SNIPER_TS=true)
          if (DEBUG_TS && !debugLoggedFirstPair) {
            debugLoggedFirstPair = true;
            console.log('[Sniper DEBUG] Sample pair TS data:');
            console.log('  Hero1:', hero1.hero_id, hero1.main_class);
            console.log('  Hero2:', hero2.hero_id, hero2.main_class);
            console.log('  expectedTS:', tsData?.expectedTS);
            console.log('  cumulativeProbs:', JSON.stringify(tsData?.cumulativeProbs || {}));
            console.log('  slotTierProbs:', JSON.stringify(tsData?.slotTierProbs || {}));
            console.log('  Input probs.active1:', JSON.stringify(probs?.active1 || {}));
            console.log('  Input probs.passive1:', JSON.stringify(probs?.passive1 || {}));
          }
          
          // Track max TS values seen across all pairs (for user guidance when TS filter is too strict)
          if (tsData?.expectedTS > tsMetadata.maxExpectedTS) {
            tsMetadata.maxExpectedTS = tsData.expectedTS;
          }
          if (tsData?.cumulativeProbs) {
            for (let t = 0; t <= 12; t++) {
              const prob = tsData.cumulativeProbs[t] ?? 0;
              if (prob > tsMetadata.maxCumulativeByTarget[t]) {
                tsMetadata.maxCumulativeByTarget[t] = prob;
              }
            }
          }
          
          const targetProb = hasAnyTarget ? jointProbability * 100 : 0;
          if (targetProb === 0) continue;
          
          // Filter by minimum offspring skill score (only if threshold is set)
          if (minOffspringSkillScore !== null && minOffspringSkillScore !== undefined) {
            const expectedTS = tsData?.expectedTS ?? 0;
            if (expectedTS < minOffspringSkillScore) {
              continue;
            }
          }
          
          // Filter by target TS cumulative probability (only if both values are set)
          // cumulativeProbs uses numeric keys (0-12) and percentage values (0-100)
          if (targetTSValue !== null && targetTSValue !== undefined && 
              minTSProbability !== null && minTSProbability !== undefined) {
            const targetKey = Math.floor(Number(targetTSValue));
            let minProb = Number(minTSProbability);
            
            // Normalize: if minProb <= 1, assume it's a fraction and convert to percentage
            if (!isNaN(minProb) && minProb > 0 && minProb <= 1) {
              minProb = minProb * 100;
            }
            
            // Validate bounds: TS must be 0-12, probability must be 0-100
            if (!isNaN(targetKey) && targetKey >= 0 && targetKey <= 12 && 
                !isNaN(minProb) && minProb >= 0 && minProb <= 100) {
              // Access with both numeric and string key for safety
              const cumulativeProb = tsData?.cumulativeProbs?.[targetKey] ?? tsData?.cumulativeProbs?.[String(targetKey)] ?? 0;
              if (cumulativeProb < minProb) {
                continue;
              }
            }
          }
          
          // Filter by elite chance (at least one tier-2 skill: Stun, Second Wind, Giant Slayer, Last Stand)
          // Elite/Exalted calculation: P(at least 1) = 1 - P(none in any of 4 slots)
          if (minEliteChance !== null && minEliteChance !== undefined) {
            const minElite = Number(minEliteChance);
            if (!isNaN(minElite) && minElite >= 0 && minElite <= 100) {
              // Calculate P(at least one elite skill) from slot tier probabilities
              const slots = tsData?.slotTierProbs || {};
              let pNoElite = 1.0;
              for (const slot of ['active1', 'active2', 'passive1', 'passive2']) {
                const slotProbs = slots[slot] || {};
                // Tier 2 is elite - try both numeric and string keys for compatibility
                const pEliteInSlot = (slotProbs['2'] ?? slotProbs[2] ?? 0) / 100;  // Convert percentage to decimal
                pNoElite *= (1 - pEliteInSlot);
              }
              const eliteChance = (1 - pNoElite) * 100;  // Convert back to percentage
              if (eliteChance < minElite) {
                continue;
              }
            }
          }
          
          // Filter by exalted chance (at least one tier-3 skill: Resurrection, Second Life)
          if (minExaltedChance !== null && minExaltedChance !== undefined) {
            const minExalted = Number(minExaltedChance);
            if (!isNaN(minExalted) && minExalted >= 0 && minExalted <= 100) {
              // Calculate P(at least one exalted skill) from slot tier probabilities
              const slots = tsData?.slotTierProbs || {};
              let pNoExalted = 1.0;
              for (const slot of ['active1', 'active2', 'passive1', 'passive2']) {
                const slotProbs = slots[slot] || {};
                // Tier 3 is exalted - try both numeric and string keys for compatibility
                const pExaltedInSlot = (slotProbs['3'] ?? slotProbs[3] ?? 0) / 100;  // Convert percentage to decimal
                pNoExalted *= (1 - pExaltedInSlot);
              }
              const exaltedChance = (1 - pNoExalted) * 100;  // Convert back to percentage
              if (exaltedChance < minExalted) {
                continue;
              }
            }
          }
          
          // Filter by max single-slot exalted chance (best slot)
          if (minMaxSlotExalted !== null && minMaxSlotExalted !== undefined) {
            const minBestSlot = Number(minMaxSlotExalted);
            if (!isNaN(minBestSlot) && minBestSlot >= 0 && minBestSlot <= 100) {
              const slots = tsData?.slotTierProbs || {};
              let maxSlotExalted = 0;
              for (const slot of ['active1', 'active2', 'passive1', 'passive2']) {
                const slotProbs = slots[slot] || {};
                const pExaltedInSlot = slotProbs['3'] ?? slotProbs[3] ?? 0;
                if (pExaltedInSlot > maxSlotExalted) maxSlotExalted = pExaltedInSlot;
              }
              if (maxSlotExalted < minBestSlot) {
                continue;
              }
            }
          }

          // Calculate USD total cost (including bridging fees)
          const tokenPriceUsd = realm === 'cv' ? crystalPriceUsd : jewelPriceUsd;
          const tokenCostUsd = totalCost * tokenPriceUsd;
          const totalCostUsd = tokenCostUsd + (bridgeCostUsd || 0);  // Add bridging cost to total USD
          
          // Use USD for efficiency if available, otherwise use native token
          const efficiency = totalCostUsd > 0 ? targetProb / totalCostUsd : targetProb / totalCost;

          pairs.push({
            hero1: {
              id: hero1.hero_id,
              normalizedId: hero1.normalized_id,
              mainClass: hero1.main_class,
              subClass: hero1.sub_class,
              profession: hero1.profession,
              rarity: hero1.rarity,
              level: hero1.level,
              generation: hero1.generation,
              summonsRemaining: hero1.max_summons - hero1.summons,
              summons: hero1.summons,
              price: parseFloat(hero1.price_native),
              token: hero1.native_token,
              realm: hero1.realm
            },
            hero2: {
              id: hero2.hero_id,
              normalizedId: hero2.normalized_id,
              mainClass: hero2.main_class,
              subClass: hero2.sub_class,
              profession: hero2.profession,
              rarity: hero2.rarity,
              level: hero2.level,
              generation: hero2.generation,
              summonsRemaining: hero2.max_summons - hero2.summons,
              summons: hero2.summons,
              price: parseFloat(hero2.price_native),
              token: hero2.native_token,
              realm: hero2.realm
            },
            realm,
            targetProbability: targetProb,
            costs: {
              purchaseCost: Math.round(purchaseCost * 100) / 100,
              summonTokenCost,
              tearCost: Math.round(tearCost * 100) / 100,
              tearCount,
              bridgeCostUsd: Math.round((bridgeCostUsd || 0) * 100) / 100,
              heroesNeedingBridge: heroesNeedingBridge || 0,
              totalCost: Math.round(totalCost * 100) / 100,
              totalCostUsd: Math.round(totalCostUsd * 100) / 100,
              tokenPriceUsd: Math.round(tokenPriceUsd * 10000) / 10000
            },
            totalCost: Math.round(totalCost * 100) / 100,
            totalCostUsd: Math.round(totalCostUsd * 100) / 100,
            efficiency,
            probabilities: {
              class: probs.class,
              subClass: probs.subClass,
              profession: probs.profession,
              active1: probs.active1 || {},
              active2: probs.active2 || {},
              passive1: probs.passive1 || {},
              passive2: probs.passive2 || {}
            },
            ts: {
              distribution: tsData.tsProbabilities,
              cumulative: tsData.cumulativeProbs,
              expected: tsData.expectedTS,
              slotTiers: tsData.slotTierProbs
            },
            eliteExaltedChances: (() => {
              const slots = tsData?.slotTierProbs || {};
              let pNoElite = 1.0;
              let pNoExalted = 1.0;
              let maxSlotElite = 0;
              let maxSlotExalted = 0;
              for (const slot of ['active1', 'active2', 'passive1', 'passive2']) {
                const slotProbs = slots[slot] || {};
                const t2 = slotProbs['2'] ?? slotProbs[2] ?? 0;
                const t3 = slotProbs['3'] ?? slotProbs[3] ?? 0;
                pNoElite *= (1 - t2 / 100);
                pNoExalted *= (1 - t3 / 100);
                if (t2 > maxSlotElite) maxSlotElite = t2;
                if (t3 > maxSlotExalted) maxSlotExalted = t3;
              }
              return {
                eliteChance: Math.round((1 - pNoElite) * 10000) / 100,
                exaltedChance: Math.round((1 - pNoExalted) * 10000) / 100,
                maxSlotElite: Math.round(maxSlotElite * 100) / 100,
                maxSlotExalted: Math.round(maxSlotExalted * 100) / 100
              };
            })()
          });

        } catch (err) {
          console.log(`[Sniper] Skipping pair due to error:`, err.message);
        }
      }

      console.log(`[Sniper] Scored ${pairs.length} pairs with non-zero probability`);

      // Sort by selected criteria
      switch (sortBy) {
        case 'chance':
          pairs.sort((a, b) => b.targetProbability - a.targetProbability);
          break;
        case 'price':
          pairs.sort((a, b) => a.totalCostUsd - b.totalCostUsd);
          break;
        case 'skillScore':
          pairs.sort((a, b) => (b.ts?.expected ?? 0) - (a.ts?.expected ?? 0));
          break;
        case 'efficiency':
        default:
          pairs.sort((a, b) => b.efficiency - a.efficiency);
          break;
      }

      // Return top results (limit=0 means no limit - return all pairs)
      const topPairs = limit > 0 ? pairs.slice(0, limit) : pairs;

      res.json({
        ok: true,
        pairs: topPairs,
        totalHeroes: heroes.length,
        totalPairsScored: pairs.length,
        tokenPrices: {
          CRYSTAL: crystalPriceUsd,
          JEWEL: jewelPriceUsd
        },
        tsMetadata: {
          maxExpectedTS: Math.round(tsMetadata.maxExpectedTS * 100) / 100,
          maxCumulativeByTarget: tsMetadata.maxCumulativeByTarget,
          requestedTarget: targetTSValue ?? null,
          requestedMinProb: minTSProbability ?? null
        },
        searchParams: {
          targetClasses: classArray,
          targetSubClasses: subClassArray,
          targetProfessions: professionArray,
          targetActiveSkills: activeSkillArray,
          targetPassiveSkills: passiveSkillArray,
          realms: filteredRealms,
          minSummonsRemaining,
          minRarity,
          summonType,
          searchMode,
          requireAllSkills
        },
        userHero: userHero ? {
          id: userHero.hero_id,
          mainClass: userHero.main_class,
          subClass: userHero.sub_class,
          profession: userHero.profession,
          rarity: userHero.rarity,
          level: userHero.level,
          generation: userHero.generation,
          summonsRemaining: userHero.max_summons - userHero.summons,
          realm: userHero.realm,
          token: userHero.native_token
        } : null
      });

    } catch (error) {
      console.error('[Sniper] Search error:', error);
      res.status(500).json({ ok: false, error: error?.message ?? String(error) });
    }
  });
  
  // GET /api/admin/pools/:pid - Get detailed pool data with APR breakdown
  app.get('/api/admin/pools/:pid', isAdminOrHasTab('pools'), async (req, res) => {
    try {
      const pid = parseInt(req.params.pid);
      
      if (isNaN(pid) || pid < 0) {
        return res.status(400).json({ error: 'Invalid pool ID' });
      }
      
      const cached = getCachedPoolAnalytics();
      
      if (!cached || !cached.data || cached.data.length === 0) {
        return res.status(503).json({ 
          error: 'Pool cache not ready', 
          message: 'Pool analytics are still loading. Please try again in a few minutes.' 
        });
      }
      
      const pool = cached.data.find(p => p.pid === pid);
      
      if (!pool) {
        return res.status(404).json({ error: 'Pool not found', pid });
      }
      
      // Parse APR percentages for detailed breakdown
      const parseAprPercent = (aprStr) => {
        if (!aprStr) return 0;
        const match = String(aprStr).match(/[\d.]+/);
        return match ? parseFloat(match[0]) : 0;
      };
      
      const feeAprValue = parseAprPercent(pool.fee24hAPR);
      const harvestAprValue = parseAprPercent(pool.harvesting24hAPR);
      const questAprWorst = parseAprPercent(pool.gardeningQuestAPR?.worst);
      const questAprBest = parseAprPercent(pool.gardeningQuestAPR?.best);
      
      res.json({
        pool: {
          pid: pool.pid,
          pairName: pool.pairName,
          lpToken: pool.lpToken,
          token0: pool.token0,
          token1: pool.token1,
          totalTVL: pool.totalTVL,
          v2TVL: pool.v2TVL,
          volume24hUSD: pool.volume24hUSD,
          fees24hUSD: pool.fees24hUSD,
        },
        aprBreakdown: {
          passive: {
            feeAPR: pool.fee24hAPR,
            feeAprValue,
            harvestingAPR: pool.harvesting24hAPR,
            harvestAprValue,
            totalPassive: feeAprValue + harvestAprValue,
            description: 'Earned passively from swap fees and CRYSTAL emissions',
          },
          active: {
            gardeningQuestAPR: pool.gardeningQuestAPR,
            questAprWorst,
            questAprBest,
            description: 'Hero-dependent: requires heroes with Gardening profession to quest',
          },
          total: {
            worst: feeAprValue + harvestAprValue + questAprWorst,
            best: feeAprValue + harvestAprValue + questAprBest,
            displayed: pool.totalAPR,
          },
        },
        lastUpdated: cached.lastUpdated,
      });
    } catch (error) {
      console.error('[API] Error getting pool detail:', error);
      res.status(500).json({ error: 'Failed to get pool details', details: error.message });
    }
  });
  
  // GET /api/admin/pools/:pid/providers - Get top LP providers for a pool
  app.get('/api/admin/pools/:pid/providers', isAdminOrHasTab('pools'), async (req, res) => {
    try {
      const pid = parseInt(req.params.pid);
      const limit = parseInt(req.query.limit) || 20;
      
      if (isNaN(pid) || pid < 0) {
        return res.status(400).json({ error: 'Invalid pool ID' });
      }
      
      // Get registered wallets from players table
      const playersWithWallets = await db.select({
        discordId: players.discordId,
        discordUsername: players.discordUsername,
        primaryWallet: players.primaryWallet,
        wallets: players.wallets,
      }).from(players).where(sql`${players.wallets} IS NOT NULL AND json_array_length(${players.wallets}) > 0`);
      
      if (playersWithWallets.length === 0) {
        return res.json({ providers: [], poolId: pid, message: 'No registered wallets found' });
      }
      
      // Import getUserGardenPositions
      const { getUserGardenPositions } = await import('./onchain-data.js');
      
      const providers = [];
      
      // Check each wallet's position in this pool (limit concurrent requests)
      for (const player of playersWithWallets.slice(0, 50)) {
        const wallets = player.wallets || [];
        for (const wallet of wallets) {
          try {
            const positions = await getUserGardenPositions(wallet, 'dfk');
            const poolPosition = positions.find(p => p.pid === pid);
            
            if (poolPosition && parseFloat(poolPosition.stakedAmount) > 0) {
              providers.push({
                wallet,
                discordUsername: player.discordUsername,
                stakedAmount: poolPosition.stakedAmount,
                stakedAmountRaw: poolPosition.stakedAmountRaw?.toString(),
              });
            }
          } catch (err) {
            console.warn(`[Pools API] Error checking wallet ${wallet}:`, err.message);
          }
        }
      }
      
      // Sort by staked amount descending
      providers.sort((a, b) => parseFloat(b.stakedAmount) - parseFloat(a.stakedAmount));
      
      res.json({
        providers: providers.slice(0, limit),
        poolId: pid,
        totalProviders: providers.length,
        note: 'Based on registered player wallets only',
      });
    } catch (error) {
      console.error('[API] Error getting pool providers:', error);
      res.status(500).json({ error: 'Failed to get pool providers', details: error.message });
    }
  });

  // POST /api/admin/etl/run-all - Run ETL for all wallet clusters
  app.post('/api/admin/etl/run-all', isAdmin, async (req, res) => {
    try {
      const { etlService } = await import('./src/etl/services/EtlService.js');
      
      const clusterRecords = await db.select().from(walletClusters);
      
      if (clusterRecords.length === 0) {
        return res.json({ message: 'No clusters found', results: [] });
      }
      
      const results = [];
      for (const cluster of clusterRecords) {
        try {
          const etlResults = await etlService.runForCluster(cluster.clusterKey);
          results.push({
            clusterKey: cluster.clusterKey,
            userId: cluster.userId,
            success: true,
            walletsProcessed: etlResults.length,
          });
        } catch (err) {
          results.push({
            clusterKey: cluster.clusterKey,
            userId: cluster.userId,
            success: false,
            error: err.message,
          });
        }
      }
      
      res.json({
        message: `ETL complete for ${clusterRecords.length} clusters`,
        results,
      });
    } catch (error) {
      console.error('[API] Error running ETL:', error);
      res.status(500).json({ error: 'Failed to run ETL', details: error.message });
    }
  });

