  // ============================================================================
  // QUEST OPTIMIZER API
  // ============================================================================
  // Analyzes wallet heroes for optimal quest assignments based on stats
  // ============================================================================

  // Training quest success rates by stat level
  const TRAINING_SUCCESS_RATES = {
    5: 0.15, 10: 0.20, 11: 0.21, 15: 0.25, 16: 0.26, 20: 0.32,
    21: 0.33, 25: 0.40, 26: 0.41, 30: 0.47, 31: 0.48, 35: 0.50,
    36: 0.51, 40: 0.53, 41: 0.54, 45: 0.60, 46: 0.61, 50: 0.68
  };

  function getSuccessRate(statValue) {
    const capped = Math.min(statValue, 50);
    const keys = Object.keys(TRAINING_SUCCESS_RATES).map(Number).sort((a, b) => a - b);
    let rate = 0.15;
    for (const k of keys) {
      if (capped >= k) rate = TRAINING_SUCCESS_RATES[k];
    }
    return rate;
  }

  // Calculate expected XP per 5 stamina for training quests
  function calcTrainingXP(statValue) {
    const successRate = getSuccessRate(statValue);
    const baseXP = 15;
    const successBonus = 30 * successRate;
    const shvasXP = 50 * 0.01 * successRate;
    const loreXP = 125 * 0.0075 * successRate;
    const crystalXP = 150 * 0.005 * successRate;
    return baseXP + successBonus + shvasXP + loreXP + crystalXP;
  }

  // Profession quest stat combos
  const PROFESSION_STATS = {
    mining: ['strength', 'stamina'], // STR + END
    gardening: ['wisdom', 'vitality'],
    fishing: ['stamina', 'stamina'], // AGI + LCK (using stamina field for endurance)
    foraging: ['stamina', 'intelligence'] // DEX + INT
  };

  // Corrected stat mappings for profession quests
  const STAT_COMBOS = {
    mining: { stats: ['strength', 'vitality'], label: 'STR + VIT' }, // Gold mining
    miningToken: { stats: ['wisdom', 'vitality'], label: 'WIS + VIT' }, // Token mining
    gardening: { stats: ['wisdom', 'vitality'], label: 'WIS + VIT' },
    fishing: { stats: ['stamina', 'mining'], label: 'AGI + LCK' }, // Using available fields
    foraging: { stats: ['intelligence', 'stamina'], label: 'DEX + INT' }
  };

  // XP estimates per stamina for profession quests
  // Based on DFK mechanics:
  // - Mining/Gardening: ~10 XP per attempt (time-based quests)
  // - Fishing/Foraging: ~15 XP per attempt (instant quests)
  // Profession gene reduces stamina cost from 7 to 5
  function calcProfessionXP(professionName, hasProfessionGene) {
    // Base XP depends on quest type
    // Fishing/Foraging are instant quests with ~15 XP base
    // Mining/Gardening are time-based with ~10 XP base
    const isInstantQuest = professionName === 'fishing' || professionName === 'foraging';
    const baseXP = isInstantQuest ? 15 : 10;
    const staminaCost = hasProfessionGene ? 5 : 7;
    return baseXP / staminaCost;
  }

  app.get('/api/admin/quest-optimizer', isAdminOrHasTab('quest-optimizer'), async (req, res) => {
    const { wallet } = req.query;

    if (!wallet || typeof wallet !== 'string' || !/^0x[a-fA-F0-9]{40}$/.test(wallet)) {
      return res.status(400).json({ error: 'Valid wallet address required' });
    }

    try {
      console.log('[Quest Optimizer] Fetching ALL heroes for wallet:', wallet);
      const { getAllHeroesByOwner } = await import('./onchain-data.js');
      const heroes = await getAllHeroesByOwner(wallet);

      if (!heroes || heroes.length === 0) {
        return res.json({ 
          wallet, 
          totalHeroes: 0, 
          optimizedHeroes: [],
          summary: { byProfession: {}, byClass: {}, byBestQuest: {} }
        });
      }

      console.log('[Quest Optimizer] Got', heroes.length, 'heroes, analyzing...');

      const optimizedHeroes = [];

      for (const hero of heroes) {
        // Calculate profession quest scores based on official DFK stat requirements
        // Mining: STR + END (gold mining) or WIS + VIT (token mining) - we use STR + END
        // Gardening: WIS + VIT
        // Fishing: AGI + LCK
        // Foraging: DEX + INT
        const professionScores = {
          mining: (hero.strength || 0) + (hero.endurance || hero.stamina || 0), // STR + END
          gardening: (hero.wisdom || 0) + (hero.vitality || 0), // WIS + VIT
          fishing: (hero.agility || hero.stamina || 0) + (hero.luck || hero.mining || 0), // AGI + LCK
          foraging: (hero.dexterity || hero.stamina || 0) + (hero.intelligence || 0) // DEX + INT
        };

        // Find best profession quest
        const bestProfession = Object.entries(professionScores)
          .sort((a, b) => b[1] - a[1])[0];
        const hasProfessionGene = hero.professionStr?.toLowerCase() === bestProfession[0];
        const professionXpPerStamina = calcProfessionXP(bestProfession[0], hasProfessionGene);

        // Calculate training quest options (stats between 40-50 only)
        const statValues = [
          { stat: 'STR', value: hero.strength || 0, quest: 'Arm Wrestling' },
          { stat: 'DEX', value: hero.dexterity || hero.stamina || 0, quest: 'Darts' },
          { stat: 'AGI', value: hero.agility || hero.stamina || 0, quest: 'Game of Ball' },
          { stat: 'END', value: hero.endurance || hero.stamina || 0, quest: 'Dancing' },
          { stat: 'VIT', value: hero.vitality || 0, quest: 'Helping the Farm' },
          { stat: 'INT', value: hero.intelligence || 0, quest: 'Alchemist Assistance' },
          { stat: 'WIS', value: hero.wisdom || 0, quest: 'Puzzle Solving' },
          { stat: 'LCK', value: hero.luck || hero.mining || 0, quest: 'Card Game' }
        ];

        // Only stats 40-50 are trainable (above 50 = cannot train)
        const trainableStats = statValues.filter(s => s.value >= 40 && s.value <= 50);
        let bestTrainingOption = null;
        let trainingXpPerStamina = 0;

        if (trainableStats.length > 0) {
          const bestStat = trainableStats.sort((a, b) => b.value - a.value)[0];
          trainingXpPerStamina = calcTrainingXP(bestStat.value) / 5;
          bestTrainingOption = {
            stat: bestStat.stat,
            value: bestStat.value,
            quest: bestStat.quest,
            successRate: (getSuccessRate(bestStat.value) * 100).toFixed(1) + '%',
            xpPerStamina: trainingXpPerStamina.toFixed(2),
            allTrainable: trainableStats.map(s => `${s.stat}:${s.value}`).join(', ')
          };
        }

        // Determine which quest type gives better XP/stamina
        const recommendTraining = bestTrainingOption && trainingXpPerStamina > professionXpPerStamina;

        const heroData = {
          id: hero.normalizedId,
          class: hero.mainClassStr,
          subClass: hero.subClassStr,
          profession: hero.professionStr,
          level: hero.level,
          rarity: hero.rarity,
          generation: hero.generation,
          // Best quest recommendation
          bestQuestType: recommendTraining ? 'training' : 'profession',
          bestQuest: recommendTraining 
            ? bestTrainingOption.quest 
            : bestProfession[0].charAt(0).toUpperCase() + bestProfession[0].slice(1),
          xpPerStamina: recommendTraining 
            ? trainingXpPerStamina.toFixed(2) 
            : professionXpPerStamina.toFixed(2),
          // Profession quest details
          professionQuest: bestProfession[0],
          professionScore: bestProfession[1],
          professionXpPerStamina: professionXpPerStamina.toFixed(2),
          hasProfessionGene,
          professionStaminaCost: hasProfessionGene ? 5 : 7,
          // Training quest details (if available)
          trainingOption: bestTrainingOption,
          canTrain: !!bestTrainingOption,
          // Stats summary
          stats: {
            str: hero.strength, dex: hero.dexterity || hero.stamina,
            agi: hero.agility || hero.stamina, end: hero.endurance || hero.stamina,
            vit: hero.vitality, int: hero.intelligence, 
            wis: hero.wisdom, lck: hero.luck || hero.mining
          }
        };

        optimizedHeroes.push(heroData);
      }

      // Sort by XP efficiency (best quests first)
      optimizedHeroes.sort((a, b) => parseFloat(b.xpPerStamina) - parseFloat(a.xpPerStamina));

      // Generate summary
      const byProfession = {};
      const byClass = {};
      const byBestQuest = {};
      for (const h of optimizedHeroes) {
        byProfession[h.profession] = (byProfession[h.profession] || 0) + 1;
        byClass[h.class] = (byClass[h.class] || 0) + 1;
        byBestQuest[h.bestQuest] = (byBestQuest[h.bestQuest] || 0) + 1;
      }

      res.json({
        wallet,
        totalHeroes: heroes.length,
        optimizedHeroes: optimizedHeroes.slice(0, 500), // Top 500
        summary: { byProfession, byClass, byBestQuest }
      });

    } catch (err) {
      console.error('[Quest Optimizer] Error:', err);
      res.status(500).json({ error: 'Failed to analyze wallet: ' + err.message });
    }
  });

  // ============================================================================
  // PVE HUNT TRACKER API
  // ============================================================================

  app.get('/api/admin/pve/live-hunts', isAdminOrHasTab('pve-hunts'), async (req, res) => {
    const { wallet } = req.query;
    if (!wallet || typeof wallet !== 'string' || !/^0x[a-fA-F0-9]{40}$/.test(wallet)) {
      return res.status(400).json({ error: 'Valid wallet address required' });
    }
    try {
      const { getAllHeroesByOwner } = await import('./onchain-data.js');
      const { rawPg } = await import('./server/db.js');

      const [heroes, activities] = await Promise.all([
        getAllHeroesByOwner(wallet),
        rawPg.unsafe(`SELECT * FROM pve_activities WHERE activity_type = 'hunt'`)
      ]);

      const activityByAddr = {};
      for (const a of activities) {
        activityByAddr[a.contract_address.toLowerCase()] = a;
      }

      const zones = {};
      for (const hero of (heroes || [])) {
        const quest = (hero.currentQuest || '').toLowerCase();
        if (!quest || quest === '0x0000000000000000000000000000000000000000') continue;
        const activity = activityByAddr[quest];
        if (!activity) continue;
        const key = activity.id;
        if (!zones[key]) {
          zones[key] = { activity, heroes: [] };
        }
        zones[key].heroes.push(hero);
      }

      res.json({ wallet, zones: Object.values(zones), totalHeroes: (heroes || []).length });
    } catch (err) {
      console.error('[PVE Hunts] Error:', err.message);
      res.status(500).json({ error: 'Failed to fetch live hunts: ' + err.message });
    }
  });

  app.get('/api/admin/pve/hunt-encounters', isAdminOrHasTab('pve-hunts'), async (req, res) => {
    const { wallet, activityId, limit: limitStr } = req.query;
    if (!wallet || typeof wallet !== 'string') {
      return res.status(400).json({ error: 'wallet required' });
    }
    const limit = Math.min(Math.max(parseInt(limitStr) || 30, 1), 100);
    try {
      const { rawPg } = await import('./server/db.js');
      let rows;
      if (activityId) {
        const activity = await rawPg.unsafe(`SELECT * FROM pve_activities WHERE id = $1`, [activityId]);
        if (activity.length === 0) return res.json({ encounters: [] });
        const enemyKey = (activity[0].name || '').toUpperCase().replace(/\s+/g, '_');
        const realmMap = { 53935: 'dfk', 8217: 'klaytn' };
        const realm = realmMap[activity[0].chain_id] || 'dfk';
        rows = await rawPg.unsafe(`
          SELECT * FROM hunting_encounters
          WHERE LOWER(wallet_address) = LOWER($1)
            AND realm = $2
            AND enemy_id = $3
          ORDER BY encountered_at DESC
          LIMIT $4
        `, [wallet, realm, enemyKey, limit]);
      } else {
        rows = await rawPg.unsafe(`
          SELECT * FROM hunting_encounters
          WHERE LOWER(wallet_address) = LOWER($1)
          ORDER BY encountered_at DESC
          LIMIT $2
        `, [wallet, limit]);
      }
      res.json({ encounters: rows });
    } catch (err) {
      console.error('[PVE Hunts] Encounters error:', err.message);
      res.status(500).json({ error: 'Failed to fetch encounters: ' + err.message });
    }
  });

  app.post('/api/admin/pve/hunt-ai-analysis', isAdminOrHasTab('pve-hunts'), async (req, res) => {
    const { wallet, zone, heroes, recentEncounters } = req.body;
    if (!zone || !heroes || !Array.isArray(heroes)) {
      return res.status(400).json({ error: 'zone and heroes[] required' });
    }
    try {
      const avgLevel = heroes.reduce((s, h) => s + (h.level || 1), 0) / heroes.length;
      const heroSummary = heroes.map(h => {
        const agi = h.agility || 0, lck = h.luck || 0, dex = h.dexterity || 0;
        const vit = h.vitality || 0, end = h.endurance || 0, int = h.intelligence || 0;
        const speed = Math.round(agi * 1.7 * avgLevel / 100);
        const eva = Math.round((agi * 1.5 + lck * 0.5) * avgLevel / 10000);
        const blk = Math.round((dex * 1.5 + lck * 0.5) * avgLevel / 10000);
        const sblk = Math.round((int * 1.5 + lck * 0.5) * avgLevel / 10000);
        const pred = Math.round((end * 1.0 + agi * 0.5) * avgLevel / 5);
        const mred = Math.round((int * 1.0 + end * 0.5) * avgLevel / 5);
        return [
          `Hero #${h.normalizedId || h.id}: Lv${h.level} ${h.mainClassStr}/${h.subClassStr || '?'} (Rarity:${h.rarity || 0}, Prof:${h.professionStr || '?'})`,
          `  Stats: STR:${h.strength} DEX:${dex} AGI:${agi} INT:${int} WIS:${h.wisdom || 0} VIT:${vit} END:${end} LCK:${lck}`,
          `  HP:${h.hp} MP:${h.mp}`,
          `  Combat: SPEED:${speed} EVA:${eva} BLK:${blk} SBLK:${sblk} P.RED:${pred} M.RED:${mred}`,
        ].join('\n');
      }).join('\n\n');

      const encounterSummary = (recentEncounters || []).length > 0
        ? (() => {
            const wins = recentEncounters.filter(e => e.result === 'WIN').length;
            const losses = recentEncounters.filter(e => e.result === 'LOSS').length;
            const flees = recentEncounters.filter(e => e.result === 'FLEE').length;
            const total = recentEncounters.length;
            const enemies = [...new Set(recentEncounters.map(e => e.enemy_id || e.enemyId))];
            const lowHpCount = recentEncounters.filter(e => e.surviving_hero_hp != null && e.surviving_hero_hp < 30).length;
            return `Recent ${total} encounters: ${wins}W/${losses}L/${flees}F (${((wins/total)*100).toFixed(0)}% win rate). Enemies faced: ${enemies.join(', ')}.${lowHpCount > 0 ? ` ${lowHpCount} fights ended with critical HP (<30%).` : ''}`;
          })()
        : 'No recent encounter data available.';

      const chainLabel = zone.activity?.chain_id === 53935 ? 'Crystalvale (DFK)' : zone.activity?.chain_id === 8217 ? 'Serendale (Klaytn)' : `Chain ${zone.activity?.chain_id}`;
      const prompt = [
        `You are a DeFi Kingdoms PvE hunt advisor. Analyze this party's combat fitness for their current hunt zone.`,
        ``,
        `Zone: ${zone.activity?.name || 'Unknown'} (Activity ID: ${zone.activity?.activity_id || '?'}, ${chainLabel})`,
        ``,
        `Party (${heroes.length} heroes, avg level ${avgLevel.toFixed(1)}):`,
        heroSummary,
        ``,
        `Combat stat notes: SPEED=turn priority, EVA=dodge chance, BLK=physical block, SBLK=spell block, P.RED=physical damage reduction, M.RED=magic damage reduction.`,
        ``,
        encounterSummary,
        ``,
        `Give 3-5 bullet points covering:`,
        `1. Overall party combat fitness for this zone (consider defensive stats, HP pools, damage output)`,
        `2. Weakest hero and why (cite specific combat stats)`,
        `3. Stamina/rest strategy`,
        `4. Whether to re-queue here or switch zones based on win rate and survivability`,
        `5. Any hero swaps that would improve party composition`,
        `Be direct and specific. Reference hero IDs and classes.`,
      ].join('\n');

      const { default: OpenAI } = await import('openai');
      const oai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
      const completion = await oai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 400,
        temperature: 0.7,
      });
      const analysis = completion.choices[0]?.message?.content?.trim() ?? null;
      res.json({ ok: true, analysis });
    } catch (err) {
      console.error('[PVE Hunts] AI analysis error:', err.message);
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  // ============================================================================
  // PVE HUNT BATTLE LOG & PER-ENCOUNTER ANALYSIS
  // ============================================================================

  // GET /api/admin/pve/hunt-battle-log?encounterId=ID
  app.get('/api/admin/pve/hunt-battle-log', isAdminOrHasTab('pve-hunts'), async (req, res) => {
    const encounterId = parseInt(req.query.encounterId);
    if (!Number.isFinite(encounterId)) {
      return res.status(400).json({ ok: false, error: 'Valid encounterId required' });
    }
    try {
      const { rawPg } = await import('./server/db.js');
      const rows = await rawPg.unsafe(
        `SELECT * FROM hunting_encounters WHERE id = $1 LIMIT 1`,
        [encounterId]
      );
      if (rows.length === 0) {
        return res.status(404).json({ ok: false, error: 'Encounter not found' });
      }
      const encounter = rows[0];
      const txHash = encounter.tx_hash;
      if (!txHash) {
        return res.json({ ok: true, decoded: false, reason: 'No transaction hash stored for this encounter.', encounter });
      }

      const realm = encounter.realm || 'dfk';
      const { COMBAT_CONTRACTS, HUNTS_DIAMOND_ABI } = await import('./src/config/combatContracts.ts');
      const rpcUrl = realm === 'klaytn'
        ? COMBAT_CONTRACTS.klaytn.rpcUrl
        : COMBAT_CONTRACTS.dfk.rpcUrl;

      const { ethers } = await import('ethers');
      const provider = new ethers.JsonRpcProvider(rpcUrl);

      let receipt;
      try {
        receipt = await provider.getTransactionReceipt(txHash);
      } catch (rpcErr) {
        console.error('[PVE BattleLog] RPC error fetching receipt:', rpcErr.message);
        return res.json({ ok: true, decoded: false, reason: 'Failed to fetch transaction receipt from RPC.', encounter });
      }

      if (!receipt) {
        return res.json({ ok: true, decoded: false, reason: 'Transaction receipt not found on chain.', encounter });
      }

      const iface = new ethers.Interface(HUNTS_DIAMOND_ABI);

      let huntCompletedLog = null;
      for (const log of receipt.logs) {
        try {
          const parsed = iface.parseLog({ topics: log.topics, data: log.data });
          if (parsed && parsed.name === 'HuntCompleted') {
            huntCompletedLog = parsed;
            break;
          }
        } catch {
          // Not a matching event
        }
      }

      if (!huntCompletedLog) {
        return res.json({
          ok: true,
          decoded: false,
          reason: 'HuntCompleted event not found in transaction logs.',
          encounter,
          logCount: receipt.logs.length,
        });
      }

      const args = huntCompletedLog.args;
      const huntId = args[0]?.toString();
      const huntStruct = args[1];
      const huntWon = args[2];
      const heroIds = args[3]?.map(id => id.toString()) || [];

      const huntData = {
        huntId,
        huntWon,
        heroIds,
        huntDataId: huntStruct?.huntDataId?.toString() || null,
        startBlock: huntStruct?.startBlock?.toString() || null,
        player: huntStruct?.player || null,
        status: huntStruct?.status?.toString() || null,
        retries: huntStruct?.retries?.toString() || null,
      };

      return res.json({
        ok: true,
        decoded: false,
        eventDecoded: true,
        turnDataAvailable: false,
        reason: 'HuntCompleted event decoded successfully, but the on-chain event does not contain turn-by-turn battle data — only hunt outcome metadata.',
        encounter,
        huntEventData: huntData,
        turns: [],
      });
    } catch (err) {
      console.error('[PVE BattleLog] Error:', err.message);
      res.status(500).json({ ok: false, error: 'Failed to fetch battle log data.' });
    }
  });

  // GET /api/admin/pve/firebase-hunt-log — full Firebase turn-by-turn battle log for a hunt
  app.get('/api/admin/pve/firebase-hunt-log', isAdminOrHasTab('pve-hunts', 'hunt-companion'), async (req, res) => {
    try {
      const raw = (req.query.huntRef || '').trim();
      if (!raw) return res.status(400).json({ ok: false, error: 'huntRef required (e.g. 53935-762160)' });

      // Accept bare `chainId-huntId` or URLs containing it
      const match = raw.match(/(\d+)-(\d+)/);
      if (!match) return res.status(400).json({ ok: false, error: 'Could not parse huntRef — expected format: chainId-huntId (e.g. 53935-762160)' });
      const huntRef = `${match[1]}-${match[2]}`;

      const idToken = await getFirebaseIdToken();
      const FSBASE = `https://firestore.googleapis.com/v1/projects/${DFK_FIREBASE_PROJECT_ID}/databases/combat-engine/documents`;

      // 1. Fetch parent battle document (metadata, hasWinner, scenarioId etc.)
      let battleMeta = null;
      try {
        const metaResp = await fetch(`${FSBASE}/battles/${huntRef}`, { headers: { Authorization: `Bearer ${idToken}` } });
        if (metaResp.ok) {
          const metaDoc = await metaResp.json();
          battleMeta = parseFirestoreDoc(metaDoc);
        }
      } catch {}

      // 2. Fetch all turn sub-documents (paginated up to 500)
      let allDocs = [];
      let pageToken = null;
      do {
        const pageUrl = `${FSBASE}/battles/${huntRef}/battle-logs?pageSize=200${pageToken ? `&pageToken=${pageToken}` : ''}`;
        const pageResp = await fetch(pageUrl, { headers: { Authorization: `Bearer ${idToken}` } });
        if (!pageResp.ok) {
          const txt = await pageResp.text();
          return res.status(pageResp.status).json({ ok: false, error: `Firestore turns fetch failed: ${txt.slice(0, 200)}` });
        }
        const pageData = await pageResp.json();
        const docs = (pageData.documents || []).map(parseFirestoreDoc).filter(Boolean);
        allDocs = allDocs.concat(docs);
        pageToken = pageData.nextPageToken || null;
      } while (pageToken && allDocs.length < 500);

      // Sort turns by _id (numeric)
      allDocs.sort((a, b) => Number(a._id) - Number(b._id));

      const { buildFirebaseBattleState } = await import('./server/firebase-hunt-state.ts');
      const battleState = buildFirebaseBattleState(huntRef, battleMeta, allDocs);

      return res.json({
        ok: true,
        ...battleState,
      });
    } catch (err) {
      console.error('[FirebaseHuntLog] Error:', err.message);
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  // POST /api/admin/pve/hunt-encounter-analysis
  app.post('/api/admin/pve/hunt-encounter-analysis', isAdminOrHasTab('pve-hunts'), async (req, res) => {
    const { encounterId, heroes, enemyId, result, turns, survivingHeroCount, survivingHeroHp, drops } = req.body;
    if (!encounterId || !heroes || !Array.isArray(heroes)) {
      return res.status(400).json({ ok: false, error: 'encounterId, heroes[] required' });
    }
    try {
      const avgLevel = heroes.reduce((s, h) => s + (h.level || 1), 0) / heroes.length;
      const heroSummary = heroes.map(h => {
        const agi = h.agility || 0, lck = h.luck || 0, dex = h.dexterity || 0;
        const vit = h.vitality || 0, end = h.endurance || 0, int_ = h.intelligence || 0;
        const speed = Math.round(agi * 1.7 * avgLevel / 100);
        const eva = Math.round((agi * 1.5 + lck * 0.5) * avgLevel / 10000);
        const pred = Math.round((end * 1.0 + agi * 0.5) * avgLevel / 5);
        const mred = Math.round((int_ * 1.0 + end * 0.5) * avgLevel / 5);
        return [
          `Hero #${h.normalizedId || h.id}: Lv${h.level} ${h.mainClassStr}/${h.subClassStr || '?'} (Rarity:${h.rarity || 0})`,
          `  Stats: STR:${h.strength} DEX:${dex} AGI:${agi} INT:${int_} WIS:${h.wisdom || 0} VIT:${vit} END:${end} LCK:${lck}`,
          `  HP:${h.hp} MP:${h.mp}`,
          `  Combat: SPEED:${speed} EVA:${eva} P.RED:${pred} M.RED:${mred}`,
        ].join('\n');
      }).join('\n\n');

      const enemyLabel = (enemyId || 'unknown').split('_').map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ');

      const hasTurns = turns && Array.isArray(turns) && turns.length > 0;
      const turnSummary = hasTurns
        ? `Turn-by-turn data (${turns.length} turns):\n` + turns.map(t =>
            `  Turn ${t.turnNumber}: ${t.actorSide === 'hero' ? `Hero slot ${t.actorSlot}` : `Enemy slot ${t.actorSlot}`} used ${t.skillId || 'basic attack'} -> ${(t.targets || []).map(tgt => `slot ${tgt.slot} (${tgt.hpBefore}->${tgt.hpAfter}, ${tgt.damage} dmg)`).join(', ')}`
          ).join('\n')
        : 'No turn-by-turn data available for this encounter. Analyze based on party stats and outcome.';

      const outcomeStr = `Encounter result: ${result || 'UNKNOWN'}. Surviving heroes: ${survivingHeroCount ?? '?'}${survivingHeroHp != null ? ` at ${survivingHeroHp}% HP` : ''}.`;
      const dropStr = drops && Array.isArray(drops) && drops.length > 0
        ? `Drops: ${drops.map(d => `${d.quantity}x ${d.itemId}`).join(', ')}`
        : 'No drops.';

      const prompt = [
        `You are a DeFi Kingdoms PvE combat analyst. Analyze this specific encounter and provide actionable recommendations.`,
        ``,
        `Enemy: ${enemyLabel} (${enemyId})`,
        `${outcomeStr}`,
        `${dropStr}`,
        ``,
        `Party (${heroes.length} heroes, avg level ${avgLevel.toFixed(1)}):`,
        heroSummary,
        ``,
        turnSummary,
        ``,
        `Provide 3-5 specific, actionable bullet recommendations covering:`,
        `1. Which hero underperformed in this encounter and why (cite hero IDs and specific stats)`,
        `2. Skill or gear adjustments that could improve the outcome`,
        `3. Whether the party composition is suitable for ${enemyLabel}`,
        `4. Speed/agility analysis — did the party have enough turn priority?`,
        `5. Survivability assessment — was HP/defense adequate?`,
        `Reference specific hero IDs (e.g., Hero #1204) and stats in your recommendations. Be direct and specific.`,
      ].join('\n');

      const { default: OpenAI } = await import('openai');
      const oai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
      const completion = await oai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 500,
        temperature: 0.7,
      });
      const analysis = completion.choices[0]?.message?.content?.trim() ?? null;
      res.json({ ok: true, analysis });
    } catch (err) {
      console.error('[PVE Encounter Analysis] Error:', err.message);
      res.status(500).json({ ok: false, error: 'Failed to generate encounter analysis.' });
    }
  });

  // ============================================================================
  // PVE COMPANION API
  // ============================================================================

  function getBearerToken(req) {
    const header = req.headers.authorization || req.headers.Authorization || '';
    if (typeof header === 'string' && header.toLowerCase().startsWith('bearer ')) {
      return header.slice(7).trim();
    }
    return req.headers['x-extension-auth'] || null;
  }

  async function resolveDashboardCompanionActorFromSessionToken(sessionToken, options = {}) {
    if (!sessionToken) return null;

    const [userSession] = await db.select().from(dashboardUserSessions)
      .where(eq(dashboardUserSessions.sessionToken, String(sessionToken))).limit(1);
    if (!userSession || new Date(userSession.expiresAt) < new Date()) {
      return null;
    }

    const [user] = await db.select().from(dashboardUsers)
      .where(eq(dashboardUsers.id, userSession.userId)).limit(1);
    if (!user || !user.isActive || (user.expiresAt && new Date(user.expiresAt) < new Date())) {
      return null;
    }

    return {
      ownerUserId: `dashboard:${user.id}`,
      ownerAuthType: 'dashboard',
      ownerUsername: user.displayName || user.username,
      dashboardUserId: user.id,
      extensionSessionToken: options.includeExtensionSessionToken ? userSession.sessionToken : undefined,
    };
  }

  async function resolveCompanionActor(req) {
    if (req.user?.userId) {
      const rawId = String(req.user.userId);
      if (rawId.startsWith('dashboard-')) {
        const userId = rawId.replace(/^dashboard-/, '');
        return {
          ownerUserId: `dashboard:${userId}`,
          ownerAuthType: 'dashboard',
          ownerUsername: req.user.username || `dashboard-${userId}`,
          dashboardUserId: Number(userId),
        };
      }
      return {
        ownerUserId: `admin:${rawId}`,
        ownerAuthType: 'admin',
        ownerUsername: req.user.username || rawId,
        dashboardUserId: null,
      };
    }

    const siteSessionToken = req.cookies?.user_session;
    if (siteSessionToken) {
      const siteActor = await resolveDashboardCompanionActorFromSessionToken(siteSessionToken);
      if (siteActor) return siteActor;
    }

    const extensionToken = getBearerToken(req);
    if (extensionToken) {
      const extensionActor = await resolveDashboardCompanionActorFromSessionToken(
        extensionToken,
        { includeExtensionSessionToken: true }
      );
      if (extensionActor) return extensionActor;
    }

    return null;
  }

  async function requireCompanionActor(req, res, next) {
    try {
      const actor = await resolveCompanionActor(req);
      if (!actor) return res.status(401).json({ ok: false, error: 'Not authenticated' });
      req.companionActor = actor;
      next();
    } catch (err) {
      console.error('[CompanionAuth] Error:', err.message);
      res.status(500).json({ ok: false, error: 'Authentication check failed' });
    }
  }

  function hydrateCompanionSessionRecord(row, memSession) {
    const latestHuntId = row.hunt_id || memSession?.latestFrame?.captureMeta?.huntId || null;
    const selectedAt = row.selected_by_extension_at || null;
    const refreshRequired = !!row.refresh_required_at;
    return {
      id: row.id,
      session_token: row.session_token,
      owner_user_id: row.owner_user_id,
      owner_auth_type: row.owner_auth_type,
      owner_username: row.owner_username,
      label: row.label,
      wallet_address: row.wallet_address,
      hunt_id: latestHuntId,
      status: row.status,
      created_at: row.created_at,
      last_seen_at: row.last_seen_at,
      selected_by_extension_at: selectedAt,
      refresh_required_at: row.refresh_required_at,
      completed_at: row.completed_at,
      archived_at: row.archived_at,
      connected_clients: memSession?.clients?.size || 0,
      latest_hunt_id: latestHuntId,
      requires_tab_refresh: refreshRequired,
    };
  }

  async function getCompanionRawPg() {
    const { rawPg } = await import('./server/db.js');
    return rawPg;
  }

  async function listOwnedCompanionSessions(actor) {
    const rawPg = await getCompanionRawPg();
    const rows = await rawPg`
      SELECT * FROM pve_companion_sessions
      WHERE owner_user_id = ${actor.ownerUserId}
      ORDER BY COALESCE(last_seen_at, created_at) DESC, created_at DESC
    `;
    return rows.map((row) => hydrateCompanionSessionRecord(row, companionSessions.get(row.session_token)));
  }

  async function getOwnedCompanionSession(sessionId, actor) {
    const rawPg = await getCompanionRawPg();
    const rows = await rawPg`
      SELECT * FROM pve_companion_sessions
      WHERE id = ${sessionId} AND owner_user_id = ${actor.ownerUserId}
      LIMIT 1
    `;
    return rows.length > 0 ? rows[0] : null;
  }

  // Extension account login using dashboard user credentials.
  app.post('/api/user/extension/login', async (req, res) => {
    try {
      const { username, password } = req.body || {};
      if (!username || !password) {
        return res.status(400).json({ ok: false, error: 'Username and password are required' });
      }

      const [user] = await db.select().from(dashboardUsers)
        .where(eq(dashboardUsers.username, username)).limit(1);
      if (!user) return res.status(401).json({ ok: false, error: 'Invalid username or password' });

      const passwordHash = crypto.createHash('sha256').update(password).digest('hex');
      if (user.passwordHash !== passwordHash) {
        return res.status(401).json({ ok: false, error: 'Invalid username or password' });
      }
      if (!user.isActive) return res.status(403).json({ ok: false, error: 'Account is disabled' });
      if (user.expiresAt && new Date(user.expiresAt) < new Date()) {
        return res.status(403).json({ ok: false, error: 'Account has expired' });
      }
      if (!Array.isArray(user.allowedTabs) || !user.allowedTabs.includes('pve-hunts')) {
        return res.status(403).json({ ok: false, error: 'PVE Hunts access not enabled for this account' });
      }

      const extensionAuthToken = crypto.randomBytes(32).toString('hex');
      const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);
      await db.insert(dashboardUserSessions).values({
        userId: user.id,
        sessionToken: extensionAuthToken,
        expiresAt,
      });

      const actor = {
        ownerUserId: `dashboard:${user.id}`,
        ownerAuthType: 'dashboard',
        ownerUsername: user.displayName || user.username,
        dashboardUserId: user.id,
      };
      const sessions = await listOwnedCompanionSessions(actor);

      res.json({
        ok: true,
        authToken: extensionAuthToken,
        user: {
          id: user.id,
          username: user.username,
          displayName: user.displayName || user.username,
          allowedTabs: user.allowedTabs || [],
        },
        sessions,
      });
    } catch (err) {
      console.error('[ExtensionLogin] Error:', err.message);
      res.status(500).json({ ok: false, error: 'Extension login failed', detail: err.message || 'Unknown error' });
    }
  });

