  app.post('/api/admin/pve/companion/explain', isAdminOrHasTab('pve-hunts', 'hunt-companion'), async (req, res) => {
    try {
      const { recommendation, battleState, enemyId } = req.body;
      if (!recommendation) return res.status(400).json({ ok: false, error: 'recommendation required' });

      const { getEnemy } = await import('./server/pve-enemy-catalog.ts');
      const enemy = getEnemy(enemyId || 'MAD_BOAR');

      const heroSummary = (battleState?.heroes || []).map(h =>
        `Hero slot ${h.slot} (${h.mainClass || '?'}): ${h.currentHp}/${h.maxHp} HP, ${h.currentMp}/${h.maxMp} MP, ${h.isAlive ? 'alive' : 'dead'}`
      ).join('\n');

      const enemySummary = enemy
        ? `${enemy.name} (Tier ${enemy.tier}): ${battleState?.enemies?.[0]?.currentHp || enemy.hp}/${enemy.hp} HP, ATK:${enemy.atk}, DEF:${enemy.def}, SPD:${enemy.spd}`
        : 'Unknown enemy';

      const prompt = [
        `You are a DeFi Kingdoms PVE battle advisor explaining a recommended action to a player during a live hunt battle.`,
        ``,
        `Current Battle State (Turn ${battleState?.turnNumber || '?'}):`,
        `Heroes:`,
        heroSummary || 'No hero data',
        `Enemy: ${enemySummary}`,
        ``,
        `Recommended Action: ${recommendation.action}`,
        `Score: ${recommendation.totalScore} (Damage EV: ${recommendation.damageEv}, Kill Chance: ${Math.round(recommendation.killChance * 100)}%, Survival Delta: ${recommendation.survivalDelta})`,
        `Reasoning: ${recommendation.reasoning}`,
        ``,
        `Explain in 2-3 sentences why this is the best action right now. Be specific about the tactical situation. Use plain language a gamer would understand.`,
      ].join('\n');

      const { default: OpenAI } = await import('openai');
      const oai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
      const completion = await oai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 200,
        temperature: 0.7,
      });
      const explanation = completion.choices[0]?.message?.content?.trim() ?? null;
      res.json({ ok: true, explanation });
    } catch (err) {
      console.error('[Companion] Explain error:', err.message);
      res.status(500).json({ ok: false, error: 'Failed to generate explanation' });
    }
  });

  // ============================================================================
  // DFK ENEMY PREDICTION API
  // ============================================================================

  app.post('/api/dfk/predict-enemy-action', isAdminOrHasTab('pve-hunts'), async (req, res) => {
    try {
      const { encounterType, enemyName, enemyType, executionMode, liveState } = req.body;
      if (!liveState) return res.status(400).json({ ok: false, error: 'liveState required' });

      const { extractStateFeatures } = await import('./server/pve-feature-extractor.ts');
      const { getHeuristicPriors } = await import('./server/pve-heuristic-priors.ts');
      const { readFileSync } = await import('fs');

      // Normalize incoming enemy type to the policy file's ID format
      const ENEMY_ID_MAP = {
        'mad_boar': 'baby_boar',
        'baby_boar': 'baby_boar',
        'mama_boar': 'mama_boar',
        'motherclucker': 'bad_motherclucker',
        'bad_motherclucker': 'bad_motherclucker',
        'baby_rocboc': 'baby_rocboc',
        'forest_wolf': 'baby_boar',
      };
      const rawType = (enemyType || '').toLowerCase().replace(/\s+/g, '_');
      let normalizedType = ENEMY_ID_MAP[rawType] || rawType;
      // Fallback: use encounterType to guess the primary enemy
      if (!ENEMY_ID_MAP[rawType]) {
        if ((encounterType || '').includes('boar')) normalizedType = 'baby_boar';
        else if ((encounterType || '').includes('motherclucker')) normalizedType = 'bad_motherclucker';
      }

      // Load available actions from bundled policy file
      let availableActions = ['Basic Attack'];
      try {
        const policiesRaw = readFileSync('./server/data/enemy_policies.master.json', 'utf8');
        const policiesData = JSON.parse(policiesRaw);
        const policyEntry = (policiesData.policies || []).find(p => p.enemyId === normalizedType);
        if (policyEntry?.actions?.length) {
          availableActions = policyEntry.actions.map(a => a.actionId);
        }
      } catch (_) {}

      // Build the enemy unit from liveState
      const enemyUnit = {
        name: enemyName || enemyType || 'Unknown',
        type: normalizedType,
        side: 'enemy',
        currentHp: liveState.enemyHp ?? null,
        maxHp: liveState.enemyMaxHp ?? null,
        currentMp: liveState.enemyMp ?? null,
        maxMp: liveState.enemyMaxMp ?? null,
        position: 0,
        isAlive: (liveState.enemyHp ?? 1) > 0,
        buffs: liveState.activeBuffs || [],
        debuffs: liveState.activeDebuffs || [],
        isChanneling: false,
      };

      // Build hero units (the "enemies" from the enemy's POV)
      const heroUnits = (liveState.heroes || []).map((h, i) => ({
        name: h.name || `Hero-${i}`,
        type: 'hero',
        side: 'player',
        currentHp: h.currentHp ?? null,
        maxHp: h.maxHp ?? null,
        currentMp: h.currentMp ?? null,
        maxMp: h.maxMp ?? null,
        position: i,
        isAlive: h.isAlive !== false,
        buffs: h.buffs || [],
        debuffs: h.debuffs || [],
        isChanneling: false,
      }));

      const snapshot = {
        encounterType: encounterType || 'unknown',
        turn: liveState.turnNumber || 1,
        battleBudgetRemaining: liveState.battleBudgetRemaining ?? null,
        consumableQuantities: {},
        units: [enemyUnit, ...heroUnits],
        lockoutStates: {},
      };

      const features = extractStateFeatures(snapshot, enemyUnit.name, availableActions);
      const heuristicPriors = getHeuristicPriors(normalizedType, features, availableActions);

      // Build reasoning strings from computed features
      const reasoning = [];
      if (features.enemyHpPercent !== null) {
        const hpLabel = features.enemyHpPercent <= 25 ? 'critical' : features.enemyHpPercent <= 50 ? 'low' : features.enemyHpPercent <= 75 ? 'mid' : 'high';
        reasoning.push(`Enemy HP ${features.enemyHpPercent}% (${hpLabel})`);
      }
      if (features.enemiesAliveCount !== null) {
        reasoning.push(`${features.enemiesAliveCount} hero(es) alive`);
      }
      if ((features.alliesAliveCount ?? 0) > 1) {
        reasoning.push(`${(features.alliesAliveCount ?? 1) - 1} enemy companion(s) alive`);
      }
      if (features.currentDebuffFlags.length > 0) {
        reasoning.push(`Enemy debuffs: ${features.currentDebuffFlags.join(', ')}`);
      }
      if (features.activePassiveFlags.length > 0) {
        reasoning.push(`Passive triggers: ${features.activePassiveFlags.join(', ')}`);
      }
      const topEntry = Object.entries(heuristicPriors).sort((a, b) => b[1] - a[1])[0];
      if (topEntry) {
        reasoning.push(`Most likely next: ${topEntry[0]} (${Math.round(topEntry[1] * 100)}%)`);
      }

      const availability = availableActions.map(name => ({
        name,
        available: true,
        reason: 'no cooldown tracked',
      }));

      const HEURISTIC_CONFIDENCE = 0.40;
      const isAutoMode = executionMode === 'auto_execute';

      return res.json({
        ok: true,
        enemy: enemyUnit.name,
        legalActions: availableActions,
        availability,
        heuristicPriors,
        learnedPolicy: null,
        finalPolicy: heuristicPriors,
        confidence: HEURISTIC_CONFIDENCE,
        sampleCount: 0,
        consumableOptions: [],
        reasoning,
        executionMode: executionMode || 'observe_only',
        simulation: null,
        safetyCheck: {
          canAutoExecute: false,
          blockReasons: isAutoMode ? ['heuristic-only mode — learned policy required for auto-execute'] : [],
          checksPassed: ['heuristic_priors_computed', 'feature_extraction_ok'],
        },
        budget: liveState.battleBudgetRemaining ?? null,
      });
    } catch (err) {
      console.error('[PVE Predict] Error:', err.message);
      return res.status(500).json({ ok: false, error: err.message });
    }
  });

  // ============================================================================
  // DFK TELEMETRY API (session-token gated, no Discord OAuth)
  // ============================================================================

  const _telemetryRateLimits = new Map();
  const TELEMETRY_RATE_LIMIT = 100;
  const TELEMETRY_RATE_WINDOW = 60_000;

  function checkTelemetryRate(token) {
    const now = Date.now();
    let entry = _telemetryRateLimits.get(token);
    if (!entry || now - entry.windowStart > TELEMETRY_RATE_WINDOW) {
      entry = { windowStart: now, count: 0 };
      _telemetryRateLimits.set(token, entry);
    }
    entry.count++;
    return entry.count <= TELEMETRY_RATE_LIMIT;
  }

  async function validateSessionToken(sessionToken) {
    if (!sessionToken || typeof sessionToken !== 'string') return null;
    const { rawPg } = await import('./server/db.js');
    const rows = await rawPg`SELECT * FROM pve_companion_sessions WHERE session_token = ${sessionToken}`;
    return rows.length > 0 ? rows[0] : null;
  }

  app.post('/api/dfk/telemetry/session', async (req, res) => {
    try {
      const { sessionToken, huntId, walletAddress, mode } = req.body;
      const session = await validateSessionToken(sessionToken);
      if (!session) return res.status(401).json({ ok: false, error: 'Invalid session token' });
      if (!checkTelemetryRate(sessionToken)) return res.status(429).json({ ok: false, error: 'Rate limit exceeded' });

      const { rawPg } = await import('./server/db.js');

      // Create-or-join: reuse an active session for the same token + huntId
      if (huntId) {
        const existing = await rawPg`
          SELECT * FROM dfk_hunt_sessions
          WHERE session_token_id = ${session.id}
            AND hunt_id = ${String(huntId)}
            AND status != 'completed'
          ORDER BY created_at DESC
          LIMIT 1
        `;
        if (existing.length > 0) {
          await rawPg`UPDATE dfk_hunt_sessions SET updated_at = NOW() WHERE id = ${existing[0].id}`;
          return res.json({ ok: true, huntSession: existing[0], joined: true });
        }
      }

      const rows = await rawPg`
        INSERT INTO dfk_hunt_sessions (hunt_id, wallet_address, mode, session_token_id)
        VALUES (${huntId ? String(huntId) : null}, ${walletAddress || null}, ${mode || 'patrol'}, ${session.id})
        RETURNING *
      `;
      res.json({ ok: true, huntSession: rows[0], joined: false });
    } catch (err) {
      console.error('[Telemetry] Session create error:', err.message);
      res.status(500).json({ ok: false, error: 'Failed to create hunt session' });
    }
  });

  async function verifyHuntSessionOwnership(rawPg, huntSessionId, sessionId) {
    const rows = await rawPg`SELECT id FROM dfk_hunt_sessions WHERE id = ${huntSessionId} AND session_token_id = ${sessionId}`;
    return rows.length > 0;
  }

  // Resolve huntSessionId from token when the extension sends null (fallback mode).
  // Returns the integer id of the most recent active hunt session for this token, or null.
  async function resolveHuntSessionId(rawPg, providedId, sessionId) {
    if (providedId) return providedId;
    const rows = await rawPg`
      SELECT id FROM dfk_hunt_sessions
      WHERE session_token_id = ${sessionId} AND status != 'completed'
      ORDER BY created_at DESC LIMIT 1
    `.catch(() => []);
    return rows.length > 0 ? rows[0].id : null;
  }

  app.post('/api/dfk/telemetry/event', async (req, res) => {
    try {
      const { sessionToken, turnNumber, actor, actorSide, target, ability, damage, manaDelta, effects, rawText } = req.body;
      let { huntSessionId } = req.body;
      const session = await validateSessionToken(sessionToken);
      if (!session) return res.status(401).json({ ok: false, error: 'Invalid session token' });
      if (!checkTelemetryRate(sessionToken)) return res.status(429).json({ ok: false, error: 'Rate limit exceeded' });
      if (turnNumber === undefined) return res.status(400).json({ ok: false, error: 'turnNumber required' });

      const { rawPg } = await import('./server/db.js');
      huntSessionId = await resolveHuntSessionId(rawPg, huntSessionId, session.id);
      if (!huntSessionId) return res.status(400).json({ ok: false, error: 'No active hunt session found for this token — call /api/dfk/telemetry/session first' });
      if (!(await verifyHuntSessionOwnership(rawPg, huntSessionId, session.id))) {
        return res.status(403).json({ ok: false, error: 'Hunt session does not belong to this token' });
      }
      const rows = await rawPg`
        INSERT INTO dfk_battle_log_events (hunt_session_id, turn_number, actor, actor_side, target, ability, damage, mana_delta, effects, raw_text)
        VALUES (${huntSessionId}, ${turnNumber}, ${actor || null}, ${actorSide || null}, ${target || null}, ${ability || null}, ${damage || null}, ${manaDelta || null}, ${effects ? JSON.stringify(effects) : null}, ${rawText || null})
        RETURNING id
      `;
      await rawPg`UPDATE dfk_hunt_sessions SET event_count = event_count + 1, updated_at = NOW() WHERE id = ${huntSessionId}`;

      // Also mirror to companion session (HTTP fallback path) and run scoring engine
      if (!companionSessions.has(sessionToken)) {
        companionSessions.set(sessionToken, {
          clients: new Set(),
          turnEvents: [],
          heroStates: null,
          enemyId: null,
          battleBudgetRemaining: null,
          consumableQuantities: {},
          latestFrame: null,
          rawFrames: [],
        });
      }
      const memSession = companionSessions.get(sessionToken);
      if (memSession) {
        if (req.body.combatFrame) {
          const { normalizeCombatFrame, getPrimaryEnemyId } = await import('./server/pve-combat-frame.ts');
          const normalizedFrame = normalizeCombatFrame(req.body.combatFrame);
          memSession.latestFrame = normalizedFrame;
          memSession.rawFrames.push(normalizedFrame);
          if (memSession.rawFrames.length > 50) memSession.rawFrames.shift();
          if (!memSession.enemyId) memSession.enemyId = getPrimaryEnemyId(normalizedFrame) || memSession.enemyId;
        }
        const httpActiveHeroSlot = req.body.activeHeroSlot != null ? Number(req.body.activeHeroSlot) : 0;
        const turnMsg = { actor, actorSide, actorSlot: req.body.actorSlot || null, skillId: ability || null, effects: effects || [], huntId: req.body.huntId || null, activeHeroSlot: httpActiveHeroSlot };
        memSession.turnEvents.push(turnMsg);
        if (httpActiveHeroSlot != null) memSession.lastActiveHeroSlot = httpActiveHeroSlot;
        // Also persist to pve_turn_events so session status polling picks it up
        const compRows = await rawPg`SELECT id FROM pve_companion_sessions WHERE session_token = ${sessionToken}`;
        if (compRows.length > 0) {
          const rawMsg = JSON.stringify(req.body);
          const compSessionId = compRows[0].id;
          await rawPg`
            INSERT INTO pve_turn_events (session_id, hunt_id, turn_number, actor_side, actor_slot, skill_id, effects, raw_event)
            VALUES (${compSessionId}, ${req.body.huntId || null}, ${turnNumber || 0}, ${actorSide || 'unknown'}, ${null}, ${ability || null}, ${JSON.stringify(effects || [])}, ${rawMsg})
          `.catch(() => {});
        }
        // Run scoring engine if we have enough context
        if (memSession.heroStates && memSession.enemyId) {
          try {
            const { getEnemy, getEnemyOrFallback } = await import('./server/pve-enemy-catalog.ts');
            const { scoreActions, buildBattleStateFromTurnEvents } = await import('./server/pve-scoring-engine.ts');
            const { enrichBattleStateFromCombatFrame, buildFallbackEnemyEntry, summarizeCombatFrameBattleState } = await import('./server/pve-combat-frame.ts');
            const enemyEntry = getEnemy(memSession.enemyId) || getEnemyOrFallback(memSession.enemyId, buildFallbackEnemyEntry(memSession.enemyId, memSession.latestFrame));
            if (enemyEntry) {
              const activeSlot = memSession.lastActiveHeroSlot ?? 0;
              let battleState = buildBattleStateFromTurnEvents(
                memSession.heroStates, enemyEntry, memSession.turnEvents, activeSlot,
                memSession.battleBudgetRemaining, memSession.consumableQuantities,
              );
              battleState = enrichBattleStateFromCombatFrame(battleState, memSession.latestFrame, enemyEntry);
              const recommendations = scoreActions(battleState);
              const responseMsg = JSON.stringify({
                type: 'recommendation',
                turnNumber: memSession.turnEvents.length,
                recommendations: recommendations.slice(0, 5),
                battleState: summarizeCombatFrameBattleState(memSession.latestFrame, battleState),
                combatFrame: memSession.latestFrame,
              });
              for (const client of memSession.clients) {
                if (client.readyState === 1) client.send(responseMsg);
              }
            }
          } catch (scoreErr) {
            console.warn('[Telemetry] HTTP scoring engine error:', scoreErr.message);
          }
        }
      }

      res.json({ ok: true, eventId: rows[0]?.id });
    } catch (err) {
      console.error('[Telemetry] Event insert error:', err.message);
      res.status(500).json({ ok: false, error: 'Failed to insert event' });
    }
  });

  app.post('/api/dfk/telemetry/snapshot', async (req, res) => {
    try {
      const { sessionToken, type } = req.body;
      let { huntSessionId } = req.body;
      const session = await validateSessionToken(sessionToken);
      if (!session) return res.status(401).json({ ok: false, error: 'Invalid session token' });
      if (!checkTelemetryRate(sessionToken)) return res.status(429).json({ ok: false, error: 'Rate limit exceeded' });

      const { rawPg } = await import('./server/db.js');
      huntSessionId = await resolveHuntSessionId(rawPg, huntSessionId, session.id);
      if (!huntSessionId) return res.status(400).json({ ok: false, error: 'No active hunt session found for this token — call /api/dfk/telemetry/session first' });
      if (!(await verifyHuntSessionOwnership(rawPg, huntSessionId, session.id))) {
        return res.status(403).json({ ok: false, error: 'Hunt session does not belong to this token' });
      }

      if (type === 'turn') {
        const { turnNumber, fullState } = req.body;
        if (turnNumber === undefined || !fullState) return res.status(400).json({ ok: false, error: 'turnNumber and fullState required for turn snapshot' });
        const rows = await rawPg`
          INSERT INTO dfk_turn_snapshots (hunt_session_id, turn_number, full_state)
          VALUES (${huntSessionId}, ${turnNumber}, ${JSON.stringify(fullState)})
          RETURNING id
        `;
        await rawPg`UPDATE dfk_hunt_sessions SET snapshot_count = snapshot_count + 1, updated_at = NOW() WHERE id = ${huntSessionId}`;

        if (!companionSessions.has(sessionToken)) {
          companionSessions.set(sessionToken, {
            clients: new Set(),
            turnEvents: [],
            heroStates: null,
            enemyId: null,
            battleBudgetRemaining: null,
            consumableQuantities: {},
            latestFrame: null,
            rawFrames: [],
          });
        }

        const memSnap = companionSessions.get(sessionToken);
        if (memSnap && req.body.combatFrame) {
          const { normalizeCombatFrame, getPrimaryEnemyId } = await import('./server/pve-combat-frame.ts');
          const normalizedFrame = normalizeCombatFrame(req.body.combatFrame);
          memSnap.latestFrame = normalizedFrame;
          memSnap.rawFrames.push(normalizedFrame);
          if (memSnap.rawFrames.length > 50) memSnap.rawFrames.shift();
          if (!memSnap.enemyId) memSnap.enemyId = getPrimaryEnemyId(normalizedFrame) || memSnap.enemyId;
        }

        // HTTP-fallback hero hydration: if fullState carries heroes (state_snapshot sent via HTTP),
        // seed the in-memory companion session so scoring can run on subsequent turn events.
        if (memSnap && fullState.heroes?.length > 0 && !memSnap.heroStates) {
          memSnap.heroStates = fullState.heroes;
          console.log(`[Companion HTTP] Seeded heroStates from fullState snapshot for token ${sessionToken?.slice(0, 8)}`);
        }
        if (memSnap && !memSnap.enemyId && fullState.enemies?.length > 0) {
          const rawName = (fullState.enemies[0].name || fullState.enemies[0].enemyId || '').trim().toLowerCase().replace(/\s+/g, '_');
          if (rawName) {
            memSnap.enemyId = rawName;
            console.log(`[Companion HTTP] Seeded enemyId '${rawName}' from fullState snapshot`);
          }
        }
        if (memSnap) {
          const snapshotBroadcast = JSON.stringify({
            type: 'state_update',
            heroes: memSnap.heroStates,
            enemyId: memSnap.enemyId,
            combatFrame: memSnap.latestFrame,
          });
          for (const client of memSnap.clients) {
            if (client.readyState === 1) client.send(snapshotBroadcast);
          }
        }

        res.json({ ok: true, snapshotId: rows[0]?.id, type: 'turn' });
      } else {
        const { unitName, unitSide, position, heroId, stats, capturedAtTurn } = req.body;
        if (!unitName || !unitSide || !stats) return res.status(400).json({ ok: false, error: 'unitName, unitSide, and stats required for unit snapshot' });
        const rows = await rawPg`
          INSERT INTO dfk_unit_snapshots (hunt_session_id, unit_name, unit_side, position, hero_id, stats, captured_at_turn)
          VALUES (${huntSessionId}, ${unitName}, ${unitSide}, ${position || 0}, ${heroId || null}, ${JSON.stringify(stats)}, ${capturedAtTurn || null})
          RETURNING id
        `;
        await rawPg`UPDATE dfk_hunt_sessions SET snapshot_count = snapshot_count + 1, updated_at = NOW() WHERE id = ${huntSessionId}`;
        res.json({ ok: true, snapshotId: rows[0]?.id, type: 'unit' });
      }
    } catch (err) {
      console.error('[Telemetry] Snapshot insert error:', err.message);
      res.status(500).json({ ok: false, error: 'Failed to insert snapshot' });
    }
  });

  app.post('/api/dfk/reconcile', async (req, res) => {
    try {
      // Contract: { sessionToken, unitSnapshot, heroId? }
      // unitSnapshot: { stats, baseStats?, level?, unitSide, unitName, items?, position?, capturedAtTurn?, id? }
      // heroId (optional): used to look up authoritative base stats + equipment from dfk_bout_heroes
      const { sessionToken, unitSnapshot, heroId } = req.body;
      const session = await validateSessionToken(sessionToken);
      if (!session) return res.status(401).json({ ok: false, error: 'Invalid session token' });
      if (!checkTelemetryRate(sessionToken)) return res.status(429).json({ ok: false, error: 'Rate limit exceeded' });
      if (!unitSnapshot || !unitSnapshot.stats) return res.status(400).json({ ok: false, error: 'unitSnapshot with stats required' });

      const { reconcileStats } = await import('./server/dfk-reconcile.ts');
      const { rawPg } = await import('./server/db.js');

      let reconcileOptions = {};

      if (unitSnapshot.unitSide === 'enemy') {
        const detectedEnemyId = unitSnapshot.unitName
          ? unitSnapshot.unitName.toUpperCase().replace(/[\s-]+/g, '_')
          : null;
        reconcileOptions = { enemyId: detectedEnemyId };
      } else {
        // Hero path: build base stats and optionally full equipment via existing bot.js pipeline
        let heroBaseStats = null;
        let heroEquipment = null;

        if (heroId) {
          // Authoritative base stats from heroes table
          const heroRows = await rawPg`
            SELECT strength, dexterity, agility, intelligence, wisdom, vitality, endurance, luck, level, hp, mp
            FROM heroes WHERE id = ${parseInt(heroId)} LIMIT 1
          `.catch(() => []);
          if (heroRows.length > 0) {
            const h = heroRows[0];
            heroBaseStats = {
              str: h.strength || 0, dex: h.dexterity || 0, agi: h.agility || 0,
              int: h.intelligence || 0, wis: h.wisdom || 0, vit: h.vitality || 0,
              end: h.endurance || 0, lck: h.luck || 0,
              level: h.level || 1, hp: h.hp, mp: h.mp,
            };
          }

          // Equipment from most recent tournament bout — provides full item data for _heroCombatExtras
          const eqRows = await rawPg`
            SELECT weapon1_json, weapon2_json, armor_json, accessory_json, offhand1_json, offhand2_json, pet_json
            FROM dfk_bout_heroes
            WHERE hero_id = ${String(heroId)}
            ORDER BY id DESC
            LIMIT 1
          `.catch(() => []);
          if (eqRows.length > 0) {
            const eq = eqRows[0];
            heroEquipment = {
              weapon1:   eq.weapon1_json   ? (typeof eq.weapon1_json   === 'string' ? JSON.parse(eq.weapon1_json)   : eq.weapon1_json)   : null,
              weapon2:   eq.weapon2_json   ? (typeof eq.weapon2_json   === 'string' ? JSON.parse(eq.weapon2_json)   : eq.weapon2_json)   : null,
              armor:     eq.armor_json     ? (typeof eq.armor_json     === 'string' ? JSON.parse(eq.armor_json)     : eq.armor_json)     : null,
              accessory: eq.accessory_json ? (typeof eq.accessory_json === 'string' ? JSON.parse(eq.accessory_json) : eq.accessory_json) : null,
              offhand1:  eq.offhand1_json  ? (typeof eq.offhand1_json  === 'string' ? JSON.parse(eq.offhand1_json)  : eq.offhand1_json)  : null,
              pet:       eq.pet_json       ? (typeof eq.pet_json       === 'string' ? JSON.parse(eq.pet_json)       : eq.pet_json)       : null,
            };
          }
        }

        // Fall back to baseStats captured by extension stat panel parser
        if (!heroBaseStats && unitSnapshot.baseStats && Object.keys(unitSnapshot.baseStats).length > 0) {
          const b = unitSnapshot.baseStats;
          heroBaseStats = {
            str: b.str || 0, dex: b.dex || 0, agi: b.agi || 0,
            int: b.int || 0, wis: b.wis || 0, vit: b.vit || 0,
            end: b.end || 0, lck: b.lck || 0,
            level: unitSnapshot.level || 1,
          };
        }

        if (!heroBaseStats) {
          return res.status(400).json({
            ok: false,
            error: 'Cannot reconcile hero stats: provide heroId or include baseStats in unitSnapshot',
          });
        }

        const hasEquipment = !!(heroEquipment) || (Array.isArray(unitSnapshot.items) && unitSnapshot.items.length > 0);
        reconcileOptions = { heroBaseStats, heroEquipment, hasEquipment };
      }

      const result = reconcileStats(unitSnapshot.stats, reconcileOptions);

      // Always persist reconciliation results — create a snapshot row if none provided
      let snapshotId = unitSnapshot.id ?? null;

      // IDOR ownership check: if a snapshot id was provided, verify it belongs to this token's sessions
      if (snapshotId) {
        const ownerCheck = await rawPg`
          SELECT us.id FROM dfk_unit_snapshots us
          JOIN dfk_hunt_sessions hs ON hs.id = us.hunt_session_id
          WHERE us.id = ${snapshotId} AND hs.session_token_id = ${session.id}
          LIMIT 1
        `.catch(() => []);
        if (ownerCheck.length === 0) {
          return res.status(403).json({ ok: false, error: 'Snapshot does not belong to this session token' });
        }
      }

      if (!snapshotId) {
        // Resolve hunt session for this token (needed as FK for dfk_unit_snapshots)
        const huntSessions = await rawPg`
          SELECT id FROM dfk_hunt_sessions
          WHERE session_token_id = ${session.id} AND status != 'completed'
          ORDER BY created_at DESC LIMIT 1
        `.catch(() => []);
        if (huntSessions.length > 0) {
          const snapRows = await rawPg`
            INSERT INTO dfk_unit_snapshots
              (hunt_session_id, unit_name, unit_side, position, hero_id, stats, captured_at_turn)
            VALUES (
              ${huntSessions[0].id},
              ${unitSnapshot.unitName || 'unknown'},
              ${unitSnapshot.unitSide || 'player'},
              ${unitSnapshot.position || 0},
              ${heroId ? String(heroId) : null},
              ${JSON.stringify(unitSnapshot.stats)},
              ${unitSnapshot.capturedAtTurn || null}
            )
            RETURNING id
          `.catch(() => []);
          snapshotId = snapRows[0]?.id ?? null;
        }
      }

      if (snapshotId && result.diffs.length > 0) {
        for (const diff of result.diffs) {
          await rawPg`
            INSERT INTO dfk_reconciliation_results
              (unit_snapshot_id, field, observed, expected, delta, suspected_cause)
            VALUES (${snapshotId}, ${diff.field}, ${diff.observed}, ${diff.expected}, ${diff.delta}, ${diff.suspectedCause})
            ON CONFLICT DO NOTHING
          `.catch(() => null);
        }
      }

      res.json({ ok: true, snapshotId, ...result });
    } catch (err) {
      console.error('[Reconcile] Error:', err.message);
      res.status(500).json({ ok: false, error: 'Reconciliation failed' });
    }
  });

  app.get('/api/admin/telemetry/sessions', isAdminOrHasTab('telemetry'), async (req, res) => {
    try {
      const { rawPg } = await import('./server/db.js');
      const limit = Math.min(parseInt(req.query.limit) || 50, 200);
      const offset = parseInt(req.query.offset) || 0;
      const rows = await rawPg`
        SELECT * FROM dfk_hunt_sessions
        ORDER BY created_at DESC
        LIMIT ${limit} OFFSET ${offset}
      `;
      const countRows = await rawPg`SELECT COUNT(*)::int as total FROM dfk_hunt_sessions`;
      res.json({ ok: true, sessions: rows, total: countRows[0]?.total || 0 });
    } catch (err) {
      console.error('[Telemetry] Sessions fetch error:', err.message);
      res.status(500).json({ ok: false, error: 'Failed to fetch sessions' });
    }
  });

