  const server = http.createServer(app);

  // ─── PVE Companion WebSocket Server ──────────────────────────────────────
  // Eagerly preload master data so it's ready before the first WebSocket turn
  import('./server/pve-master-data.ts').then(m => m.preloadMasterData()).catch(err =>
    console.warn('[MasterData] Preload failed (non-fatal):', err.message)
  );

  const { WebSocketServer } = await import('ws');
  const companionWss = new WebSocketServer({ noServer: true });
  const companionSessions = new Map();

  server.on('upgrade', (request, socket, head) => {
    const url = new URL(request.url, `http://${request.headers.host}`);
    if (url.pathname === '/ws/companion') {
      companionWss.handleUpgrade(request, socket, head, (ws) => {
        companionWss.emit('connection', ws, request);
      });
    } else {
      socket.destroy();
    }
  });

  companionWss.on('connection', (ws) => {
    let sessionToken = null;
    let sessionId = null;
    let heroProfileSentForHunt = null;

    async function maybePushHeroProfiles(huntId, walletAddress) {
      if (!huntId || heroProfileSentForHunt === huntId) return;
      heroProfileSentForHunt = huntId;
      try {
        const { fetchHeroesForHunt } = await import('./server/dfk-graphql-client.ts');
        const heroes = await fetchHeroesForHunt(huntId, walletAddress || undefined);
        if (heroes.length > 0) {
          console.log(`[Companion WS] Auto-pushing ${heroes.length} hero profiles for hunt ${huntId}`);
          ws.send(JSON.stringify({ type: 'hero_profile', heroes, huntId }));
        }
      } catch (err) {
        console.warn(`[Companion WS] Auto hero profile push failed:`, err.message);
      }
    }

    ws.on('message', async (data) => {
      try {
        const msg = JSON.parse(data.toString());
        const { rawPg } = await import('./server/db.js');

        if (msg.type === 'join') {
          sessionToken = msg.sessionToken;
          if (!sessionToken) {
            ws.send(JSON.stringify({ type: 'error', message: 'Missing sessionToken' }));
            return;
          }
          const rows = await rawPg`SELECT * FROM pve_companion_sessions WHERE session_token = ${sessionToken}`;
          if (rows.length === 0) {
            ws.send(JSON.stringify({ type: 'error', message: 'Invalid session token' }));
            return;
          }
          sessionId = rows[0].id;
          await rawPg`UPDATE pve_companion_sessions SET status = 'connected', last_seen_at = CURRENT_TIMESTAMP WHERE id = ${sessionId}`;

          if (!companionSessions.has(sessionToken)) {
            companionSessions.set(sessionToken, {
              clients: new Set(),
              turnEvents: [],
              heroStates: null,
              enemyId: null,
              battleBudgetRemaining: null,
              consumableQuantities: {},
              latestFrame: null,
              rawFrames: [],
            });
          }
          companionSessions.get(sessionToken).clients.add(ws);

          const existingEvents = await rawPg`SELECT * FROM pve_turn_events WHERE session_id = ${sessionId} ORDER BY turn_number ASC`;
          ws.send(JSON.stringify({
            type: 'joined',
            sessionId,
            existingTurns: existingEvents.length,
            status: 'connected',
          }));
          console.log(`[Companion WS] Client joined session ${sessionToken}`);

        } else if (msg.type === 'request_hero_profiles') {
          const huntId = msg.huntId;
          const heroIds = msg.heroIds || [];
          const wallet = msg.wallet || msg.walletAddress || null;
          try {
            const { fetchHeroesByIds, fetchQuestingHeroesByOwner, fetchHeroesForHunt } = await import('./server/dfk-graphql-client.ts');
            let heroes = [];
            if (heroIds.length > 0) {
              heroes = await fetchHeroesByIds(heroIds);
            } else if (wallet) {
              heroes = await fetchQuestingHeroesByOwner(wallet);
            } else if (huntId) {
              heroes = await fetchHeroesForHunt(huntId);
            }
            if (heroes.length > 0) {
              console.log(`[Companion WS] Sending ${heroes.length} hero profiles for hunt ${huntId}`);
              ws.send(JSON.stringify({ type: 'hero_profile', heroes, huntId }));
            }
          } catch (err) {
            console.warn(`[Companion WS] Hero profile fetch failed:`, err.message);
          }

        } else if (msg.type === 'state_snapshot') {
          if (!sessionToken || !sessionId) {
            ws.send(JSON.stringify({ type: 'error', message: 'Not joined to a session' }));
            return;
          }
          const session = companionSessions.get(sessionToken);
          if (session) {
            if (msg.combatFrame) {
              const { normalizeCombatFrame, getPrimaryEnemyId } = await import('./server/pve-combat-frame.ts');
              const normalizedFrame = normalizeCombatFrame(msg.combatFrame);
              session.latestFrame = normalizedFrame;
              session.rawFrames.push(normalizedFrame);
              if (session.rawFrames.length > 50) session.rawFrames.shift();
              if (!session.enemyId) session.enemyId = getPrimaryEnemyId(normalizedFrame) || session.enemyId;
            }
            session.heroStates = msg.heroes || null;
            // Prefer explicit enemyId, then auto-detect from enemies array name
            if (msg.enemyId) {
              session.enemyId = msg.enemyId;
            } else if (!session.enemyId && msg.enemies?.length > 0) {
              const firstName = (msg.enemies[0].name || '').trim().toLowerCase().replace(/\s+/g, '_');
              if (firstName) session.enemyId = firstName;
            }
            if (msg.huntId) {
              const snapshotWallet = msg.wallet || msg.walletAddress || null;
              await rawPg`UPDATE pve_companion_sessions
                SET hunt_id = ${msg.huntId}, wallet_address = ${snapshotWallet}, status = 'hunt_linked', refresh_required_at = NULL, last_seen_at = CURRENT_TIMESTAMP
                WHERE id = ${sessionId}`;
              maybePushHeroProfiles(msg.huntId, snapshotWallet);
            } else {
              await rawPg`UPDATE pve_companion_sessions
                SET status = 'connected', refresh_required_at = NULL, last_seen_at = CURRENT_TIMESTAMP
                WHERE id = ${sessionId}`;
            }
          }
          ws.send(JSON.stringify({ type: 'snapshot_ack', received: true }));
          const snapshotBroadcast = JSON.stringify({ type: 'state_update', heroes: session.heroStates, enemyId: session.enemyId, combatFrame: session.latestFrame });
          for (const client of session.clients) {
            if (client.readyState === 1 && client !== ws) client.send(snapshotBroadcast);
          }

        } else if (msg.type === 'hunt_id_update') {
          // Extension broadcasts huntId when a new hunt/quest session is detected.
          // Trigger one-time hero profile prefetch for this session.
          if (!sessionToken || !sessionId) return;
          const session = companionSessions.get(sessionToken);
          if (session && msg.huntId) {
            const huntWallet = msg.wallet || msg.walletAddress || null;
            await rawPg`UPDATE pve_companion_sessions
              SET hunt_id = ${msg.huntId}, status = 'hunt_linked', refresh_required_at = NULL, last_seen_at = CURRENT_TIMESTAMP
              WHERE id = ${sessionId}`;
            maybePushHeroProfiles(msg.huntId, huntWallet);
            const huntBroadcast = JSON.stringify({ type: 'hunt_id_update', huntId: msg.huntId });
            for (const client of session.clients) {
              if (client.readyState === 1) client.send(huntBroadcast);
            }
          }
          ws.send(JSON.stringify({ type: 'hunt_ack', huntId: msg.huntId }));

        } else if (msg.type === 'turn_event') {
          if (!sessionToken || !sessionId) {
            ws.send(JSON.stringify({ type: 'error', message: 'Not joined to a session' }));
            return;
          }
          if (msg.huntId) {
            maybePushHeroProfiles(msg.huntId, msg.wallet || msg.walletAddress || null);
          }
          const { turnNumber, actorSide, actorSlot, skillId, targets, hpState, mpState, effects } = msg;
          await rawPg`INSERT INTO pve_turn_events (session_id, hunt_id, turn_number, actor_side, actor_slot, skill_id, targets, hp_state, mp_state, effects, raw_event)
            VALUES (${sessionId}, ${msg.huntId || null}, ${turnNumber || 0}, ${actorSide || 'unknown'}, ${actorSlot || 0}, ${skillId || null}, ${JSON.stringify(targets || [])}, ${JSON.stringify(hpState || {})}, ${JSON.stringify(mpState || {})}, ${JSON.stringify(effects || [])}, ${JSON.stringify(msg)})`;
          await rawPg`UPDATE pve_companion_sessions
            SET last_seen_at = CURRENT_TIMESTAMP,
                refresh_required_at = NULL,
                status = CASE WHEN ${msg.huntId || null} IS NOT NULL THEN 'in_progress' ELSE status END,
                hunt_id = COALESCE(${msg.huntId || null}, hunt_id)
            WHERE id = ${sessionId}`;

          const session = companionSessions.get(sessionToken);
          if (session) {
            if (msg.combatFrame) {
              const { normalizeCombatFrame, getPrimaryEnemyId } = await import('./server/pve-combat-frame.ts');
              const normalizedFrame = normalizeCombatFrame(msg.combatFrame);
              session.latestFrame = normalizedFrame;
              session.rawFrames.push(normalizedFrame);
              if (session.rawFrames.length > 50) session.rawFrames.shift();
              if (!session.enemyId) session.enemyId = getPrimaryEnemyId(normalizedFrame) || session.enemyId;
            }
            session.turnEvents.push(msg);
            const { getEnemy, getEnemyOrFallback } = await import('./server/pve-enemy-catalog.ts');
            const { scoreActions, buildBattleStateFromTurnEvents } = await import('./server/pve-scoring-engine.ts');
            const { enrichBattleStateFromCombatFrame, buildFallbackEnemyEntry, summarizeCombatFrameBattleState } = await import('./server/pve-combat-frame.ts');
            const enemyId = session.enemyId || msg.enemyId || 'MAD_BOAR';
            const enemyEntry = getEnemy(enemyId) || getEnemyOrFallback(enemyId, buildFallbackEnemyEntry(enemyId, session.latestFrame));
            if (enemyEntry && session.heroStates && msg.activeHeroSlot !== undefined) {
              // Update budget from live telemetry message if provided
              if (msg.battleBudgetRemaining !== undefined) {
                session.battleBudgetRemaining = msg.battleBudgetRemaining;
              }
              if (msg.consumableQuantities && typeof msg.consumableQuantities === 'object') {
                session.consumableQuantities = { ...session.consumableQuantities, ...msg.consumableQuantities };
              }

              let battleState = buildBattleStateFromTurnEvents(
                session.heroStates,
                enemyEntry,
                session.turnEvents,
                msg.activeHeroSlot,
                session.battleBudgetRemaining,
                session.consumableQuantities,
              );
              battleState = enrichBattleStateFromCombatFrame(battleState, session.latestFrame, enemyEntry);
              const recommendations = scoreActions(battleState, msg.legalActions || undefined);
              const summarizedBattleState = summarizeCombatFrameBattleState(session.latestFrame, battleState);
              const responseMsg = JSON.stringify({
                type: 'recommendation',
                turnNumber: turnNumber || session.turnEvents.length,
                recommendations: recommendations.slice(0, 5),
                battleState: summarizedBattleState,
                combatFrame: session.latestFrame,
              });
              const turnStateMsg = JSON.stringify({
                type: 'turn_state',
                battleState: summarizedBattleState,
                combatFrame: session.latestFrame,
              });
              for (const client of session.clients) {
                if (client.readyState === 1) {
                  client.send(responseMsg);
                  client.send(turnStateMsg);
                }
              }
            }
          }

          const liveSession = companionSessions.get(sessionToken);
          const turnBroadcast = JSON.stringify({ type: 'turn_update', turnNumber: turnNumber || 0, actorSide, actorSlot, skillId, actor: msg.actor || null, ability: msg.ability || null, effects: effects || [], combatFrame: liveSession?.latestFrame || null });
          for (const client of liveSession?.clients || []) {
            if (client.readyState === 1 && client !== ws) client.send(turnBroadcast);
          }
          ws.send(JSON.stringify({ type: 'turn_ack', turnNumber: turnNumber || 0 }));
        }
      } catch (err) {
        console.error('[Companion WS] Error:', err.message);
        ws.send(JSON.stringify({ type: 'error', message: 'Internal error' }));
      }
    });

    ws.on('close', () => {
      if (sessionToken && companionSessions.has(sessionToken)) {
        const session = companionSessions.get(sessionToken);
        session.clients.delete(ws);
        if (session.clients.size === 0) {
          companionSessions.delete(sessionToken);
        }
      }
    });
  });
  console.log('✅ PVE Companion WebSocket server attached at /ws/companion');

  server.on('error', (err) => {
    console.error('❌ Web server error:', err.message);
    if (err.code === 'EADDRINUSE') {
      console.log('Port 5000 already in use - web server disabled');
    }
  });

  // Serve static files AFTER API routes
  app.use(express.static('public'));

  // Try to set up Vite dev server, fallback to static serving
  try {
    const { setupVite } = await import('./server/vite.js');
    await setupVite(app, server);
    console.log('✅ Vite dev server configured');
  } catch (err) {
    console.log(`❌ Failed to setup Vite: ${err.message}`);
    console.log('Falling back to static file serving...');

    const staticBuildPath = path.resolve(import.meta.dirname, 'static-build');
    const distPublicPath = path.resolve(import.meta.dirname, 'dist', 'public');
    const staticBuildIndex = path.resolve(staticBuildPath, 'index.html');
    const distPublicIndex = path.resolve(distPublicPath, 'index.html');
    
    // Check if we have any built frontend files
    const hasStaticBuild = fs.existsSync(staticBuildIndex);
    const hasDistPublic = fs.existsSync(distPublicIndex);
    
    // If no frontend build exists at all, run vite build at startup
    // This handles Replit deployments where build artifacts don't persist to run phase
    if (!hasStaticBuild && !hasDistPublic) {
      console.log('🔨 No frontend build found - running vite build at startup...');
      try {
        const { execSync } = await import('child_process');
        // Build directly into static-build to avoid sync issues
        execSync('npx vite build --outDir static-build', { 
          stdio: 'inherit',
          cwd: import.meta.dirname,
          timeout: 300000 // 5 minute timeout
        });
        console.log('✅ Frontend build completed to static-build/');
      } catch (buildErr) {
        console.error('❌ CRITICAL: Failed to build frontend:', buildErr.message);
        console.error('❌ Server will not be able to serve the web interface.');
        // Don't abort - API endpoints should still work even if frontend fails
      }
    }
    
    // After potential build, sync dist/public to static-build if it exists (for builds that went to dist/public)
    if (fs.existsSync(distPublicIndex) && !fs.existsSync(staticBuildIndex)) {
      console.log('📦 Syncing dist/public to static-build for runtime serving...');
      try {
        // Clear existing static-build to avoid stale files
        if (fs.existsSync(staticBuildPath)) {
          fs.rmSync(staticBuildPath, { recursive: true, force: true });
        }
        fs.mkdirSync(staticBuildPath, { recursive: true });
        
        // Copy all files from dist/public to static-build
        const copyRecursive = (src, dest) => {
          const entries = fs.readdirSync(src, { withFileTypes: true });
          for (const entry of entries) {
            const srcPath = path.join(src, entry.name);
            const destPath = path.join(dest, entry.name);
            if (entry.isDirectory()) {
              fs.mkdirSync(destPath, { recursive: true });
              copyRecursive(srcPath, destPath);
            } else {
              fs.copyFileSync(srcPath, destPath);
            }
          }
        };
        copyRecursive(distPublicPath, staticBuildPath);
        console.log('✅ Synced build files to static-build/');
      } catch (copyErr) {
        console.error('❌ Failed to sync build files:', copyErr.message);
      }
    }

    // Check multiple possible build output directories
    // - static-build/: Primary location (synced from dist/public)
    // - dist/public/: Vite build output
    // - dist/: Alternative location
    const possiblePaths = [
      staticBuildPath,
      distPublicPath,
      path.resolve(import.meta.dirname, 'dist')
    ];
    
    let distPath = null;
    for (const p of possiblePaths) {
      if (fs.existsSync(p) && fs.existsSync(path.resolve(p, 'index.html'))) {
        distPath = p;
        break;
      }
    }
    
    if (distPath) {
      app.use(express.static(distPath));
      // SPA fallback - serve index.html for all non-API routes
      app.use((req, res, next) => {
        // Skip API and auth routes
        if (req.path.startsWith('/api') || req.path.startsWith('/auth')) {
          return next();
        }
        // Skip requests for static files
        if (req.path.includes('.')) {
          return next();
        }
        res.sendFile(path.resolve(distPath, 'index.html'));
      });
      console.log(`✅ Serving React app from ${distPath}`);
    } else {
      console.log('⚠️ No built frontend found. Checked locations:');
      possiblePaths.forEach(p => console.log(`   - ${p}`));
      console.log('Run "npm run build" or "npx vite build --outDir static-build" to build the client');
    }
  }

  // Global error handler - must be added last, after all routes
  app.use((err, req, res, next) => {
    console.error('[Express Error Handler] Unhandled error:', {
      method: req.method,
      path: req.path,
      error: err.message,
      stack: err.stack
    });
    res.status(500).json({ 
      error: 'Internal Server Error',
      message: isProduction() ? 'An unexpected error occurred' : err.message
    });
  });

  server.listen(5000, async () => {
    console.log('✅ Web server listening on port 5000');
    console.log(`📍 Environment: ${getEnvironmentName().toUpperCase()}`);
    
    // Only auto-start indexers in production
    if (isProduction()) {
      console.log('[AutoStart] Production environment detected - auto-starting all indexers...');
      
      // Auto-start parallel sync if not running and indexing is incomplete
      await autoStartParallelSync();
      
      // Auto-start unified pool indexer for all pools (V2)
      await autoStartUnifiedPoolIndexer();
      
      // Auto-start unified pool indexer V1 (legacy)
      await autoStartUnifiedPoolIndexerV1();
      
      // Auto-start Jeweler indexer
      await autoStartJewelerIndexer();
      
      // Auto-start Gardening Quest indexer
      await autoStartGardeningQuestIndexer();
      
      // Auto-start Tournament/Battle indexer
      await autoStartTournamentIndexer();
      
      // Auto-start Tavern indexer (marketplace heroes)
      await autoStartTavernIndexer();
      
      // Auto-start Sale ingestion (market intel / demand heatmap)
      await autoStartSaleIngestion();
      
      // Auto-start Auction Pipeline (listing indexer, finalizer, backfill)
      await autoStartAuctionPipeline();

      // Auto-start bracket poller (snapshots in-progress tournaments every 20 min)
      await autoStartBracketPoller();
    } else {
      console.log('[AutoStart] Development environment - indexers will only run when manually triggered from admin panel');
    }
  });
  
  // Auto-start unified pool indexer V2 on server startup
  async function autoStartUnifiedPoolIndexer() {
    try {
      // Wait a bit for database connections to stabilize
      await new Promise(r => setTimeout(r, 5000));
      
      console.log('[UnifiedIndexer] Auto-starting unified pool indexers...');
      const { startAllUnifiedAutoRun, getUnifiedAutoRunStatus } = await import('./src/etl/ingestion/poolUnifiedIndexer.js');
      
      // Check if any are already running
      const currentStatus = getUnifiedAutoRunStatus();
      if (currentStatus.length > 0) {
        console.log(`[UnifiedIndexer] ${currentStatus.length} workers already running, skipping auto-start`);
        return;
      }
      
      // Start all pool indexers with 3 workers per pool (42 total workers)
      const result = await startAllUnifiedAutoRun();
      console.log(`[UnifiedIndexer] Auto-start complete: ${result.started} workers across ${result.totalPools} pools`);
    } catch (err) {
      console.error('[UnifiedIndexer] Auto-start error:', err.message);
    }
  }
  
